const QUESTIONS = [
{id:"q-0000",cat:"math",diff:"easy",q:"If A = {1,2,3} and B = {3,4,5}, what is A ∩ B?",opts:["{1,2,3,4,5}","{3}","{1,2}","{4,5}"],ans:1,exp:"A∩B contains elements in both: only 3."},
  {id:"q-0001",cat:"math",diff:"easy",q:"If |A|=5, |B|=7, and |A∩B|=2, what is |A∪B|?",opts:["14","10","12","9"],ans:1,exp:"|A∪B|=|A|+|B|−|A∩B|=5+7−2=10."},
  {id:"q-0002",cat:"math",diff:"easy",q:"Which is true for all sets A?",opts:["A∪A=∅","A∩A=∅","A∪∅=A","A∩U=∅"],ans:2,exp:"Union with empty set returns the set itself."},
  {id:"q-0003",cat:"math",diff:"medium",q:"How many subsets does a set of n elements have?",opts:["n","2n","n²","2ⁿ"],ans:3,exp:"Each element in or out → 2ⁿ."},
  {id:"q-0004",cat:"math",diff:"medium",q:"Power set of {1,2} is:",opts:["{{1},{2}}","{∅,{1},{2},{1,2}}","{1,2,3}","{1,2,12}"],ans:1,exp:"All subsets including ∅."},
  {id:"q-0005",cat:"math",diff:"easy",q:"P→Q is false when:",opts:["P true, Q true","P true, Q false","P false, Q true","P false, Q false"],ans:1,exp:"Only when antecedent true, consequent false."},
  {id:"q-0006",cat:"math",diff:"easy",q:"Which is logically equivalent to P→Q?",opts:["Q→P","¬P∨Q","P∧Q","¬P∧¬Q"],ans:1,exp:"Material implication."},
  {id:"q-0007",cat:"math",diff:"medium",q:"Contrapositive of 'If rains, umbrella' is:",opts:["If umbrella, rains","If not rains, no umbrella","If no umbrella, no rain","If rains, no umbrella"],ans:2,exp:"Contrapositive flips and negates both parts: P→Q becomes ¬Q→¬P. So 'If rains then umbrella' becomes 'If no umbrella, then no rain'."},
  {id:"q-0008",cat:"math",diff:"easy",q:"∀x P(x) means:",opts:["There exists x with P(x)","P(x) for some x","P(x) for every x","P(x) false"],ans:2,exp:"Universal quantifier."},
  {id:"q-0009",cat:"math",diff:"easy",q:"∃x P(x) is false when:",opts:["At least one x satisfies P","No x satisfies P","All x satisfy P","P undefined"],ans:1,exp:"Existential: true if any element satisfies."},
  {id:"q-0010",cat:"math",diff:"medium",q:"¬(P∧Q) is equivalent to:",opts:["¬P∧¬Q","¬P∨¬Q","P∨Q","P→Q"],ans:1,exp:"De Morgan's law: the negation of AND becomes OR of negations.\n¬(P∧Q) = ¬P ∨ ¬Q"},
  {id:"q-0011",cat:"math",diff:"medium",q:"¬(P∨Q) is equivalent to:",opts:["¬P∨¬Q","¬P∧¬Q","P∧Q","P→Q"],ans:1,exp:"De Morgan's law: the negation of OR becomes AND of negations.\n¬(P∨Q) = ¬P ∧ ¬Q"},
  {id:"q-0012",cat:"math",diff:"easy",q:"A function is injective if:",opts:["f(a)=f(b)⇒a=b","Every codomain element hit","f continuous","f monotonic"],ans:0,exp:"Injective (one-to-one): different inputs always give different outputs.\nIf f(a) = f(b), then a must equal b. No two inputs map to the same output."},
  {id:"q-0013",cat:"math",diff:"easy",q:"A function is surjective if:",opts:["Every input has output","Every codomain element has preimage","Invertible","Linear"],ans:1,exp:"Surjective (onto): every element in the codomain is hit by at least one input.\nFor every y in codomain, there exists some x with f(x) = y."},
  {id:"q-0014",cat:"math",diff:"medium",q:"A bijection from {1,2,3} to {a,b,c}:",opts:["Must be permutation","All same output","No inverse","Undefined"],ans:0,exp:"A bijection is both injective and surjective.\nFor two finite sets of the same size, any bijection is just a rearrangement (permutation) of the elements."},
  {id:"q-0015",cat:"math",diff:"easy",q:"sin²θ + cos²θ =",opts:["0","1","2","sin2θ"],ans:1,exp:"Pythagorean identity: fundamental trig identity.\nFor any angle θ on the unit circle, sin²θ + cos²θ = 1.\nDerived from x² + y² = 1 where x = cosθ, y = sinθ."},
  {id:"q-0016",cat:"math",diff:"easy",q:"sin(90°) =",opts:["0","1/2","1","√3/2"],ans:2,exp:"sin(90°) = sin(π/2) = 1.\nOn the unit circle, at 90° the point is (0,1), and sin = y-coordinate = 1."},
  {id:"q-0017",cat:"math",diff:"medium",q:"cos(60°) =",opts:["1/2","√3/2","1","0"],ans:0,exp:"cos(60°) = cos(π/3) = 1/2.\nOn the unit circle, at 60° the point is (1/2, √3/2), and cos = x-coordinate = 1/2."},
  {id:"q-0018",cat:"math",diff:"medium",q:"sin(2θ) =",opts:["2 sinθ cosθ","sin²θ−cos²θ","2 sinθ","2 cosθ"],ans:0,exp:"Double angle formula for sine.\nsin(2θ) = 2·sinθ·cosθ\nExample: sin(60°) = 2·sin(30°)·cos(30°) = 2·(1/2)·(√3/2) = √3/2 ✓"},
  {id:"q-0019",cat:"math",diff:"medium",q:"cos(2θ) =",opts:["1−2sin²θ","2 sinθ cosθ","sin²θ","1+2sin²θ"],ans:0,exp:"Double angle formula for cosine (one of three equivalent forms).\ncos(2θ) = cos²θ − sin²θ = 1 − 2sin²θ = 2cos²θ − 1"},
  {id:"q-0020",cat:"math",diff:"hard",q:"tan(A+B) =",opts:["(tanA+tanB)/(1−tanA·tanB)","(tanA−tanB)/(1+tanA·tanB)","tanA·tanB","tanA+tanB"],ans:0,exp:"Tangent addition formula:\ntan(A+B) = (tanA + tanB) / (1 − tanA·tanB)\nDerived from sin(A+B)/cos(A+B)."},
  {id:"q-0021",cat:"math",diff:"easy",q:"log₁₀(100) =",opts:["1","2","10","100"],ans:1,exp:"log₁₀(100) asks: 10 to what power equals 100?\n10² = 100, so log₁₀(100) = 2."},
  {id:"q-0022",cat:"math",diff:"easy",q:"ln(e³) =",opts:["1","3","e","3e"],ans:1,exp:"ln(eˣ) = x (natural log and exponential are inverses).\nSo ln(e³) = 3."},
  {id:"q-0023",cat:"math",diff:"medium",q:"log_b(xy) =",opts:["log_b x · log_b y","log_b x + log_b y","log_b x − log_b y","log_b(x+y)"],ans:1,exp:"Logarithm product rule:\nlog_b(xy) = log_b(x) + log_b(y)\nExample: log(100) = log(10·10) = log 10 + log 10 = 1 + 1 = 2"},
  {id:"q-0024",cat:"math",diff:"medium",q:"log_b(xⁿ) =",opts:["n·log_b x","log_b x + n","n + log_b x","(log_b x)ⁿ"],ans:0,exp:"Logarithm power rule:\nlog_b(xⁿ) = n · log_b(x)\nExample: log(1000) = log(10³) = 3·log(10) = 3"},
  {id:"q-0025",cat:"math",diff:"hard",q:"Compute log₂(8):",opts:["1","3","4","8"],ans:1,exp:"log₂(8) asks: 2 to what power equals 8?\n2¹ = 2, 2² = 4, 2³ = 8. So log₂(8) = 3."},
  {id:"q-0026",cat:"math",diff:"medium",q:"Solve e^(2x) = 7. x =",opts:["ln 7","(ln 7)/2","2 ln 7","e^7"],ans:1,exp:"Step 1: Take natural log of both sides.\nln(e^(2x)) = ln(7)\nStep 2: Simplify left side.\n2x = ln 7\nStep 3: Solve for x.\nx = ln(7) / 2"},
  {id:"q-0027",cat:"math",diff:"easy",q:"i² =",opts:["1","−1","i","0"],ans:1,exp:"Definition of the imaginary unit: i = √(−1), so i² = −1.\nThis is the foundational definition all complex arithmetic builds on."},
  {id:"q-0028",cat:"math",diff:"medium",q:"Conjugate of z=3+4i:",opts:["−3+4i","3−4i","−3−4i","4+3i"],ans:1,exp:"The conjugate of a+bi is a−bi (flip the sign of imaginary part).\nConjugate of 3+4i is 3−4i.\nKey property: z·z̄ = |z|² (a real number)."},
  {id:"q-0029",cat:"math",diff:"medium",q:"|3+4i| =",opts:["1","5","7","25"],ans:1,exp:"Modulus of complex number: |a+bi| = √(a²+b²).\n|3+4i| = √(9+16) = √25 = 5.\nGeometrically: distance from origin to point (3,4) in complex plane."},
  {id:"q-0030",cat:"math",diff:"hard",q:"e^(iπ) + 1 =",opts:["0","1","2","i"],ans:0,exp:"Euler's identity: e^(iπ) = cos(π) + i·sin(π) = −1 + i·0 = −1.\nSo e^(iπ) + 1 = −1 + 1 = 0.\nCalled the most beautiful equation in mathematics (links e, i, π, 1, 0)."},
  {id:"q-0031",cat:"math",diff:"hard",q:"3 cube roots of unity sum to:",opts:["0","1","3","i"],ans:0,exp:"The 3 cube roots of unity are: 1, ω = e^(2πi/3), ω² = e^(4πi/3).\nThey sum to 1 + (−1/2 + i√3/2) + (−1/2 − i√3/2) = 0.\nThe imaginary parts cancel and the real parts sum to zero."},
  {id:"q-0032",cat:"math",diff:"medium",q:"If A⊆B and B⊆A, then:",opts:["Disjoint","A=B","A empty","B empty"],ans:1,exp:"Antisymmetry of subset relation.\nIf every element of A is in B, AND every element of B is in A,\nthen A and B contain exactly the same elements: A = B."},
  {id:"q-0033",cat:"math",diff:"easy",q:"(A∪B)ᶜ =",opts:["Aᶜ∪Bᶜ","Aᶜ∩Bᶜ","A∩B","A−B"],ans:1,exp:"De Morgan's law for sets: complement of union = intersection of complements.\n(A∪B)ᶜ = Aᶜ ∩ Bᶜ\nThe complement of 'in A or in B' is 'not in A AND not in B'."},
  {id:"q-0034",cat:"math",diff:"medium",q:"|{1,2,3}×{a,b}| =",opts:["5","6","9","3"],ans:1,exp:"Cartesian product: |A×B| = |A| · |B|.\nEach of the 3 elements pairs with each of the 2 elements.\n3 × 2 = 6 pairs: {(1,a),(1,b),(2,a),(2,b),(3,a),(3,b)}."},
  {id:"q-0035",cat:"math",diff:"easy",q:"Domain of f(x)=1/x:",opts:["All reals","Reals except 0","x>0","x≥0"],ans:1,exp:"Division by zero is undefined.\nf(x) = 1/x is defined for all real x except x = 0.\nDomain: (−∞, 0) ∪ (0, ∞)"},
  {id:"q-0036",cat:"math",diff:"easy",q:"Range of f(x)=x²:",opts:["All reals","[0,∞)","(0,∞)","R⁺"],ans:1,exp:"Any real number squared is ≥ 0.\nx² = 0 only when x = 0, and x² → ∞ as x → ±∞.\nRange: [0, ∞). Note: 0 IS included (unlike (0,∞))."},
  {id:"q-0037",cat:"math",diff:"medium",q:"f(g(x)) with f=x², g=x+1:",opts:["x²+1","(x+1)²","x²+x+1","2x+1"],ans:1,exp:"Function composition: substitute g(x) into f.\nf(g(x)) = f(x+1) = (x+1)²\nNote: (x+1)² = x²+2x+1, NOT x²+1. Common trap!"},
  {id:"q-0038",cat:"math",diff:"easy",q:"How many primes ≤ 10?",opts:["3","4","5","6"],ans:1,exp:"Primes are numbers divisible only by 1 and themselves.\nPrimes ≤ 10: 2, 3, 5, 7. Total = 4.\nNote: 1 is NOT prime (by definition)."},
  {id:"q-0039",cat:"math",diff:"medium",q:"GCD(12,18) =",opts:["2","3","6","36"],ans:2,exp:"GCD = largest number dividing both.\nFactors of 12: 1,2,3,4,6,12\nFactors of 18: 1,2,3,6,9,18\nCommon factors: 1,2,3,6 → GCD = 6."},
  {id:"q-0040",cat:"math",diff:"medium",q:"LCM(4,6) =",opts:["2","12","24","10"],ans:1,exp:"LCM = smallest number that is a multiple of both.\nMultiples of 4: 4,8,12,16,20,24...\nMultiples of 6: 6,12,18,24...\nFirst common multiple = 12.\nShortcut: LCM(4,6) = 4·6/GCD(4,6) = 24/2 = 12."},
  {id:"q-0041",cat:"math",diff:"easy",q:"Sum 1+2+...+10 =",opts:["45","55","65","100"],ans:1,exp:"Sum of first n integers: n(n+1)/2.\nHere: 10·11/2 = 110/2 = 55."},
  {id:"q-0042",cat:"math",diff:"medium",q:"Sum of first n odd numbers =",opts:["n","n²","2n","n+1"],ans:1,exp:"The first n odd numbers: 1, 3, 5, ..., (2n−1).\nSum = n². This is a famous result.\nExamples: 1=1², 1+3=4=2², 1+3+5=9=3², 1+3+5+7=16=4²."},
  {id:"q-0043",cat:"math",diff:"easy",q:"0! =",opts:["0","1","undefined","n"],ans:1,exp:"By convention, 0! = 1.\nThis makes the formula n!/n = (n−1)! work for n=1:\n1!/1 = 0! = 1. ✓"},
  {id:"q-0044",cat:"math",diff:"medium",q:"P(5,2) =",opts:["10","20","25","60"],ans:1,exp:"Permutation: P(n,r) = n!/(n−r)!\nP(5,2) = 5!/3! = (5·4·3!)/3! = 5·4 = 20.\nArranging 2 out of 5 items in order: 20 ways."},
  {id:"q-0045",cat:"math",diff:"easy",q:"C(5,2) =",opts:["10","20","25","5"],ans:0,exp:"Combination: C(n,r) = n!/(r!(n−r)!)\nC(5,2) = 5!/(2!·3!) = (5·4)/2 = 10.\nChoosing 2 out of 5 items (order doesn't matter): 10 ways."},
  {id:"q-0046",cat:"math",diff:"easy",q:"sin(0) =",opts:["0","1","−1","undefined"],ans:0,exp:"sin(0°) = sin(0) = 0.\nOn the unit circle, at angle 0 the point is (1,0), and sin = y-coordinate = 0."},
  {id:"q-0047",cat:"math",diff:"medium",q:"cos(π) =",opts:["0","1","−1","π"],ans:2,exp:"cos(π) = cos(180°) = −1.\nAt 180° on the unit circle, the point is (−1,0), so cos = x = −1."},
  {id:"q-0048",cat:"math",diff:"easy",q:"e⁰ =",opts:["0","1","e","undefined"],ans:1,exp:"Any nonzero number raised to the power 0 equals 1.\ne⁰ = 1. This is a fundamental exponent rule."},
  {id:"q-0049",cat:"math",diff:"easy",q:"log_b(1) =",opts:["0","1","b","undefined"],ans:0,exp:"log_b(1) = 0 because b⁰ = 1 for any b > 0.\n'What power of b gives 1?' → always 0."},
  {id:"q-0050",cat:"math",diff:"medium",q:"log₂(32) = x. x =",opts:["4","5","6","8"],ans:1,exp:"log₂(32) asks: 2 to what power = 32?\n2¹=2, 2²=4, 2³=8, 2⁴=16, 2⁵=32. So x = 5."},
  {id:"q-0051",cat:"math",diff:"hard",q:"(f∘g)⁻¹ =",opts:["f⁻¹∘g⁻¹","g⁻¹∘f⁻¹","f∘g","(g∘f)⁻¹"],ans:1,exp:"To undo composition f∘g, reverse the operations in reverse order.\n(f∘g)⁻¹ = g⁻¹ ∘ f⁻¹\nFirst undo f, then undo g."},
  {id:"q-0052",cat:"math",diff:"medium",q:"Odd function satisfies:",opts:["f(−x)=f(x)","f(−x)=−f(x)","f(x)=0","f(x+y)=f(x)f(y)"],ans:1,exp:"Odd function: symmetric about the origin.\nf(−x) = −f(x). Examples: sin(x), x³, x.\nGraph: rotating 180° around origin gives same graph."},
  {id:"q-0053",cat:"math",diff:"medium",q:"Even function satisfies:",opts:["f(−x)=f(x)","f(−x)=−f(x)","f(x)=x","f(0)=1"],ans:0,exp:"Even function: symmetric about the y-axis.\nf(−x) = f(x). Examples: cos(x), x², |x|.\nGraph: mirror image across y-axis."},
  {id:"q-0054",cat:"math",diff:"hard",q:"lim (1+1/n)ⁿ =",opts:["1","e","π","0"],ans:1,exp:"This is the definition of e as n → ∞.\nlim(n→∞) (1 + 1/n)ⁿ = e ≈ 2.71828.\nKey limit that defines Euler's number."},
  {id:"q-0055",cat:"math",diff:"medium",q:"Integers 1..100 divisible by 3:",opts:["33","34","32","30"],ans:0,exp:"Count = floor(100/3) = 33.\nThe multiples are: 3, 6, 9, ..., 99 (33 numbers).\nVerify: 3·33 = 99 ≤ 100, but 3·34 = 102 > 100."},
  {id:"q-0056",cat:"math",diff:"easy",q:"7² mod 5 =",opts:["3","4","2","1"],ans:1,exp:"Step 1: 7² = 49.\nStep 2: 49 mod 5 = 49 ÷ 5 = 9 remainder 4.\nSo 49 mod 5 = 4."},
  {id:"q-0057",cat:"math",diff:"hard",q:"Sum 2+5+8+...+29:",opts:["155","145","150","160"],ans:0,exp:"Arithmetic series: first term a=2, common difference d=3, last term=29.\nn = (29−2)/3 + 1 = 10 terms.\nSum = n(a₁+aₙ)/2 = 10·(2+29)/2 = 10·31/2 = 155."},
  {id:"q-0058",cat:"math",diff:"medium",q:"1+2+4+8+16 =",opts:["31","32","30","16"],ans:0,exp:"Geometric series: 2⁰ + 2¹ + 2² + 2³ + 2⁴ = 1+2+4+8+16.\nSum of first n terms: (2ⁿ−1)/(2−1) = 2⁵−1 = 31."},
  {id:"q-0059",cat:"math",diff:"medium",q:"2ˣ = 16 ⇒ x =",opts:["2","4","8","16"],ans:1,exp:"Powers of 2: 2¹=2, 2²=4, 2³=8, 2⁴=16.\nSo 2ˣ = 16 ⇒ x = 4."},
  {id:"q-0060",cat:"math",diff:"easy",q:"Sum of first 100 positive integers:",opts:["1000","4950","5050","10000"],ans:2,exp:"Gauss formula: n(n+1)/2 = 100·101/2 = 5050.\nThis is the famous result Gauss discovered as a child."},
  {id:"q-0061",cat:"math",diff:"medium",q:"If 3⁴ = 81, log₃(81) =",opts:["3","4","27","81"],ans:1,exp:"log₃(81) asks: 3 to what power = 81?\n3¹=3, 3²=9, 3³=27, 3⁴=81. So log₃(81) = 4."},
  {id:"q-0062",cat:"math",diff:"easy",q:"Number of even numbers between 1 and 10:",opts:["4","5","6","3"],ans:1,exp:"Even numbers from 1 to 10: 2, 4, 6, 8, 10.\nTotal = 5. (Includes both endpoints since 2 and 10 are even.)"},
  {id:"q-0063",cat:"math",diff:"medium",q:"tan(45°) =",opts:["0","1","√3","1/√3"],ans:1,exp:"tan(45°) = tan(π/4) = 1.\nAt 45°: sin = cos = √2/2, so tan = sin/cos = 1."},
  {id:"q-0064",cat:"math",diff:"hard",q:"sin(π/6) =",opts:["1/2","√3/2","1","0"],ans:0,exp:"sin(π/6) = sin(30°) = 1/2.\nAt 30° the point on the unit circle is (√3/2, 1/2), so sin = y = 1/2."},
  {id:"q-0065",cat:"math",diff:"hard",q:"Solution to 2x+3 = 11:",opts:["3","4","5","7"],ans:1,exp:"Step 1: Subtract 3 from both sides.\n2x = 11 − 3 = 8\nStep 2: Divide by 2.\nx = 8/2 = 4"},
  {id:"q-0066",cat:"math",diff:"easy",q:"Decimal 0.25 as a fraction:",opts:["1/2","1/3","1/4","1/5"],ans:2,exp:"0.25 = 25/100 = 1/4.\nOne quarter is 0.25."},
  {id:"q-0067",cat:"math",diff:"medium",q:"If f(x)=2x+1, f(3) =",opts:["5","6","7","8"],ans:2,exp:"Substitute x = 3 into f(x) = 2x + 1.\nf(3) = 2(3) + 1 = 6 + 1 = 7."},
  {id:"q-0068",cat:"math",diff:"hard",q:"Number of ways to arrange 3 distinct books:",opts:["3","6","9","12"],ans:1,exp:"Permutation of 3 items: 3! = 3·2·1 = 6.\nIf books are A,B,C: ABC, ACB, BAC, BCA, CAB, CBA."},
  {id:"q-0069",cat:"math",diff:"medium",q:"Sum of geometric series 1+1/2+1/4+... =",opts:["1","2","3","∞"],ans:1,exp:"Infinite geometric series: a=1, r=1/2.\nSince |r| < 1, sum = a/(1−r) = 1/(1−1/2) = 1/(1/2) = 2."},
  {id:"q-0070",cat:"math",diff:"easy",q:"Square root of 144:",opts:["10","11","12","14"],ans:2,exp:"12² = 144, so √144 = 12.\nTip: 10²=100, 12²=144, 15²=225 — memorize common squares."},
  {id:"q-0071",cat:"math",diff:"medium",q:"Next term: 2,4,8,16,...",opts:["18","24","32","30"],ans:2,exp:"Each term doubles: 2, 4, 8, 16, ...\nThis is 2ⁿ where n=1,2,3,4,...\nNext term: 2⁵ = 32."},
  {id:"q-0072",cat:"math",diff:"hard",q:"gcd(0,5) =",opts:["0","5","1","undefined"],ans:1,exp:"By definition, gcd(0, n) = |n| for n ≠ 0.\nEvery number divides 0, so the greatest common divisor is the larger number.\ngcd(0, 5) = 5."},
  {id:"q-0073",cat:"math",diff:"easy",q:"Is 17 prime?",opts:["Yes","No","Sometimes","Depends"],ans:0,exp:"17 is prime — its only divisors are 1 and 17.\nIt is not divisible by 2, 3 (√17 ≈ 4.1, so check primes ≤ 4): 17÷2=8.5, 17÷3=5.67."},
  {id:"q-0074",cat:"math",diff:"medium",q:"Area of triangle with base 4, height 3:",opts:["6","7","12","10"],ans:0,exp:"Area = ½ × base × height = ½ × 4 × 3 = 6."},
  {id:"q-0075",cat:"math",diff:"easy",q:"Circumference of circle, radius r:",opts:["2πr","πr²","πr","4πr"],ans:0,exp:"Circumference C = 2πr (perimeter of a circle).\nDiameter = 2r, and C = π × diameter = 2πr."},
  {id:"q-0076",cat:"math",diff:"hard",q:"Area of circle, radius r:",opts:["2πr","πr²","πr","4πr"],ans:1,exp:"Area A = πr².\nDerived from integrating circumference: A = ∫₀ʳ 2πt dt = πr²."},
  {id:"q-1000",cat:"la",diff:"easy",q:"If A is a 3×2 matrix and B is a 2×4 matrix, what is the shape of AB?",opts:["3×2","2×3","3×4","4×2"],ans:2,exp:"Inner dimensions (2) cancel; outer dimensions give 3×4."},
  {id:"q-1001",cat:"la",diff:"easy",q:"Which matrix multiplied by any vector leaves the vector unchanged?",opts:["Zero matrix","Identity matrix","Diagonal matrix","Transpose matrix"],ans:1,exp:"The identity I acts as a multiplicative identity: Iv = v."},
  {id:"q-1002",cat:"la",diff:"easy",q:"For a square matrix A, A · Aᵀ is always:",opts:["Skew-symmetric","Symmetric","Diagonal","Zero"],ans:1,exp:"(AAᵀ)ᵀ = (Aᵀ)ᵀAᵀ = AAᵀ, so it is symmetric."},
  {id:"q-1003",cat:"la",diff:"easy",q:"The rank of a 3×3 identity matrix is:",opts:["0","1","2","3"],ans:3,exp:"I₃ has three linearly independent rows/columns, so rank = 3."},
  {id:"q-1004",cat:"la",diff:"medium",q:"det(2A) for a 3×3 matrix A equals:",opts:["2·det(A)","4·det(A)","6·det(A)","8·det(A"],ans:3,exp:"Scaling each row by 2 multiplies det by 2³ = 8 for n=3."},
  {id:"q-1005",cat:"la",diff:"medium",q:"A matrix is invertible if and only if:",opts:["det(A) = 0","det(A) ≠ 0","tr(A) = 0","A is symmetric"],ans:1,exp:"Invertibility ⇔ nonzero determinant."},
  {id:"q-1006",cat:"la",diff:"medium",q:"For an n×n matrix, the trace equals the sum of its:",opts:["Singular values","Eigenvalues","Row sums","Column norms"],ans:1,exp:"Trace = sum of diagonal entries = sum of eigenvalues.\ntr(A) = Σᵢ aᵢᵢ = Σᵢ λᵢ. This holds for all diagonalizable matrices."},
  {id:"q-1007",cat:"la",diff:"medium",q:"The rank–nullity theorem says:",opts:["rank + nullity = m","rank + nullity = n","rank · nullity = n","rank = nullity"],ans:1,exp:"For an m×n matrix, rank(A) + nullity(A) = n."},
  {id:"q-1008",cat:"la",diff:"medium",q:"A vector v is an eigenvector of A if:",opts:["Av = 0","Av = λv for some scalar λ","v is unit length","Aᵀv = v"],ans:1,exp:"Eigenvector: nonzero v with Av = λv."},
  {id:"q-1009",cat:"la",diff:"medium",q:"The eigenvalues of a real symmetric matrix are always:",opts:["Complex","Real","Non-negative","Integers"],ans:1,exp:"Spectral theorem: symmetric real matrices have real eigenvalues."},
  {id:"q-1010",cat:"la",diff:"hard",q:"For A = [[2,1],[1,2]], eigenvalues are:",opts:["2 and 2","1 and 3","-1 and 5","0 and 4"],ans:1,exp:"Characteristic eq: (2-λ)²−1 = 0 → λ = 1, 3."},
  {id:"q-1011",cat:"la",diff:"hard",q:"The SVD of A is written as:",opts:["A = PDP⁻¹","A = UΣVᵀ","A = LLᵀ","A = QR"],ans:1,exp:"A = UΣVᵀ with U,V orthogonal and Σ diagonal of singular values."},
  {id:"q-1012",cat:"la",diff:"hard",q:"Number of nonzero singular values of A equals:",opts:["trace(A)","determinant(A)","rank(A)","norm(A)"],ans:2,exp:"rank(A) = # of nonzero singular values."},
  {id:"q-1013",cat:"la",diff:"hard",q:"For a projection matrix P, P² equals:",opts:["P","0","I","Pᵀ"],ans:0,exp:"Idempotent: a projection satisfies P² = P."},
  {id:"q-1014",cat:"la",diff:"hard",q:"If A is n×n and det(A) = 0, then A:",opts:["Has n distinct eigenvalues","Is invertible","Is singular","Is orthogonal"],ans:2,exp:"Zero determinant ⇒ singular ⇒ not invertible."},
  {id:"q-1015",cat:"la",diff:"easy",q:"The dot product u·v of u=[1,2,3] and v=[4,5,6] is:",opts:["15","32","-3","62"],ans:1,exp:"1·4 + 2·5 + 3·6 = 4+10+18 = 32."},
  {id:"q-1016",cat:"la",diff:"easy",q:"The L2 norm of [3,4] is:",opts:["5","7","1","25"],ans:0,exp:"√(9+16) = √25 = 5."},
  {id:"q-1017",cat:"la",diff:"medium",q:"For u=[1,1], v=[-1,1], u·v equals:",opts:["0","2","-2","1"],ans:0,exp:"1·(-1) + 1·1 = 0; vectors are orthogonal."},
  {id:"q-1018",cat:"la",diff:"medium",q:"Cramer's rule solves:",opts:["Eigenvalue problems","Linear systems Ax = b","Least-squares","Differential equations"],ans:1,exp:"Cramer's rule: xᵢ = det(Aᵢ)/det(A) when det(A) ≠ 0."},
  {id:"q-1019",cat:"la",diff:"medium",q:"The transpose of (AB)ᵀ is:",opts:["AᵀBᵀ","BᵀAᵀ","(BA)ᵀ","AB"],ans:1,exp:"(AB)ᵀ = BᵀAᵀ — order reverses."},
  {id:"q-1020",cat:"la",diff:"medium",q:"A basis for ℝ³ has exactly:",opts:["1 vector","2 vectors","3 vectors","4 vectors"],ans:2,exp:"dim(ℝ³) = 3, so any basis has exactly 3 vectors.\nA basis is linearly independent + spans the space.\nMore than 3 vectors in ℝ³ are always dependent."},
  {id:"q-1021",cat:"la",diff:"hard",q:"The pseudoinverse A⁺ satisfies:",opts:["AA⁺A = A","A⁺ = A","A⁺ = Aᵀ","AA⁺ = 0"],ans:0,exp:"Moore–Penrose condition #1: AA⁺A = A."},
  {id:"q-1022",cat:"la",diff:"hard",q:"Cauchy–Schwarz inequality says |u·v| ≤",opts:["||u|| + ||v||","||u||·||v||","||u||²·||v||²","1"],ans:1,exp:"Classic: |u·v| ≤ ||u|| · ||v|| with equality when parallel."},
  {id:"q-1023",cat:"la",diff:"hard",q:"A square matrix A is orthogonal if:",opts:["A = Aᵀ","AAᵀ = I","A² = I","det(A) = 1"],ans:1,exp:"Orthogonal: columns are orthonormal ⇒ AAᵀ = I."},
  {id:"q-1024",cat:"la",diff:"hard",q:"For an orthogonal matrix Q, det(Q) equals:",opts:["0","±1","2","det(Qᵀ)"],ans:1,exp:"|det(Q)| = 1, so det(Q) ∈ {+1, -1}."},
  {id:"q-1025",cat:"la",diff:"medium",q:"Column space of A is also called:",opts:["Null space","Range / image","Eigenspace","Kernel"],ans:1,exp:"Im(A) = {Ax : x ∈ ℝⁿ}."},
  {id:"q-1026",cat:"la",diff:"medium",q:"If A is 5×3 with rank 3, the null space has dimension:",opts:["0","1","2","3"],ans:0,exp:"rank + nullity = n (number of columns = 3) ⇒ nullity = 0 (full column rank)."},
  {id:"q-1027",cat:"la",diff:"hard",q:"The condition number of A relates to:",opts:["Numerical stability of solving Ax=b","Number of eigenvalues","Trace","Determinant only"],ans:0,exp:"Large κ(A) ⇒ ill-conditioned system."},
  {id:"q-1028",cat:"la",diff:"medium",q:"If λ is an eigenvalue of A, then λ² is an eigenvalue of:",opts:["A","A²","Aᵀ","I"],ans:1,exp:"Av = λv ⇒ A²v = A(Av) = λ²v."},
  {id:"q-1029",cat:"la",diff:"hard",q:"A symmetric matrix can be diagonalized as A = QDQᵀ where Q is:",opts:["Singular","Orthogonal","Skew-symmetric","Triangular"],ans:1,exp:"Spectral theorem: orthogonal Q diagonalizes real symmetric A."},
  {id:"q-1100",cat:"calc",diff:"easy",q:"d/dx [x³] =",opts:["3x²","x²","3x","x³"],ans:0,exp:"Power rule: d/dx xⁿ = n·xⁿ⁻¹."},
  {id:"q-1101",cat:"calc",diff:"easy",q:"d/dx [eˣ] =",opts:["eˣ","xeˣ","eˣ/x","1"],ans:0,exp:"The exponential is its own derivative."},
  {id:"q-1102",cat:"calc",diff:"easy",q:"d/dx [ln x] =",opts:["1/x","x","ln x","eˣ"],ans:0,exp:"Natural log derivative: d/dx[ln x] = 1/x.\nThis is the inverse of d/dx[eˣ] = eˣ. Fundamental derivative."},
  {id:"q-1103",cat:"calc",diff:"easy",q:"d/dx [sin x] =",opts:["-sin x","cos x","-cos x","tan x"],ans:1,exp:"Derivative of sine is cosine."},
  {id:"q-1104",cat:"calc",diff:"easy",q:"d/dx [cos x] =",opts:["-sin x","sin x","-cos x","cos x"],ans:0,exp:"Derivative of cosine is negative sine."},
  {id:"q-1105",cat:"calc",diff:"medium",q:"d/dx [x²·sin x] =",opts:["2x·sin x","x²·cos x","2x·sin x + x²·cos x","2x·cos x − x²·sin x"],ans:2,exp:"Product rule: (fg)' = f'g + fg'."},
  {id:"q-1106",cat:"calc",diff:"medium",q:"d/dx [sin(x²)] =",opts:["2x·cos(x²)","cos(x²)","2·cos(x²)","−2x·sin(x²)"],ans:0,exp:"Chain rule: cos(x²) · 2x."},
  {id:"q-1107",cat:"calc",diff:"medium",q:"d/dx [1/x] =",opts:["1/x²","−1/x²","ln x","−1/x"],ans:1,exp:"d/dx x⁻¹ = −x⁻² = −1/x²."},
  {id:"q-1108",cat:"calc",diff:"medium",q:"∫ 2x dx =",opts:["x² + C","x²","2x² + C","2 + C"],ans:0,exp:"Antiderivative of 2x is x² + C."},
  {id:"q-1109",cat:"calc",diff:"medium",q:"∫ eˣ dx =",opts:["eˣ + C","xeˣ + C","eˣ/x + C","1 + C"],ans:0,exp:"eˣ integrates to itself plus C."},
  {id:"q-1110",cat:"calc",diff:"medium",q:"∫ cos x dx =",opts:["-cos x + C","sin x + C","-sin x + C","cos x + C"],ans:1,exp:"Integral of cosine is sine."},
  {id:"q-1111",cat:"calc",diff:"medium",q:"∫ 1/x dx =",opts:["x + C","ln|x| + C","-1/x² + C","1 + C"],ans:1,exp:"Standard log antiderivative."},
  {id:"q-1112",cat:"calc",diff:"hard",q:"lim (x→0) sin(x)/x =",opts:["0","1","∞","undefined"],ans:1,exp:"Fundamental trig limit: lim(x→0) sin(x)/x = 1.\nProved via squeeze theorem between cos(x) and 1.\nUsed to derive ALL trig derivatives (e.g., d/dx[sin x] = cos x)."},
  {id:"q-1113",cat:"calc",diff:"hard",q:"lim (x→∞) (1 + 1/x)ˣ =",opts:["1","e","∞","0"],ans:1,exp:"This is the definition of Euler's number e.\nAs x→∞, (1 + 1/n)ⁿ → e ≈ 2.71828.\nAlso works: lim(n→∞)(1 + a/n)ⁿ = eᵃ."},
  {id:"q-1114",cat:"calc",diff:"hard",q:"The chain rule: d/dx f(g(x)) =",opts:["f'(g(x))","f'(g(x))·g'(x)","f(g'(x))","f'(x)·g(x)"],ans:1,exp:"Chain rule: f'(g(x)) · g'(x)."},
  {id:"q-1115",cat:"calc",diff:"medium",q:"∂/∂x of x²y + y³ is:",opts:["2xy","2xy + 3y²","x² + 3y²","2x + 3y"],ans:0,exp:"Treat y as constant: 2x·y = 2xy."},
  {id:"q-1116",cat:"calc",diff:"medium",q:"The gradient ∇(x² + y²) is:",opts:["(x,y)","(2x, 2y)","(y,x)","(1,1)"],ans:1,exp:"∇f = (∂f/∂x, ∂f/∂y) = (2x, 2y)."},
  {id:"q-1117",cat:"calc",diff:"hard",q:"A critical point of f is where:",opts:["f = 0","f' = 0 or undefined","f'' > 0","f is concave"],ans:1,exp:"Interior extremum candidates: f' = 0 or undefined."},
  {id:"q-1118",cat:"calc",diff:"hard",q:"The second derivative test: if f'(x)=0 and f''(x)>0, then f has a:",opts:["Maximum","Minimum","Saddle","Discontinuity"],ans:1,exp:"Positive second derivative ⇒ local minimum."},
  {id:"q-1119",cat:"calc",diff:"hard",q:"The Taylor series of eˣ around 0 is:",opts:["Σ xⁿ/n!","Σ xⁿ","Σ xⁿ/n","Σ (−1)ⁿx²ⁿ/(2n)!"],ans:0,exp:"Maclaurin series: eˣ = Σ xⁿ/n!."},
  {id:"q-1120",cat:"calc",diff:"hard",q:"∫₀¹ x dx =",opts:["1/2","1","0","2"],ans:0,exp:"Area of triangle: (1/2)·1·1 = 1/2."},
  {id:"q-1121",cat:"calc",diff:"hard",q:"∫₀^∞ e⁻ˣ dx =",opts:["0","1","∞","e"],ans:1,exp:"Gamma: Γ(1) = 1."},
  {id:"q-1122",cat:"calc",diff:"medium",q:"d/dx [tan x] =",opts:["sec² x","csc² x","tan² x","cot x"],ans:0,exp:"Derivative of tan is sec²."},
  {id:"q-1123",cat:"calc",diff:"medium",q:"d/dx [arctan x] =",opts:["1/x","1/(1+x²)","1/√(1−x²)","arctan x"],ans:1,exp:"Standard inverse-trig derivative."},
  {id:"q-1124",cat:"calc",diff:"hard",q:"L'Hôpital's rule applies to:",opts:["0/0 or ∞/∞ forms","All limits","Integrals","Derivatives"],ans:0,exp:"Indeterminate forms 0/0 or ∞/∞."},
  {id:"q-1125",cat:"calc",diff:"hard",q:"∫ x·eˣ dx by parts =",opts:["x·eˣ − eˣ + C","x·eˣ + eˣ + C","eˣ + C","x²·eˣ/2 + C"],ans:0,exp:"u = x, dv = eˣdx ⇒ x·eˣ − ∫eˣdx = x·eˣ − eˣ + C."},
  {id:"q-1126",cat:"calc",diff:"medium",q:"∫ sin x dx =",opts:["-cos x + C","cos x + C","-sin x + C","sin x + C"],ans:0,exp:"Integral of sine is negative cosine."},
  {id:"q-1127",cat:"calc",diff:"hard",q:"∂/∂x [ln(x²+y²)] =",opts:["2x/(x²+y²)","1/(x²+y²)","x/(x²+y²)","2x"],ans:0,exp:"Chain rule: 2x/(x²+y²)."},
  {id:"q-1128",cat:"calc",diff:"hard",q:"The Mean Value Theorem requires f to be:",opts:["Continuous on [a,b] and differentiable on (a,b)","Only continuous","Polynomials","Monotonic"],ans:0,exp:"Standard MVT hypotheses."},
  {id:"q-1129",cat:"calc",diff:"hard",q:"∫ sec² x dx =",opts:["tan x + C","sec x + C","cot x + C","-cot x + C"],ans:0,exp:"Antiderivative of sec² is tan."},
  {id:"q-1200",cat:"prob",diff:"easy",q:"Probability of an event must lie in:",opts:["[-1,1]","[0,1]","[0,∞)","(-∞,∞)"],ans:1,exp:"Axiom: 0 ≤ P(A) ≤ 1."},
  {id:"q-1201",cat:"prob",diff:"easy",q:"For two independent events, P(A∩B) =",opts:["P(A)·P(B)","P(A)+P(B)","P(A)−P(B)","0"],ans:0,exp:"Independence: multiplication rule."},
  {id:"q-1202",cat:"prob",diff:"easy",q:"P(Aᶜ) =",opts:["P(A)","1 − P(A)","P(A)−1","0"],ans:1,exp:"Complement rule."},
  {id:"q-1203",cat:"prob",diff:"easy",q:"Rolling a fair die, P(even) =",opts:["1/2","1/3","1/6","2/3"],ans:0,exp:"3 even outcomes out of 6."},
  {id:"q-1204",cat:"prob",diff:"medium",q:"Bayes' theorem: P(A|B) =",opts:["P(B|A)·P(A)/P(B)","P(A)·P(B)","P(A)+P(B)","P(B)/P(A)"],ans:0,exp:"Posterior = likelihood × prior / evidence."},
  {id:"q-1205",cat:"prob",diff:"medium",q:"E[aX+b] =",opts:["a·E[X]","a·E[X] + b","E[X]+b","a·E[X]−b"],ans:1,exp:"Linearity of expectation."},
  {id:"q-1206",cat:"prob",diff:"medium",q:"Var(aX+b) =",opts:["a²·Var(X)","a·Var(X)","Var(X)","Var(X)+b"],ans:0,exp:"Variance scales with the square of the multiplier."},
  {id:"q-1207",cat:"prob",diff:"medium",q:"For Binomial(n, p): E[X] =",opts:["p","np","n(1-p)","√(np)"],ans:1,exp:"Mean of Binomial is np."},
  {id:"q-1208",cat:"prob",diff:"medium",q:"For Binomial(n, p): Var(X) =",opts:["np","np(1−p)","n²p","p(1−p)"],ans:1,exp:"Variance of Binomial is np(1−p)."},
  {id:"q-1209",cat:"prob",diff:"medium",q:"A fair coin flipped 3 times, P(exactly 2 heads) =",opts:["1/8","3/8","1/2","3/4"],ans:1,exp:"C(3,2)·(1/2)³ = 3/8."},
  {id:"q-1210",cat:"prob",diff:"medium",q:"Standard normal has mean and variance:",opts:["0, 0","1, 1","0, 1","1, 0"],ans:2,exp:"Z ~ N(0,1)."},
  {id:"q-1211",cat:"prob",diff:"hard",q:"For Poisson(λ): E[X] =",opts:["λ²","λ","λ/2","1/λ"],ans:1,exp:"Mean equals λ."},
  {id:"q-1212",cat:"prob",diff:"hard",q:"P(A|B) when A, B are independent equals:",opts:["P(B)","P(A)","P(A)+P(B)","0"],ans:1,exp:"Independence: posterior equals prior."},
  {id:"q-1213",cat:"prob",diff:"medium",q:"Law of total probability: P(B) =",opts:["Σ P(B|Aᵢ)·P(Aᵢ)","P(B|A)","P(B)·P(A)","Σ P(Aᵢ)"],ans:0,exp:"Marginalize over partition."},
  {id:"q-1214",cat:"prob",diff:"medium",q:"If X ~ N(μ, σ²), then (X−μ)/σ ~",opts:["N(0, σ²)","N(0,1)","N(μ,1)","t-distribution"],ans:1,exp:"Standardization: Z = (X−μ)/σ ~ N(0,1)."},
  {id:"q-1215",cat:"prob",diff:"hard",q:"MLE stands for:",opts:["Maximum Likelihood Estimation","Most Likely Estimate","Mean of Log Evidence","Minimum Loss Estimator"],ans:0,exp:"Maximum Likelihood Estimation."},
  {id:"q-1216",cat:"prob",diff:"hard",q:"MAP differs from MLE by including:",opts:["Likelihood","Prior","Loss function","Gradient"],ans:1,exp:"MAP = argmax P(θ|data) ∝ P(data|θ)·P(θ)."},
  {id:"q-1217",cat:"prob",diff:"hard",q:"For continuous X with pdf f, P(X = c) =",opts:["f(c)","0","1","∞"],ans:1,exp:"Continuous distributions assign zero mass to single points."},
  {id:"q-1218",cat:"prob",diff:"medium",q:"Cov(X, X) =",opts:["0","Var(X)","E[X]","SD(X)"],ans:1,exp:"Covariance of a variable with itself is its variance."},
  {id:"q-1219",cat:"prob",diff:"medium",q:"If X, Y are independent, Cov(X, Y) =",opts:["E[XY]","0","Var(X)·Var(Y)","1"],ans:1,exp:"Independence implies zero covariance."},
  {id:"q-1220",cat:"prob",diff:"hard",q:"Central Limit Theorem: sum of i.i.d. variables approaches:",opts:["Uniform","Normal","Exponential","Poisson"],ans:1,exp:"CLT → Gaussian regardless of the original distribution (with finite variance)."},
  {id:"q-1221",cat:"prob",diff:"hard",q:"Type I error =",opts:["Rejecting a true null hypothesis","Failing to reject a false null","Accepting alternative","Sampling error"],ans:0,exp:"α = P(reject H₀ | H₀ true)."},
  {id:"q-1222",cat:"prob",diff:"hard",q:"A p-value < 0.05 typically leads to:",opts:["Reject H₀ at α = 0.05","Fail to reject H₀","Accept H₁","Restart experiment"],ans:0,exp:"If p < α, reject H₀."},
  {id:"q-1223",cat:"prob",diff:"medium",q:"Tossing 2 dice, P(sum = 7) =",opts:["1/12","1/6","1/8","1/4"],ans:1,exp:"Six favorable pairs out of 36: 6/36 = 1/6."},
  {id:"q-1224",cat:"prob",diff:"medium",q:"E[X] for X = {0,1,2} with P = {1/3, 1/3, 1/3} equals:",opts:["1","4/3","2","3"],ans:0,exp:"Mean = (0+1+2)/3 = 1."},
  {id:"q-1225",cat:"prob",diff:"hard",q:"If P(A) = 0.3, P(B) = 0.4, P(A∩B) = 0.1, then P(A∪B) =",opts:["0.7","0.6","0.5","0.1"],ans:1,exp:"P(A∪B) = 0.3 + 0.4 − 0.1 = 0.6."},
  {id:"q-1226",cat:"prob",diff:"hard",q:"For a 95% confidence interval from N(μ, σ²/n), margin of error uses:",opts:["z = 1.96","z = 1.645","z = 2.575","z = 0.5"],ans:0,exp:"Two-sided 95% CI: z = 1.96."},
  {id:"q-1227",cat:"prob",diff:"medium",q:"Geometric distribution with success prob p has mean:",opts:["1/p","p","p²","(1−p)/p"],ans:0,exp:"E[X] = 1/p."},
  {id:"q-1228",cat:"prob",diff:"medium",q:"If X and Y are i.i.d. with mean μ, E[X+Y] =",opts:["2μ","μ","μ²","0"],ans:0,exp:"Linearity + identical mean."},
  {id:"q-1229",cat:"prob",diff:"hard",q:"Markov's inequality bounds:",opts:["P(X ≥ a) ≤ E[X]/a","E[X]","Var(X)","P(X ≥ a) ≤ 1"],ans:0,exp:"Classical Markov bound for non-negative X."},
  {id:"q-1300",cat:"prog",diff:"easy",q:"Time complexity of accessing an array element by index:",opts:["O(1)","O(log n)","O(n)","O(n²)"],ans:0,exp:"Arrays store elements contiguously in memory.\nIndexing computes the address directly: base + index × element_size.\nNo searching needed → O(1) constant time."},
  {id:"q-1301",cat:"prog",diff:"easy",q:"A stack follows which order?",opts:["FIFO","LIFO","Random","Priority"],ans:1,exp:"LIFO = Last-In, First-Out.\nThink of a stack of plates: the last plate placed on top is the first one removed.\nOperations: push (add to top), pop (remove from top), peek (view top)."},
  {id:"q-1302",cat:"prog",diff:"easy",q:"A queue follows which order?",opts:["FIFO","LIFO","Random","Priority"],ans:0,exp:"FIFO = First-In, First-Out.\nLike a line at a store: first person in line is first served.\nOperations: enqueue (add to back), dequeue (remove from front)."},
  {id:"q-1303",cat:"prog",diff:"medium",q:"Worst-case time to search in a balanced BST:",opts:["O(1)","O(log n)","O(n)","O(n log n)"],ans:1,exp:"A balanced BST (AVL, Red-Black) has height O(log n).\nSearch compares with one node per level → O(log n) comparisons.\nWorst case only becomes O(n) if the tree becomes unbalanced."},
  {id:"q-1304",cat:"prog",diff:"medium",q:"Hash table average-case lookup is:",opts:["O(1)","O(log n)","O(n)","O(n²)"],ans:0,exp:"Hash function maps key to bucket index in O(1).\nWith a good hash function and low load factor, most buckets have 0 or 1 elements.\nWorst case O(n) if all keys hash to same bucket (collisions)."},
  {id:"q-1305",cat:"prog",diff:"medium",q:"Bubble sort worst-case is:",opts:["O(n log n)","O(n²)","O(n)","O(log n)"],ans:1,exp:"Bubble sort repeatedly swaps adjacent out-of-order elements.\nIn worst case (reversed array): ~n²/2 comparisons and swaps.\nNo early termination possible → O(n²)."},
  {id:"q-1306",cat:"prog",diff:"medium",q:"Merge sort worst-case is:",opts:["O(n log n)","O(n²)","O(n)","O(2ⁿ)"],ans:0,exp:"Merge sort divides array in half recursively (log n levels),\nthen merges sorted halves in O(n) per level.\nTotal: O(n log n) in ALL cases — guaranteed."},
  {id:"q-1307",cat:"prog",diff:"medium",q:"Quicksort average-case is:",opts:["O(n log n)","O(n²)","O(n)","O(log n)"],ans:0,exp:"Average case: good pivot splits ~evenly → log n levels × n work = O(n log n).\nWorst case: already sorted data + bad pivot choice → O(n²).\nRandomized pivot makes worst case extremely unlikely."},
  {id:"q-1308",cat:"prog",diff:"medium",q:"Binary search requires the input to be:",opts:["Sorted","Hashed","Linked","Heap-ordered"],ans:0,exp:"Binary search halves the search space each step: O(log n).\nThis only works if the array is sorted — otherwise there is no guarantee\nwhich half to discard."},
  {id:"q-1309",cat:"prog",diff:"easy",q:"Recursion needs a:",opts:["Loop counter","Base case","Static variable","Global object"],ans:1,exp:"A base case is a condition where the function returns directly without recursing.\nWithout it, the recursion never stops → stack overflow → crash.\nExample: fact(0) = 1 is the base case for factorial."},
  {id:"q-1310",cat:"prog",diff:"medium",q:"Memoization primarily optimizes:",opts:["I/O","Repeated subcalls","Sorting","Compilation"],ans:1,exp:"Memoization caches function results for already-computed inputs.\nWhen the same input appears again, return cached result instead of recomputing.\nTurns exponential recursion (e.g., Fibonacci O(2ⁿ)) into O(n)."},
  {id:"q-1311",cat:"prog",diff:"medium",q:"DFS on a graph uses which structure?",opts:["Queue","Stack","Heap","Hash"],ans:1,exp:"DFS (Depth-First Search) goes as deep as possible before backtracking.\nUses a stack: push neighbors, pop one, explore it fully.\nCan also be implemented via recursion (call stack = implicit stack)."},
  {id:"q-1312",cat:"prog",diff:"medium",q:"BFS uses which structure?",opts:["Stack","Queue","Heap","Tree"],ans:1,exp:"BFS (Breadth-First Search) explores all neighbors at distance d before distance d+1.\nUses a queue: enqueue all neighbors of current node, then dequeue next.\nGuarantees shortest path in unweighted graphs."},
  {id:"q-1313",cat:"prog",diff:"hard",q:"Dijkstra's algorithm finds:",opts:["MST","Shortest paths from a source","Maximum flow","Topological order"],ans:1,exp:"Dijkstra finds shortest paths from one source to all other nodes.\nUses a priority queue: always expand the unvisited node with smallest tentative distance.\nRequires non-negative edge weights (use Bellman-Ford if weights can be negative)."},
  {id:"q-1314",cat:"prog",diff:"medium",q:"Time complexity of Python dict average-case insertion:",opts:["O(1)","O(log n)","O(n)","O(n²)"],ans:0,exp:"Python dicts are hash tables with amortized O(1) insertion.\nCompute hash → find bucket → insert. Resize (rehash) happens occasionally\nbut the amortized cost per operation is constant."},
  {id:"q-1315",cat:"prog",diff:"easy",q:"A linked list does not support:",opts:["Insertion at head","Random access","Traversal","Dynamic size"],ans:1,exp:"Linked list nodes are scattered in memory (linked by pointers).\nTo access element at index i, must traverse from head: O(n).\nArrays have O(1) random access; linked lists do not."},
  {id:"q-1316",cat:"prog",diff:"medium",q:"Heap insertion is:",opts:["O(1)","O(log n)","O(n)","O(n log n)"],ans:1,exp:"Insert at the end, then 'sift up' to restore heap property.\nThe heap has height log n, so sift-up traverses at most log n levels.\nDeletion of min/max also takes O(log n) (sift down)."},
  {id:"q-1317",cat:"prog",diff:"medium",q:"A min-heap returns the next element in:",opts:["O(1)","O(log n)","O(n)","O(n²)"],ans:0,exp:"The minimum element is always at the root (index 0 in array representation).\nAccessing it is O(1). Removing it takes O(log n) because the heap must be repaired."},
  {id:"q-1318",cat:"prog",diff:"easy",q:"A boolean variable can hold:",opts:["True/False","Any string","Integers","Floats"],ans:0,exp:"Booleans have exactly two values: True and False (or 1 and 0).\nUsed in conditions: if, while, and logical operations (and, or, not)."},
  {id:"q-1319",cat:"prog",diff:"easy",q:"A list comprehension in Python produces:",opts:["A tuple","A list","A dict","A set"],ans:1,exp:"Syntax: [expression for item in iterable if condition]\nExample: [x² for x in range(5)] → [0, 1, 4, 9, 16]\nAlways produces a list. Use {} for dict/set comprehensions."},
  {id:"q-1320",cat:"prog",diff:"medium",q:"Big-O of `x in mylist` for a Python list:",opts:["O(1)","O(log n)","O(n)","O(n²)"],ans:2,exp:"Lists use sequential storage → must scan element by element.\nWorst case: element is not in list → scans all n elements → O(n).\nFor O(1) lookup, use a set or dict instead."},
  {id:"q-1321",cat:"prog",diff:"hard",q:"Stable sort preserves:",opts:["Speed","Order of equal keys","Memory","Recursion depth"],ans:1,exp:"A stable sort keeps the original relative order of equal elements.\nExample: sorting [(Alice,85), (Bob,92), (Charlie,85)] by score →\nAlice comes before Charlie (Alice appeared first in input).\nMerge sort is stable; quicksort is typically not."},
  {id:"q-1322",cat:"prog",diff:"hard",q:"Time complexity of `x in myset` in Python:",opts:["O(1) avg","O(log n)","O(n)","O(n²)"],ans:0,exp:"Python sets are hash tables → amortized O(1) membership test.\nHash the element, check if bucket is occupied.\nThis is why converting a list to a set before repeated lookups speeds things up."},
  {id:"q-1323",cat:"prog",diff:"medium",q:"Backtracking explores:",opts:["Greedy choices","All combinations with pruning","Sorted data","Random graphs"],ans:1,exp:"Backtracking = DFS + pruning of invalid paths.\nBuild solution incrementally, abandon ('backtrack') when current path can't lead to a solution.\nExample: N-Queens, Sudoku, generating all subsets."},
  {id:"q-1324",cat:"prog",diff:"hard",q:"A dynamic programming solution typically has:",opts:["Greedy structure","Overlapping subproblems + optimal substructure","Only recursion","Bit manipulation"],ans:1,exp:"Two hallmarks of DP:\n1. Overlapping subproblems: same subproblem solved multiple times (cache it)\n2. Optimal substructure: optimal solution built from optimal sub-solutions\nExample: Fibonacci → fib(n) = fib(n-1) + fib(n-2) has both."},
  {id:"q-1325",cat:"prog",diff:"medium",q:"Big-O of appending to the end of a Python list (amortized):",opts:["O(1)","O(log n)","O(n)","O(n²)"],ans:0,exp:"Python lists are dynamic arrays. Most appends are O(1).\nOccasionally the array is full and must be resized (copy all elements to a bigger array).\nThe resize is O(n) but happens so rarely that amortized cost per append is O(1)."},
  {id:"q-1326",cat:"prog",diff:"medium",q:"In Python, a tuple is:",opts:["Mutable","Immutable","A list","A dict"],ans:1,exp:"Tuples are immutable sequences — once created, they cannot be changed.\nUse ( ) or just commas: t = (1, 2, 3).\nImmutable means: can be dict keys, thread-safe, slightly faster than lists."},
  {id:"q-1327",cat:"prog",diff:"easy",q:"T(n) = T(n/2) + 1 solves to:",opts:["O(1)","O(log n)","O(n)","O(n²)"],ans:1,exp:"Recurrence: each call halves the input and does O(1) work.\nNumber of levels: n → n/2 → n/4 → ... → 1 = log₂(n) levels.\nTotal: log(n) levels × O(1) work = O(log n)."},
  {id:"q-1328",cat:"prog",diff:"medium",q:"Fibonacci with naive recursion is:",opts:["O(n)","O(log n)","O(2ⁿ)","O(n²)"],ans:2,exp:"Naive fib(n) calls fib(n-1) AND fib(n-2), which each call two more.\nThe call tree has ~2ⁿ nodes (exponential blowup).\nfib(5) calls fib(3) twice, fib(2) three times — massive redundancy.\nFix: memoization → O(n), or iterative → O(n)."},
  {id:"q-1329",cat:"prog",diff:"hard",q:"Topological sort applies to:",opts:["Any graph","Directed acyclic graphs","Trees only","Bipartite graphs"],ans:1,exp:"DAGs admit a topological order."},
  {id:"q-1400",cat:"oop",diff:"easy",q:"A class is a:",opts:["Function","Blueprint","Variable","Module"],ans:1,exp:"A class is a blueprint/template that defines the structure (attributes) and behavior (methods) of objects.\nYou create instances (objects) from a class, like creating houses from a blueprint."},
  {id:"q-1401",cat:"oop",diff:"easy",q:"An object is:",opts:["A class","An instance of a class","A function","A module"],ans:1,exp:"An object is a concrete instance created from a class.\nEach object has its own copy of the attributes defined in the class.\nExample: dog1 = Dog('Rex') creates one object; dog2 = Dog('Buddy') creates another."},
  {id:"q-1402",cat:"oop",diff:"easy",q:"`self` in Python refers to:",opts:["The class","The instance","The module","The function"],ans:1,exp:"self refers to the current instance — the specific object calling the method.\nIn Python, methods receive self as the first parameter automatically.\nself.name = 'Rex' sets the name attribute on THIS specific object."},
  {id:"q-1403",cat:"oop",diff:"easy",q:"Encapsulation means:",opts:["Hiding internals","Inheritance","Polymorphism","Dynamic typing"],ans:0,exp:"Encapsulation bundles data (attributes) and methods that operate on that data into a single unit (class).\nAccess is controlled: public API exposed, internal details hidden.\nPython uses _ (protected) and __ (private) naming conventions."},
  {id:"q-1404",cat:"oop",diff:"easy",q:"Inheritance allows:",opts:["Code reuse via parent classes","Faster code","Compilation","Network calls"],ans:0,exp:"A subclass inherits all attributes and methods from its parent class.\nChild can add new methods or override parent methods.\nExample: class Dog(Animal) inherits speak(), eat() from Animal."},
  {id:"q-1405",cat:"oop",diff:"easy",q:"Polymorphism allows:",opts:["One interface, many implementations","Single inheritance only","Static methods","Multiple modules"],ans:0,exp:"Same method call produces different behavior based on the object's type.\nExample: animal.speak() → Dog says 'Woof', Cat says 'Meow'.\nThe code calling speak() doesn't need to know the specific type."},
  {id:"q-1406",cat:"oop",diff:"medium",q:"Abstraction in OOP means:",opts:["Showing only essential features","Hiding everything","Multiple inheritance","Concurrency"],ans:0,exp:"Abstraction hides complex implementation details and exposes only the essential interface.\nExample: you drive a car (accelerate, brake) without knowing how the engine works.\nAbstract classes and interfaces enforce abstraction."},
  {id:"q-1407",cat:"oop",diff:"medium",q:"A method marked `@staticmethod` receives:",opts:["self","cls","Neither self nor cls","Only args"],ans:2,exp:"@staticmethod defines a method that belongs to the class but doesn't access\ninstance (self) or class (cls) state. It's just a regular function placed in the class namespace for organization."},
  {id:"q-1408",cat:"oop",diff:"medium",q:"`@classmethod` receives:",opts:["self","cls","Neither","A module"],ans:1,exp:"@classmethod receives the class itself (cls) as the first argument, not an instance.\nCommon use: alternative constructors (e.g., Dog.from_name('Rex')).\ncls() creates a new instance of the class (works correctly for subclasses too)."},
  {id:"q-1409",cat:"oop",diff:"medium",q:"Composition is a relationship where:",opts:["'is-a'","'has-a'","'uses-a'","None"],ans:1,exp:"Composition = 'has-a' relationship: one object contains another.\nExample: a Car HAS-A Engine, a Student HAS-A Schedule.\nFavor composition over inheritance — more flexible, less coupling."},
  {id:"q-1410",cat:"oop",diff:"medium",q:"Liskov Substitution Principle says:",opts:["Subtypes must be substitutable for base types","Subclasses hide methods","All methods must be virtual","No exceptions allowed"],ans:0,exp:"LSP: if S is a subtype of T, then objects of T can be replaced with objects of S\nwithout breaking the program.\nExample: if a function expects an Animal, passing a Dog should work.\nViolations: Square subclassing Rectangle but changing setWidth() behavior."},
  {id:"q-1411",cat:"oop",diff:"medium",q:"S.O.L.I.D.'s 'S' stands for:",opts:["Single responsibility","Static typing","Subclassing","Strict typing"],ans:0,exp:"Single Responsibility Principle: a class should have only ONE reason to change.\nEach class should have one job / responsibility.\nExample: separate UserAuthentication from UserDatabase — different reasons to change."},
  {id:"q-1412",cat:"oop",diff:"medium",q:"The 'O' in SOLID stands for:",opts:["Open/closed","Optional","Object","Override"],ans:0,exp:"Open/Closed Principle: classes should be OPEN for extension (add new behavior)\nbut CLOSED for modification (don't change existing tested code).\nAchieved via interfaces, abstract classes, and strategy pattern."},
  {id:"q-1413",cat:"oop",diff:"medium",q:"The 'D' in SOLID stands for:",opts:["Dynamic dispatch","Dependency inversion","Data hiding","Default methods"],ans:1,exp:"Dependency Inversion Principle: depend on abstractions (interfaces), not concretions.\nHigh-level modules shouldn't depend on low-level modules — both depend on abstractions.\nExample: code should depend on Logger interface, not ConsoleLogger class."},
  {id:"q-1414",cat:"oop",diff:"medium",q:"A `__init__` method in Python is:",opts:["Destructor","Constructor","Decorator","Generator"],ans:1,exp:"__init__ is the constructor/initializer — called automatically when creating an object.\ndog = Dog('Rex') → __init__(self, name='Rex') runs.\nSets up initial attribute values for the new instance."},
  {id:"q-1415",cat:"oop",diff:"medium",q:"Multiple inheritance is supported in:",opts:["Java","C++","C#","Go (structs only)"],ans:1,exp:"C++ supports multiple inheritance directly (a class can inherit from multiple parents).\nJava and C# support only single inheritance of classes (but multiple interfaces).\nPython also supports it but the MRO (Method Resolution Order) resolves conflicts."},
  {id:"q-1416",cat:"oop",diff:"medium",q:"An abstract class:",opts:["Can be instantiated","Must be subclassed","Has no methods","Has only static fields"],ans:1,exp:"An abstract class CANNOT be instantiated directly — it's meant to be a template.\nSubclasses must implement all abstract methods before they can be instantiated.\nExample: Shape is abstract; Circle and Rectangle are concrete subclasses."},
  {id:"q-1417",cat:"oop",diff:"hard",q:"The Diamond Problem is solved in C++ via:",opts:["Dynamic dispatch","Virtual inheritance","Garbage collection","Namespaces"],ans:1,exp:"Diamond Problem: class D inherits from both B and C, which both inherit from A.\nWithout virtual inheritance, D would have TWO copies of A's members.\nVirtual inheritance: B and C share a single instance of A."},
  {id:"q-1418",cat:"oop",diff:"medium",q:"The Factory pattern is:",opts:["Creational","Structural","Behavioral","Concurrency"],ans:0,exp:"Factory is a creational pattern: provides an interface for creating objects\nwithout specifying their exact class.\nExample: AnimalFactory.create('dog') returns a Dog instance.\nCaller doesn't need to know the concrete class — decouples creation from usage."},
  {id:"q-1419",cat:"oop",diff:"medium",q:"The Observer pattern is:",opts:["Creational","Structural","Behavioral","Functional"],ans:2,exp:"Observer is a behavioral pattern: defines one-to-many dependency.\nWhen one object (subject) changes state, all its dependents (observers) are notified.\nExample: event listeners, pub/sub, UI updates when data changes."},
  {id:"q-1420",cat:"oop",diff:"medium",q:"The Decorator pattern:",opts:["Wraps objects to add behavior","Creates families","Replaces inheritance","Compresses data"],ans:0,exp:"Decorator adds new behavior to an object by wrapping it in a decorator class.\nAlternative to subclassing — more flexible, can stack multiple decorators.\nExample: @logged, @timed decorators wrap a function with logging/timing."},
  {id:"q-1421",cat:"oop",diff:"medium",q:"The Singleton pattern ensures:",opts:["Many instances","Exactly one instance","No inheritance","Async access"],ans:1,exp:"Singleton restricts class instantiation to exactly ONE object.\nUsed for shared resources: database connections, loggers, config managers.\nImplemented via private constructor + static instance + static getter."},
  {id:"q-1422",cat:"oop",diff:"easy",q:"A subclass `__init__` should call:",opts:["The parent constructor explicitly","Nothing","Garbage collector","Thread lock"],ans:0,exp:"In Python: super().__init__() — calls the parent's __init__ to set up inherited attributes.\nIn Java: super() — must be the first line of the subclass constructor.\nWithout it, parent attributes won't be initialized."},
  {id:"q-1423",cat:"oop",diff:"easy",q:"`isinstance(obj, Class)` checks:",opts:["Equality","Type","Memory","Identity"],ans:1,exp:"isinstance() returns True if obj is an instance of Class or ANY of its subclasses.\nExample: isinstance(dog, Animal) → True (Dog inherits from Animal).\nUseful for type-checking with inheritance hierarchies."},
  {id:"q-1424",cat:"oop",diff:"easy",q:"A property in Python is created with:",opts:["@property","@getter","@field","@attr"],ans:0,exp:"@property turns a method into a read-only attribute-like accessor.\nAllows you to add validation logic to getting/setting attributes.\nExample: @property def age(self): return self._age"},
  {id:"q-1425",cat:"oop",diff:"medium",q:"Method overriding allows:",opts:["Same name, different behavior in subclass","Static binding","Name hiding","Overloading only"],ans:0,exp:"A subclass can redefine a method inherited from the parent.\nSame method name and signature, but different implementation.\nCalled via dynamic dispatch: obj.speak() calls the subclass version, not the parent's."},
  {id:"q-1426",cat:"oop",diff:"medium",q:"Method overloading (same name, different args) is:",opts:["Native in Python via args","Resolved by type","Done via default args","Not supported"],ans:2,exp:"Python does NOT support traditional method overloading (same name, different parameter types).\nWorkarounds: default arguments, *args/**kwargs, or isinstance checks.\nOnly the LAST definition of a method survives — previous ones are overwritten."},
  {id:"q-1427",cat:"oop",diff:"hard",q:"Cohesion vs coupling: high cohesion + low coupling is:",opts:["Good design","Bad design","Slow","Memory-intensive"],ans:0,exp:"High cohesion: a class's methods are closely related to its attributes (focused purpose).\nLow coupling: classes depend on as few other classes as possible.\nHigh cohesion + low coupling = modular, maintainable, testable code (SOLID goal)."},
  {id:"q-1428",cat:"oop",diff:"medium",q:"A Mixin is:",opts:["A standalone class","A class meant to add functionality via inheritance","An interface","An enum"],ans:1,exp:"A Mixin is a small class that provides reusable methods to be inherited.\nNot meant to stand alone — provides extra behavior when mixed into other classes.\nExample: a LogMixin adds logging methods to any class that inherits it."},
  {id:"q-1429",cat:"oop",diff:"medium",q:"UML class diagram: an open triangle arrow means:",opts:["Dependency","Inheritance/generalization","Composition","Aggregation"],ans:1,exp:"UML notation: open/hollow triangle arrowhead = inheritance (generalization).\nPoints from child TO parent: Dog → Animal means 'Dog extends Animal'.\nFilled diamond = composition, open diamond = aggregation, dashed arrow = dependency."},
  {id:"q-1500",cat:"ml",diff:"easy",q:"Supervised learning uses:",opts:["Unlabeled data","Labeled data","Only images","Only text"],ans:1,exp:"Pairs (x, y) used to learn a mapping."},
  {id:"q-1501",cat:"ml",diff:"easy",q:"Unsupervised learning finds:",opts:["Labels","Patterns/structure","Errors","Rewards"],ans:1,exp:"Discovers clusters, manifolds, anomalies."},
  {id:"q-1502",cat:"ml",diff:"easy",q:"Linear regression minimizes:",opts:["MSE","Entropy","Accuracy","F1"],ans:0,exp:"Most common loss for regression."},
  {id:"q-1503",cat:"ml",diff:"easy",q:"Logistic regression is used for:",opts:["Regression","Classification","Clustering","Generation"],ans:1,exp:"Binary/multiclass classification."},
  {id:"q-1504",cat:"ml",diff:"medium",q:"Cross-entropy loss is used for:",opts:["Regression","Classification","PCA","K-means"],ans:1,exp:"Standard for probabilistic classifiers."},
  {id:"q-1505",cat:"ml",diff:"medium",q:"Closed-form solution for linear regression:",opts:["w = (XᵀX)⁻¹Xᵀy","w = X⁻¹y","w = Xᵀy","w = y/X"],ans:0,exp:"Normal equations."},
  {id:"q-1506",cat:"ml",diff:"medium",q:"Ridge regression adds which regularization?",opts:["L1","L2","L∞","Dropout"],ans:1,exp:"L2 penalty on weights."},
  {id:"q-1507",cat:"ml",diff:"medium",q:"Lasso regression uses which penalty?",opts:["L1","L2","Elastic net only","No penalty"],ans:0,exp:"L1 induces sparsity."},
  {id:"q-1508",cat:"ml",diff:"medium",q:"A decision tree splits on:",opts:["Random","Information gain / Gini","Distance","Probability"],ans:1,exp:"Maximizes purity at each split."},
  {id:"q-1509",cat:"ml",diff:"medium",q:"Random forest is an ensemble of:",opts:["Linear models","Decision trees","SVMs","k-NN models"],ans:1,exp:"Bagging of trees."},
  {id:"q-1510",cat:"ml",diff:"medium",q:"XGBoost is a form of:",opts:["Bagging","Boosting","Stacking","Dropout"],ans:1,exp:"Gradient boosting with trees."},
  {id:"q-1511",cat:"ml",diff:"hard",q:"SVM kernel trick:",opts:["Maps data to lower dim","Maps data to higher dim implicitly","Removes features","Reduces labels"],ans:1,exp:"Allows non-linear decision boundaries."},
  {id:"q-1512",cat:"ml",diff:"hard",q:"Soft margin SVM uses:",opts:["Only C","Hinge loss + L2 reg","MSE","No regularization"],ans:1,exp:"Slack variables + penalty parameter C."},
  {id:"q-1513",cat:"ml",diff:"medium",q:"k-NN is called a:",opts:["Eager learner","Lazy learner","Generative model","Latent model"],ans:1,exp:"No training phase; compares at predict time."},
  {id:"q-1514",cat:"ml",diff:"medium",q:"Naive Bayes assumes:",opts:["Features dependent","Features independent given class","Continuous labels","Gaussian noise"],ans:1,exp:"Conditional independence."},
  {id:"q-1515",cat:"ml",diff:"medium",q:"PCA finds directions of:",opts:["Maximum variance","Minimum variance","Equal variance","Random"],ans:0,exp:"Top eigenvectors of covariance matrix."},
  {id:"q-1516",cat:"ml",diff:"medium",q:"t-SNE is used for:",opts:["Classification","Dimensionality reduction visualization","Generation","Clustering only"],ans:1,exp:"Non-linear 2D/3D projection."},
  {id:"q-1517",cat:"ml",diff:"medium",q:"k-Means minimizes:",opts:["Within-cluster sum of squares","Entropy","Variance","Log-likelihood"],ans:0,exp:"WCSS objective."},
  {id:"q-1518",cat:"ml",diff:"medium",q:"DBSCAN clusters by:",opts:["Centroids","Density","Hierarchical merge","Probabilities"],ans:1,exp:"Density-reachability."},
  {id:"q-1519",cat:"ml",diff:"hard",q:"Bias-variance tradeoff says total error =",opts:["Bias + Var","Bias² + Var + noise","Bias × Var","Var only"],ans:1,exp:"Classic decomposition."},
  {id:"q-1520",cat:"ml",diff:"hard",q:"Underfitting corresponds to:",opts:["High bias, low variance","Low bias, high variance","Both high","Neither"],ans:0,exp:"Model too simple."},
  {id:"q-1521",cat:"ml",diff:"medium",q:"Standardization rescales features to:",opts:["[0,1]","Mean 0, var 1","Unit norm","Same range"],ans:1,exp:"z = (x − μ)/σ."},
  {id:"q-1522",cat:"ml",diff:"easy",q:"One-hot encoding converts a categorical to:",opts:["A single integer","Binary vectors","Floats","Strings"],ans:1,exp:"|categories| binary columns."},
  {id:"q-1523",cat:"ml",diff:"medium",q:"Feature selection methods include:",opts:["Filter, wrapper, embedded","Only L1","Only PCA","Dropout"],ans:0,exp:"Three classic families."},
  {id:"q-1524",cat:"ml",diff:"medium",q:"A perceptron computes:",opts:["Weighted sum then activation","XOR only","Always sigmoid","Maximum"],ans:0,exp:"Linear combiner + nonlinearity."},
  {id:"q-1525",cat:"ml",diff:"medium",q:"Multi-layer perceptron (MLP) stacks:",opts:["Linear models","Perceptrons with nonlinear activations","Decision trees","k-NN"],ans:1,exp:"Layers of perceptrons + nonlinearities."},
  {id:"q-1526",cat:"ml",diff:"hard",q:"Backprop uses:",opts:["Forward pass only","Chain rule","Random sampling","Markov chains"],ans:1,exp:"Chain rule applied to compute gradients."},
  {id:"q-1527",cat:"ml",diff:"medium",q:"F1 score =",opts:["2PR/(P+R)","(P+R)/2","P+R","P/R"],ans:0,exp:"Harmonic mean of precision and recall."},
  {id:"q-1528",cat:"ml",diff:"medium",q:"Precision = TP /",opts:["TP+FP","TP+FN","TP+TN","FN+FP"],ans:0,exp:"TP / (TP + FP)."},
  {id:"q-1529",cat:"ml",diff:"medium",q:"Recall = TP /",opts:["TP+FP","TP+FN","TN+FP","FN+FP"],ans:1,exp:"TP / (TP + FN)."},
  {id:"q-1600",cat:"dl",diff:"easy",q:"ReLU(x) =",opts:["max(0, x)","x","sigmoid(x)","tanh(x)"],ans:0,exp:"Rectified Linear Unit."},
  {id:"q-1601",cat:"dl",diff:"easy",q:"Sigmoid squashes to:",opts:["[0,1]","[-1,1]","[0,∞)","[-∞,∞]"],ans:0,exp:"σ(x) ∈ (0, 1)."},
  {id:"q-1602",cat:"dl",diff:"easy",q:"tanh squashes to:",opts:["[0,1]","[-1,1]","[0,∞)","[-2,2]"],ans:1,exp:"Range (−1, 1)."},
  {id:"q-1603",cat:"dl",diff:"medium",q:"SGD with momentum adds:",opts:["Adaptive learning rates","A velocity term","Dropout","Batch norm"],ans:1,exp:"Velocity accumulates past gradients."},
  {id:"q-1604",cat:"dl",diff:"medium",q:"Adam optimizer combines:",opts:["SGD + momentum","Momentum + RMSProp","Adagrad only","None"],ans:1,exp:"Adaptive moment estimation."},
  {id:"q-1605",cat:"dl",diff:"medium",q:"RMSProp uses:",opts:["Momentum only","Running average of squared gradients","Adagrad minus momentum","No memory"],ans:1,exp:"Adapts LR per parameter."},
  {id:"q-1606",cat:"dl",diff:"medium",q:"Dropout is used for:",opts:["Regularization","Initialization","Loss","Activation"],ans:0,exp:"Randomly zeros activations during training."},
  {id:"q-1607",cat:"dl",diff:"medium",q:"BatchNorm normalizes:",opts:["Across batch dimension","Per sample globally","Only at output","Across epochs"],ans:0,exp:"Normalizes activations across the mini-batch."},
  {id:"q-1608",cat:"dl",diff:"medium",q:"LayerNorm normalizes:",opts:["Across batch","Across feature dimension of one sample","Across epochs","Across classes"],ans:1,exp:"Per-sample across features."},
  {id:"q-1609",cat:"dl",diff:"medium",q:"A convolution shares weights via:",opts:["Stride","Padding","Kernel","Pooling"],ans:2,exp:"Same kernel slides across positions."},
  {id:"q-1610",cat:"dl",diff:"easy",q:"Max pooling outputs:",opts:["Average of window","Maximum of window","Sum","Random"],ans:1,exp:"Keeps the largest activation in the window."},
  {id:"q-1611",cat:"dl",diff:"medium",q:"Stride in convolution:",opts:["Increases kernel size","Controls step of kernel","Pads input","Removes channels"],ans:1,exp:"Step size when sliding the kernel."},
  {id:"q-1612",cat:"dl",diff:"hard",q:"Padding='same' preserves:",opts:["Output size = input size","Channels","Filter count","Bias"],ans:0,exp:"Pads so output spatial size matches input."},
  {id:"q-1613",cat:"dl",diff:"hard",q:"Vanishing gradient problem is mitigated by:",opts:["ReLU + residual connections","Sigmoid only","Linear activations","No init"],ans:0,exp:"Modern activation + skip connections."},
  {id:"q-1614",cat:"dl",diff:"medium",q:"He/Xavier initialization targets:",opts:["Zero gradients","Stable variance across layers","Sparse weights","Small models"],ans:1,exp:"Keeps activation/gradient variance roughly constant."},
  {id:"q-1615",cat:"dl",diff:"medium",q:"ResNet introduces:",opts:["Vanishing gradient","Skip / residual connections","Attention only","Dropout"],ans:1,exp:"y = F(x) + x; enables very deep nets."},
  {id:"q-1616",cat:"dl",diff:"medium",q:"An LSTM has gates:",opts:["1","2","3","4"],ans:2,exp:"Forget, input, output."},
  {id:"q-1617",cat:"dl",diff:"medium",q:"GRU has gates:",opts:["1","2","3","4"],ans:1,exp:"Reset and update."},
  {id:"q-1618",cat:"dl",diff:"medium",q:"Seq2seq has:",opts:["One encoder","Encoder + decoder","Two encoders","No decoder"],ans:1,exp:"Encoder-decoder architecture."},
  {id:"q-1619",cat:"dl",diff:"hard",q:"Teacher forcing uses:",opts:["Ground truth as next input","Random tokens","Generated output","Dropout"],ans:0,exp:"During training, feed the true previous token instead of prediction."},
  {id:"q-1620",cat:"dl",diff:"hard",q:"Attention formula:",opts:["Q·K","softmax(QKᵀ/√d)·V","Q+K","Q−K"],ans:1,exp:"Scaled dot-product attention."},
  {id:"q-1621",cat:"dl",diff:"hard",q:"Self-attention computes:",opts:["Token–token interactions","Cross-lingual","Only positions","Convolutions"],ans:0,exp:"Tokens attend to other tokens."},
  {id:"q-1622",cat:"dl",diff:"hard",q:"Multi-head attention allows:",opts:["Multiple parallel subspaces","Single head","No parameters","Recurrence"],ans:0,exp:"h parallel attention heads concatenated."},
  {id:"q-1623",cat:"dl",diff:"hard",q:"A Transformer has complexity per layer:",opts:["O(n)","O(n²)","O(log n)","O(2ⁿ)"],ans:1,exp:"Self-attention over n tokens is O(n²)."},
  {id:"q-1624",cat:"dl",diff:"medium",q:"A CNN is well suited to:",opts:["Sequences","Images / grid data","Sets","Trees"],ans:1,exp:"Local receptive fields and weight sharing."},
  {id:"q-1625",cat:"dl",diff:"medium",q:"A pooling layer:",opts:["Adds parameters","Downsamples","Adds channels","Activates"],ans:1,exp:"Reduces spatial size."},
  {id:"q-1626",cat:"dl",diff:"medium",q:"Gradient clipping addresses:",opts:["Exploding gradients","Vanishing gradients","Slow LR","Initialization"],ans:0,exp:"Caps large gradients to a norm."},
  {id:"q-1627",cat:"dl",diff:"medium",q:"LR scheduling includes:",opts:["Constant only","Step, cosine, warmup","Only decay","Only warmup"],ans:1,exp:"Many schedules exist."},
  {id:"q-1628",cat:"dl",diff:"medium",q:"Weight decay is equivalent to L2 when applied to:",opts:["All optimizers","SGD-style updates","Adam only","Adagrad"],ans:1,exp:"Standard SGD case."},
  {id:"q-1629",cat:"dl",diff:"hard",q:"A residual block computes y =",opts:["F(x)","x","F(x) + x","F(x) − x"],ans:2,exp:"Skip connection addition."},
  {id:"q-1700",cat:"nlp",diff:"easy",q:"Tokenization is:",opts:["Encrypting text","Splitting text into tokens","Embedding tokens","Translating"],ans:1,exp:"First preprocessing step."},
  {id:"q-1701",cat:"nlp",diff:"easy",q:"Lowercasing is:",opts:["Embedding","Normalization","Translation","Generation"],ans:1,exp:"Common preprocessing step."},
  {id:"q-1702",cat:"nlp",diff:"easy",q:"Stopwords are:",opts:["High-frequency words to filter","Errors","Embeddings","Tokens"],ans:0,exp:"Common words like 'the', 'a'."},
  {id:"q-1703",cat:"nlp",diff:"medium",q:"Stemming chops word ends using:",opts:["Rules","Embeddings","LLMs","POS tags"],ans:0,exp:"Heuristic suffix removal."},
  {id:"q-1704",cat:"nlp",diff:"medium",q:"Lemmatization requires:",opts:["POS info","Just rules","Random","GPU"],ans:0,exp:"Uses vocabulary + morphology."},
  {id:"q-1705",cat:"nlp",diff:"medium",q:"TF-IDF stands for:",opts:["Term frequency · inverse document frequency","Token format · index","Text feature index","Time-frequency"],ans:0,exp:"Classic IR weighting."},
  {id:"q-1706",cat:"nlp",diff:"medium",q:"Word2Vec produces:",opts:["Sparse one-hots","Dense embeddings","BoW","RNNs"],ans:1,exp:"Continuous distributed representations."},
  {id:"q-1707",cat:"nlp",diff:"medium",q:"GloVe is based on:",opts:["Local context","Global co-occurrence","Attention","Recurrence"],ans:1,exp:"Matrix factorization on co-occurrence."},
  {id:"q-1708",cat:"nlp",diff:"medium",q:"FastText uses:",opts:["Characters/subwords","Whole words only","Bytes only","Bytes + parity"],ans:0,exp:"Subword n-grams for OOV handling."},
  {id:"q-1709",cat:"nlp",diff:"medium",q:"Cosine similarity measures:",opts:["Euclidean distance","Angle between vectors","Manhattan distance","Norm"],ans:1,exp:"cos(θ) = (u·v)/(||u||·||v||)."},
  {id:"q-1710",cat:"nlp",diff:"medium",q:"BLEU measures:",opts:["Translation/generation","Classification accuracy","F1","Recall"],ans:0,exp:"N-gram overlap with references."},
  {id:"q-1711",cat:"nlp",diff:"medium",q:"ROUGE measures:",opts:["Translation","Summarization","Generation length","POS accuracy"],ans:1,exp:"Recall-oriented n-grams."},
  {id:"q-1712",cat:"nlp",diff:"hard",q:"BERT is:",opts:["Decoder-only","Encoder-only","Encoder-decoder","None"],ans:1,exp:"Bidirectional encoder."},
  {id:"q-1713",cat:"nlp",diff:"hard",q:"GPT is:",opts:["Decoder-only","Encoder-only","Encoder-decoder","None"],ans:0,exp:"Autoregressive decoder stack."},
  {id:"q-1714",cat:"nlp",diff:"hard",q:"T5 is:",opts:["Decoder-only","Encoder-only","Encoder-decoder","RNN"],ans:2,exp:"Text-to-text transfer transformer."},
  {id:"q-1715",cat:"nlp",diff:"medium",q:"Fine-tuning vs prompting: fine-tuning",opts:["Updates all parameters","Uses no parameters","Uses 0 examples","Avoids gradient"],ans:0,exp:"Full or partial parameter update."},
  {id:"q-1716",cat:"nlp",diff:"medium",q:"In-context learning uses:",opts:["Gradient updates","Examples in the prompt","Reinforcement","Decoding tricks"],ans:1,exp:"Few-shot via prompt only."},
  {id:"q-1717",cat:"nlp",diff:"medium",q:"NER stands for:",opts:["Named entity recognition","Neural embedding ranking","Numeric entity retrieval","None"],ans:0,exp:"Find people, places, etc."},
  {id:"q-1718",cat:"nlp",diff:"medium",q:"Perplexity is used for:",opts:["Translation","LM evaluation","NER","POS tagging"],ans:1,exp:"Lower perplexity = better LM."},
  {id:"q-1719",cat:"nlp",diff:"hard",q:"A tokenizer's vocabulary size affects:",opts:["Memory and OOV rate","Only speed","Only accuracy","Nothing"],ans:0,exp:"Bigger vocab → fewer OOV, more memory."},
  {id:"q-1720",cat:"nlp",diff:"hard",q:"BPE (byte-pair encoding) builds vocab by:",opts:["Merging frequent pairs","Random sampling","Letter removal","Padding"],ans:0,exp:"Greedy bottom-up merge."},
  {id:"q-1721",cat:"nlp",diff:"medium",q:"Word sense disambiguation is:",opts:["POS tagging","Determining meaning in context","Translation","Embedding"],ans:1,exp:"Picking the right sense."},
  {id:"q-1722",cat:"nlp",diff:"medium",q:"Bag-of-words ignores:",opts:["Word order","Word counts","Word presence","Frequency"],ans:0,exp:"BoW is order-agnostic."},
  {id:"q-1723",cat:"nlp",diff:"hard",q:"A transformer context window limits:",opts:["Number of training epochs","Number of tokens per inference","Embedding dim","Vocabulary"],ans:1,exp:"Maximum tokens attended in one pass."},
  {id:"q-1724",cat:"nlp",diff:"medium",q:"Stemming vs lemmatization: lemmatization is:",opts:["Faster","More accurate but slower","Random","Same"],ans:1,exp:"Uses vocabulary + morphology."},
  {id:"q-1725",cat:"nlp",diff:"medium",q:"A sentiment classifier output is often:",opts:["A label or score","An image","A tree","A graph"],ans:0,exp:"Positive/negative or probability."},
  {id:"q-1726",cat:"nlp",diff:"medium",q:"Span-based QA predicts:",opts:["Label per token","Start and end positions","Class","Embedding"],ans:1,exp:"Span extraction."},
  {id:"q-1727",cat:"nlp",diff:"hard",q:"Zero-shot classification requires:",opts:["Labels per class","Only class names","A retriever","A LM"],ans:1,exp:"Use pretrained LM with class verbalizer."},
  {id:"q-1728",cat:"nlp",diff:"medium",q:"A chat template typically includes:",opts:["Only input","System + user + assistant","Only assistant","Only tokens"],ans:1,exp:"Multi-role turns."},
  {id:"q-1729",cat:"nlp",diff:"hard",q:"Long-context transformers may use:",opts:["Sparse attention","Pure dense","Recurrence","CNN"],ans:0,exp:"Sparse / linear attention variants."},
  {id:"q-1800",cat:"llm",diff:"medium",q:"An LLM is typically:",opts:["Encoder-only Transformer","Decoder-only Transformer","CNN","RNN"],ans:1,exp:"Decoder-only stacks (GPT-style)."},
  {id:"q-1801",cat:"llm",diff:"medium",q:"Causal self-attention masks:",opts:["Future tokens","Past tokens","Padding only","Nothing"],ans:0,exp:"Prevents attending to future positions."},
  {id:"q-1802",cat:"llm",diff:"medium",q:"RoPE encodes:",opts:["Absolute positions only","Rotary positional embeddings","Byte-pairs","Subwords"],ans:1,exp:"Rotates query/key by position."},
  {id:"q-1803",cat:"llm",diff:"medium",q:"ALiBi adds:",opts:["Rotary embeddings","Linear bias to attention","Dropout","Activation"],ans:1,exp:"Linear attention bias for length generalization."},
  {id:"q-1804",cat:"llm",diff:"medium",q:"KV cache speeds up:",opts:["Training","Inference","Tokenization","Embedding"],ans:1,exp:"Avoids recomputing K,V for past tokens."},
  {id:"q-1805",cat:"llm",diff:"medium",q:"Context window limits:",opts:["Vocabulary","Max tokens attended in inference","Number of epochs","Batch size"],ans:1,exp:"Hard cap on prompt+output length."},
  {id:"q-1806",cat:"llm",diff:"medium",q:"Pretraining objective is typically:",opts:["Next-token prediction","Classification","Regression","Clustering"],ans:0,exp:"Standard LM objective."},
  {id:"q-1807",cat:"llm",diff:"medium",q:"Cross-entropy loss for LM = -log P(next token | context).",opts:["True","False","Only at decoding","Only at eval"],ans:0,exp:"That is the standard loss."},
  {id:"q-1808",cat:"llm",diff:"medium",q:"Chinchilla scaling suggests:",opts:["More parameters than tokens","Tokens ≈ 20 × parameters","No scaling","Random"],ans:1,exp:"Roughly 20 tokens per parameter."},
  {id:"q-1809",cat:"llm",diff:"hard",q:"Scaling laws describe:",opts:["Loss vs N,D,compute","Loss vs temperature","Loss vs dropout","Loss vs LR"],ans:0,exp:"Empirical relationships (Kaplan, Chinchilla)."},
  {id:"q-1810",cat:"llm",diff:"medium",q:"SFT =",opts:["Supervised fine-tuning","Self-supervised training","Stochastic forward tuning","Sample-free tuning"],ans:0,exp:"Supervised fine-tuning on instruction data."},
  {id:"q-1811",cat:"llm",diff:"hard",q:"RLHF uses:",opts:["Reward model + PPO","Only PPO","Only RM","Only SFT"],ans:0,exp:"Train RM on preferences, optimize policy with PPO."},
  {id:"q-1812",cat:"llm",diff:"hard",q:"DPO directly optimizes:",opts:["A reward model","Policy from preference data","A value function","A classifier"],ans:1,exp:"Direct preference optimization without RM."},
  {id:"q-1813",cat:"llm",diff:"medium",q:"LoRA is:",opts:["Full fine-tuning","Low-rank parameter update","Quantization","Pruning"],ans:1,exp:"Adds trainable low-rank matrices."},
  {id:"q-1814",cat:"llm",diff:"medium",q:"QLoRA combines:",opts:["LoRA + quantization","LoRA + dropout","LoRA + MoE","LoRA + RLHF"],ans:0,exp:"4-bit base + LoRA adapters."},
  {id:"q-1815",cat:"llm",diff:"medium",q:"PEFT stands for:",opts:["Parameter-efficient fine-tuning","Pretraining framework","Pretrained eval","Parallel eval FT"],ans:0,exp:"Family of methods (LoRA, prefix tuning, etc.)."},
  {id:"q-1816",cat:"llm",diff:"medium",q:"RAG =",opts:["Retrieval-augmented generation","Random activation gating","Reinforced attention grad","Recursive attention gen"],ans:0,exp:"Retrieve docs → augment prompt → generate."},
  {id:"q-1817",cat:"llm",diff:"medium",q:"A vector DB stores:",opts:["Strings","Embeddings","Images","Labels"],ans:1,exp:"Dense vectors for similarity search."},
  {id:"q-1818",cat:"llm",diff:"medium",q:"Greedy decoding picks:",opts:["Sample with temp=1","argmax","Random","Beam"],ans:1,exp:"Highest-probability token at each step."},
  {id:"q-1819",cat:"llm",diff:"medium",q:"Beam search keeps:",opts:["Top-k candidates per step","Single best","Random","None"],ans:0,exp:"k-best hypotheses."},
  {id:"q-1820",cat:"llm",diff:"medium",q:"Temperature scaling:",opts:["Adds bias","Sharpens/softens distribution","Adds layers","Prunes"],ans:1,exp:"Lower temp → sharper distribution."},
  {id:"q-1821",cat:"llm",diff:"medium",q:"Top-k sampling restricts to:",opts:["Top k tokens","All tokens","None","Bottom k"],ans:0,exp:"Sample from the k highest-prob tokens."},
  {id:"q-1822",cat:"llm",diff:"medium",q:"Top-p (nucleus) sampling picks tokens until:",opts:["Sum p ≥ p","Top k","Random","Max len"],ans:0,exp:"Smallest set with cumulative probability ≥ p."},
  {id:"q-1823",cat:"llm",diff:"medium",q:"Repetition penalty discourages:",opts:["New tokens","Tokens already generated","Punctuation","EOS"],ans:1,exp:"Penalizes already-seen tokens."},
  {id:"q-1824",cat:"llm",diff:"medium",q:"Length penalty in beam search:",opts:["Truncates early","Discourages too-short outputs","Encourages more layers","None"],ans:1,exp:"Normalizes by length."},
  {id:"q-1825",cat:"llm",diff:"medium",q:"MMLU evaluates:",opts:["Coding","General knowledge across subjects","Translation","Vision"],ans:1,exp:"Multitask language understanding."},
  {id:"q-1826",cat:"llm",diff:"medium",q:"HumanEval tests:",opts:["Reading comprehension","Code generation","Translation","Sentiment"],ans:1,exp:"Python function synthesis."},
  {id:"q-1827",cat:"llm",diff:"hard",q:"LLM-as-judge uses:",opts:["Humans only","Another LLM to score outputs","Random","Heuristics"],ans:1,exp:"LM evaluates LM outputs."},
  {id:"q-1828",cat:"llm",diff:"medium",q:"Hallucination means:",opts:["Correct answer","Plausible but unsupported output","Slow inference","Memory error"],ans:1,exp:"Confident but wrong."},
  {id:"q-1829",cat:"llm",diff:"medium",q:"Prompt injection is:",opts:["Training technique","Adversarial prompt attack","Hyperparam","Embedding trick"],ans:1,exp:"Manipulating prompts to bypass policy."},
  {id:"q-2000",cat:"math",diff:"easy",q:"3⁴ =",opts:["12","27","64","81"],ans:3,exp:"3×3×3×3 = 81."},
  {id:"q-2001",cat:"math",diff:"easy",q:"5! =",opts:["25","60","120","125"],ans:2,exp:"5! = 5·4·3·2·1 = 120."},
  {id:"q-2002",cat:"math",diff:"easy",q:"gcd(24, 36) =",opts:["6","12","24","72"],ans:1,exp:"gcd(24,36) = 12."},
  {id:"q-2003",cat:"math",diff:"easy",q:"lcm(8, 12) =",opts:["24","48","96","16"],ans:0,exp:"8=2³, 12=2²·3 ⇒ lcm = 2³·3 = 24."},
  {id:"q-2004",cat:"math",diff:"medium",q:"Sum of arithmetic series 1+3+5+...+99 =",opts:["1000","2500","2401","5000"],ans:1,exp:"n=50, sum = 50² = 2500."},
  {id:"q-2005",cat:"math",diff:"medium",q:"Sum of first n squares =",opts:["n(n+1)/2","n(n+1)(2n+1)/6","n³","n²"],ans:1,exp:"Classic closed form."},
  {id:"q-2006",cat:"math",diff:"medium",q:"Sum of first n cubes =",opts:["[n(n+1)/2]²","n³","n⁴","n²"],ans:0,exp:"Equals the square of triangular number."},
  {id:"q-2007",cat:"math",diff:"medium",q:"tan(π/3) =",opts:["1/√3","1","√3","0"],ans:2,exp:"tan 60° = √3."},
  {id:"q-2008",cat:"math",diff:"medium",q:"cos(π/3) =",opts:["1/2","√3/2","1","0"],ans:0,exp:"cos 60° = 1/2."},
  {id:"q-2009",cat:"math",diff:"medium",q:"sin(π/3) =",opts:["1/2","√3/2","1","0"],ans:1,exp:"sin 60° = √3/2."},
  {id:"q-2010",cat:"math",diff:"medium",q:"e^(iπ/2) =",opts:["1","i","−1","−i"],ans:1,exp:"Imaginary unit on unit circle."},
  {id:"q-2011",cat:"math",diff:"medium",q:"If A,B disjoint and |A|=3,|B|=4, then |A∪B| =",opts:["7","12","1","0"],ans:0,exp:"Disjoint union sums sizes."},
  {id:"q-2012",cat:"math",diff:"medium",q:"P(A∪B) =",opts:["P(A)+P(B)","P(A)+P(B)−P(A∩B)","P(A)·P(B)","1"],ans:1,exp:"Inclusion-exclusion."},
  {id:"q-2013",cat:"math",diff:"medium",q:"Permutations of n=5 distinct items:",opts:["60","120","25","5"],ans:1,exp:"5! = 120."},
  {id:"q-2014",cat:"math",diff:"medium",q:"C(10,3) =",opts:["120","720","60","30"],ans:0,exp:"10·9·8 / 3! = 720/6 = 120."},
  {id:"q-2015",cat:"math",diff:"hard",q:"(1+i)² =",opts:["1","2i","1+i","0"],ans:1,exp:"(1+i)² = 1+2i+i² = 1+2i−1 = 2i."},
  {id:"q-2016",cat:"math",diff:"hard",q:"Argument of z = 1+i is:",opts:["π/2","π/4","π/3","0"],ans:1,exp:"arctan(1/1) = π/4."},
  {id:"q-2017",cat:"math",diff:"hard",q:"Roots of x² − 5x + 6 = 0:",opts:["1,6","2,3","−2,−3","0,5"],ans:1,exp:"Factor: (x−2)(x−3)."},
  {id:"q-2018",cat:"math",diff:"hard",q:"Discriminant of x²+bx+c is:",opts:["b²−4c","b²+c","4c−b²","b²−4ac (with a=1)"],ans:3,exp:"With a=1: Δ = b²−4c."},
  {id:"q-2019",cat:"math",diff:"hard",q:"Sum of roots of x²+5x+6 =",opts:["-5","5","6","-6"],ans:0,exp:"−b/a = −5."},
  {id:"q-2020",cat:"math",diff:"hard",q:"Product of roots of x²+5x+6 =",opts:["5","6","-5","-6"],ans:1,exp:"c/a = 6."},
  {id:"q-2021",cat:"math",diff:"medium",q:"If f(x)=3x+2, f⁻¹(x) =",opts:["(x−2)/3","3x−2","(2−x)/3","x/3+2"],ans:0,exp:"Solve y=3x+2 ⇒ x=(y−2)/3."},
  {id:"q-2022",cat:"math",diff:"hard",q:"lim (x→0) (sin 5x)/x =",opts:["0","1","5","1/5"],ans:2,exp:"Standard: sin(ax)/x → a."},
  {id:"q-2023",cat:"math",diff:"hard",q:"lim (x→∞) (1 + 2/x)^x =",opts:["1","2","e","e²"],ans:3,exp:"(1 + a/n)ⁿ → eᵃ."},
  {id:"q-2024",cat:"math",diff:"medium",q:"Number of subsets of a 3-element set:",opts:["3","6","8","9"],ans:2,exp:"2³ = 8."},
  {id:"q-2025",cat:"math",diff:"medium",q:"If sin θ = 1/2, θ in [0, π/2], cos θ =",opts:["1/2","√3/2","√2/2","0"],ans:1,exp:"sin²+cos²=1 ⇒ cos = √3/2."},
  {id:"q-2026",cat:"math",diff:"hard",q:"For real x, minimum of x² + 1/x² (x≠0):",opts:["2","0","1","undefined"],ans:0,exp:"AM-GM: x²+1/x² ≥ 2."},
  {id:"q-2027",cat:"math",diff:"hard",q:"Solve x² = 16:",opts:["±4","4 only","−4 only","0"],ans:0,exp:"Two real roots."},
  {id:"q-2028",cat:"math",diff:"medium",q:"Number of handshakes with 5 people (each pair once):",opts:["5","10","15","20"],ans:1,exp:"C(5,2) = 10."},
  {id:"q-2029",cat:"math",diff:"hard",q:"Euler's totient φ(10) =",opts:["4","5","8","10"],ans:0,exp:"{1,3,7,9} ⇒ 4."},
  {id:"q-2030",cat:"math",diff:"medium",q:"log₂ 64 =",opts:["4","5","6","7"],ans:2,exp:"2⁶ = 64."},
  {id:"q-2031",cat:"math",diff:"easy",q:"Modular arithmetic: 17 mod 5 =",opts:["2","3","4","1"],ans:0,exp:"17 = 3·5 + 2."},
  {id:"q-2032",cat:"math",diff:"medium",q:"Sum 1² + 2² + 3² + 4² =",opts:["14","20","30","16"],ans:2,exp:"1+4+9+16 = 30."},
  {id:"q-2033",cat:"math",diff:"medium",q:"Number of distinct 3-letter words from {A,B,C,D}:",opts:["12","24","64","81"],ans:1,exp:"4³ = 64 (repetition allowed); without repetition = 24. (This one is 'distinct' so no repeat ⇒ 24.)"},
  {id:"q-2034",cat:"math",diff:"hard",q:"A geometric series 2+4+8+...+256 has n terms where n =",opts:["6","7","8","9"],ans:2,exp:"2ⁿ=128 ⇒ n=7+1? Actually 2⁸=256 ⇒ n=8."},
  {id:"q-2035",cat:"math",diff:"medium",q:"The hypotenuse of a right triangle with legs 6 and 8:",opts:["10","12","14","8"],ans:0,exp:"6²+8² = 100 ⇒ √100 = 10."},
  {id:"q-2036",cat:"math",diff:"medium",q:"Solve 3x − 7 = 2:",opts:["1","3","5","7"],ans:1,exp:"3x = 9 ⇒ x = 3."},
  {id:"q-2037",cat:"math",diff:"hard",q:"Binomial: (a+b)³ =",opts:["a³+3a²b+3ab²+b³","a³+b³","a³+3ab+b³","3a+3b"],ans:0,exp:"Standard expansion."},
  {id:"q-2038",cat:"math",diff:"hard",q:"If 2ˣ = 32, x =",opts:["4","5","6","10"],ans:1,exp:"2⁵ = 32."},
  {id:"q-2039",cat:"math",diff:"medium",q:"Average of first 50 positive integers:",opts:["25","25.5","26","24"],ans:1,exp:"(1+50)/2 = 25.5."},
  {id:"q-2040",cat:"math",diff:"medium",q:"n choose 0 =",opts:["1","0","n","n!"],ans:0,exp:"Empty subset, exactly one way."},
  {id:"q-2041",cat:"math",diff:"medium",q:"Square root of 169:",opts:["11","12","13","14"],ans:2,exp:"13² = 169."},
  {id:"q-2042",cat:"math",diff:"medium",q:"Solve |x−3| = 5:",opts:["8 or −2","2 only","−8 only","8 only"],ans:0,exp:"x = 3±5."},
  {id:"q-2043",cat:"math",diff:"hard",q:"If f(x) = x³ − 3x, f′(x) =",opts:["3x² − 3","x² − 3","3x² − x","x³ − 1"],ans:0,exp:"Standard power rule."},
  {id:"q-2044",cat:"math",diff:"hard",q:"∫₀¹ 2x dx =",opts:["0","1","2","1/2"],ans:1,exp:"Antiderivative x² evaluated 0..1 = 1."},
  {id:"q-2045",cat:"math",diff:"medium",q:"Sum of squares of first 5 positive integers:",opts:["30","45","55","25"],ans:2,exp:"1+4+9+16+25 = 55."},
  {id:"q-2046",cat:"math",diff:"hard",q:"For x>0, d/dx ln(x²) =",opts:["2/x","1/x","2x","x"],ans:0,exp:"Chain rule: (1/x²)·2x = 2/x."},
  {id:"q-2047",cat:"math",diff:"hard",q:"∫ 1/(1+x²) dx =",opts:["arctan x + C","ln(1+x²) + C","1/(2x) + C","x/(1+x²) + C"],ans:0,exp:"Standard integral."},
  {id:"q-2048",cat:"math",diff:"medium",q:"Sum of arithmetic series: 5+10+15+...+50 (n=10):",opts:["275","300","500","250"],ans:0,exp:"n·(first+last)/2 = 10·55/2 = 275."},
  {id:"q-2049",cat:"math",diff:"medium",q:"A sequence 1,4,9,16,25,... is:",opts:["Arithmetic","Geometric","Quadratic (squares)","Random"],ans:2,exp:"n² pattern."},
  {id:"q-2050",cat:"math",diff:"hard",q:"A function f is even if f(−x) =",opts:["−f(x)","f(x)","f(x)+c","0"],ans:1,exp:"Symmetric about y-axis."},
  // ============= TRICKY QUESTIONS (tricky: true) =============

  // ---- Linear Algebra tricky ----
  {id:"q-3000",cat:"la",diff:"medium",q:"If A is 3×3 and det(A) = −2, then det(Aᵀ) =",opts:["−2","2","−8","8"],ans:0,tricky:true,exp:"det(Aᵀ) = det(A). The sign does NOT flip on transpose. Common trap is to think transpose negates."},
  {id:"q-3001",cat:"la",diff:"medium",q:"If A and B are n×n and AB = 0 (zero matrix), then:",opts:["A = 0 or B = 0","Both A and B must be singular","At least one of A or B is singular","Both must be non-singular"],ans:2,tricky:true,exp:"AB=0 doesn't force either to be zero, but det(AB)=det(A)·det(B)=0, so at least one has det=0 (singular)."},
  {id:"q-3002",cat:"la",diff:"hard",q:"A 3×3 matrix has eigenvalues 2, 2, 5. The determinant is:",opts:["9","20","10","4"],ans:1,tricky:true,exp:"det = product of eigenvalues = 2×2×5 = 20. Trap: don't forget multiplicities — 2 appears twice."},
  {id:"q-3003",cat:"la",diff:"hard",q:"If A has eigenvalues {1,2,3}, then A⁻¹ has eigenvalues:",opts:["{−1,−2,−3}","{1,1/2,1/3}","{1,4,9}","{0,1/2,1/3}"],ans:1,tricky:true,exp:"If Av=λv then A⁻¹v=(1/λ)v. Zero is impossible (A would be singular)."},
  {id:"q-3004",cat:"la",diff:"medium",q:"A projection matrix P satisfies P²=P. Can det(P)=2?",opts:["Yes, for any rank","No, det(P) is always 0 or 1","Yes, if P is not orthogonal","Only for complex matrices"],ans:1,tricky:true,exp:"P²=P ⇒ eigenvalues satisfy λ²=λ ⇒ λ∈{0,1} ⇒ det∈{0,1}. Cannot be 2."},
  {id:"q-3005",cat:"la",diff:"medium",q:"The trace of AB equals the trace of BA. This holds when:",opts:["A and B are square","A and B are any matrices (if both products defined)","Only when AB=BA","Only for diagonal matrices"],ans:1,tricky:true,exp:"tr(AB)=tr(BA) is true whenever both products are defined, even for non-square matrices (e.g., A is m×n, B is n×m)."},
  {id:"q-3006",cat:"la",diff:"hard",q:"If v₁=[1,0,1], v₂=[1,1,0], v₃=[2,1,1], then v₃ equals:",opts:["v₁+v₂","2v₁","v₁−v₂","Independent of v₁, v₂"],ans:0,tricky:true,exp:"v₁+v₂=[2,1,1]=v₃, so v₃ is linearly dependent. The set {v₁,v₂,v₃} does NOT form a basis for R³."},
  {id:"q-3007",cat:"la",diff:"medium",q:"A 4×2 matrix A: what is the maximum possible rank?",opts:["2","4","6","1"],ans:0,tricky:true,exp:"Rank ≤ min(rows, cols) = min(4,2) = 2. The rank can never exceed the number of columns."},
  {id:"q-3008",cat:"la",diff:"hard",q:"For a symmetric matrix A = [[0,1],[1,0]], the eigenvalues are:",opts:["0 and 0","1 and −1","1 and 1","0 and 1"],ans:1,tricky:true,exp:"det(A−λI)=λ²−1=0 ⇒ λ=±1. Common trap: seeing zeros on the diagonal and guessing 0 is an eigenvalue."},
  {id:"q-3009",cat:"la",diff:"medium",q:"If u=[1,2,3] and v=[4,5,6], the angle between them is:",opts:["Acute","Obtuse","Right","Zero (parallel)"],ans:0,tricky:true,exp:"u·v=4+10+18=32>0, so cosθ>0 ⇒ acute. Don't compute the full angle — just check the sign of the dot product."},
  {id:"q-3010",cat:"la",diff:"hard",q:"The null space of A is the same as the null space of AᵀA. This means:",opts:["A and AᵀA have the same eigenvalues","They share the same solution space for Ax=0","AᵀA is always invertible","A is symmetric"],ans:1,tricky:true,exp:"null(A)=null(AᵀA) is a key property in least-squares. But their column spaces differ."},
  {id:"q-3011",cat:"la",diff:"medium",q:"det(−A) for a 4×4 matrix A equals:",opts:["−det(A)","det(A)","4·det(A)","16·det(A)"],ans:3,tricky:true,exp:"det(−A)=(−1)⁴·det(A)=det(A). For even n the sign is positive. Common mistake: always putting − sign."},
  {id:"q-3012",cat:"la",diff:"hard",q:"If A is invertible, then (2A⁻¹)⁻¹ =",opts:["2A","A/2","A²/2","1/(2A)"],ans:1,tricky:true,exp:"(2A⁻¹)·(A/2)=I, so (2A⁻¹)⁻¹=A/2. Trap: guessing 2A instead of dividing."},
  {id:"q-3013",cat:"la",diff:"medium",q:"The row space and column space of A have:",opts:["Always the same dimension","The same basis vectors","The same number of elements","The same rank"],ans:3,tricky:true,exp:"rank(A) = dim(rowspace) = dim(colspace). But the spaces themselves can differ (e.g., for non-square A)."},
  {id:"q-3014",cat:"la",diff:"hard",q:"If A is orthogonal, then A⁻¹ equals:",opts:["−A","Aᵀ","2A","A²"],ans:1,tricky:true,exp:"Orthogonal: AAᵀ=I ⇒ A⁻¹=Aᵀ. Don't confuse with A⁻¹=−A (which has no general basis)."},
  {id:"q-3015",cat:"la",diff:"medium",q:"Adding a multiple of one row to another in a matrix changes the determinant by a factor of:",opts:["0","The multiplier","1 (no change)","−1"],ans:2,tricky:true,exp:"Row addition is a determinant-preserving elementary operation (factor of 1). Swapping rows gives −1, scaling gives the scalar."},
  {id:"q-3016",cat:"la",diff:"hard",q:"For A with eigenvalues {2,3}, A²+I has eigenvalues:",opts:["{4,9}","{3,4}","{5,10}","{3,10}"],ans:2,tricky:true,exp:"If λ is eigenvalue of A, then λ²+1 is eigenvalue of A²+I: 2²+1=5, 3²+1=10. Trap: forgetting to add I."},
  {id:"q-3017",cat:"la",diff:"medium",q:"A matrix with all entries equal to 1 (say 3×3) has rank:",opts:["3","2","1","0"],ans:2,tricky:true,exp:"Every row is [1,1,1], so only 1 independent row → rank 1. All rows are identical."},
  {id:"q-3018",cat:"la",diff:"hard",q:"If A is nilpotent (Aᵏ=0 for some k), then all eigenvalues of A are:",opts:["Any real number","1","0","Undefined"],ans:2,tricky:true,exp:"Aᵏv=λᵏv=0 for all eigenvectors ⇒ λᵏ=0 ⇒ λ=0. All eigenvalues of a nilpotent matrix are zero."},
  {id:"q-3019",cat:"la",diff:"medium",q:"A matrix A is diagonalizable if:",opts:["It is square","It has n linearly independent eigenvectors","It is symmetric","det(A)≠0"],ans:1,tricky:true,exp:"A is diagonalizable iff eigenvectors form a basis (n L.I. eigenvectors). Symmetric matrices are always diagonalizable, but non-symmetric ones can be too."},
  {id:"q-3020",cat:"la",diff:"hard",q:"For A=[[1,1],[0,1]], A is:",opts:["Diagonalizable","Not diagonalizable","Orthogonal","Singular"],ans:1,tricky:true,exp:"A has eigenvalue 1 with algebraic multiplicity 2 but only one eigenvector [1,0]. Defective ⇒ not diagonalizable."},
  {id:"q-3021",cat:"la",diff:"medium",q:"Cross product u×v is:",opts:["Commutative","Anti-commutative (u×v=−v×u)","Always zero","Only defined for 2D"],ans:1,tricky:true,exp:"Cross product is anti-commutative, unlike dot product which is commutative."},
  {id:"q-3022",cat:"la",diff:"hard",q:"If ||Av|| = ||v|| for all v, then A is:",opts:["The identity","An orthogonal matrix","A symmetric matrix","A zero matrix"],ans:1,tricky:true,exp:"Preserving all norms ⇒ orthogonal (AAᵀ=I). The identity is a special case, but any rotation/reflection works too."},
  {id:"q-3023",cat:"la",diff:"medium",q:"The Gram-Schmidt process produces:",opts:["Eigenvalues","An orthonormal basis from any basis","A diagonal matrix","The inverse of A"],ans:1,tricky:true,exp:"Gram-Schmidt takes a set of vectors and produces an orthonormal set spanning the same space."},
  {id:"q-3024",cat:"la",diff:"hard",q:"For a positive semi-definite matrix, all eigenvalues are:",opts:["Negative","Non-negative","Positive","Complex"],ans:1,tricky:true,exp:"PSD: λᵢ ≥ 0. PD: λᵢ > 0. Semi-definite allows zeros, which is the subtle distinction students miss."},
  {id:"q-3025",cat:"la",diff:"medium",q:"The determinant of a diagonal matrix is:",opts:["The sum of diagonal entries","The product of diagonal entries","Always 1","Always 0"],ans:1,tricky:true,exp:"det(diag(d₁,...,dₙ))=∏dᵢ. Trap: confusing with trace (sum)."},
  {id:"q-3026",cat:"la",diff:"hard",q:"A matrix with det(A)>0 and A=Aᵀ always has:",opts:["Negative eigenvalues","Positive eigenvalues","Purely imaginary eigenvalues","At least one zero eigenvalue"],ans:1,tricky:true,exp:"Symmetric + positive determinant ⇒ all eigenvalues positive (since det=product of eigenvalues and symmetric ⇒ real eigenvalues)."},
  {id:"q-3027",cat:"la",diff:"medium",q:"Two matrices A and B are similar (A=P⁻¹BP). Then A and B share:",opts:["The same entries","The same eigenvalues","The same eigenvectors","The same determinant sign only"],ans:1,tricky:true,exp:"Similar matrices have the same eigenvalues, trace, determinant, rank. But eigenvectors generally differ (they transform by P)."},
  {id:"q-3028",cat:"la",diff:"hard",q:"In SVD, if U=V, then A is:",opts:["Zero matrix","Symmetric positive semi-definite","Anti-symmetric","Not possible"],ans:1,tricky:true,exp:"A=UΣVᵀ, if U=V then A=UΣUᵀ which is symmetric PSD. The eigenvalues are the singular values."},
  {id:"q-3029",cat:"la",diff:"medium",q:"For a consistent system Ax=b with infinitely many solutions, rank(A) =",opts:["= number of columns","< number of columns","> number of columns","= 0"],ans:1,tricky:true,exp:"Infinitely many solutions ⇒ nullity > 0 ⇒ rank < n (columns). The null space provides the free variables."},

  // ---- Calculus tricky ----
  {id:"q-3100",cat:"calc",diff:"medium",q:"d/dx [sin²(x)] =",opts:["2sin(x)","sin(2x)","cos²(x)","2sin(x)cos(x)"],ans:3,tricky:true,exp:"Chain rule: 2sin(x)·cos(x) = sin(2x). Trap: writing 2sin(x) and forgetting the cos(x) factor."},
  {id:"q-3101",cat:"calc",diff:"medium",q:"d/dx [e^(x²)] =",opts:["e^(x²)","2xe^(x²)","x·e^(x²)","2e^(x²)"],ans:1,tricky:true,exp:"Chain rule: e^(x²)·2x. Trap: forgetting the inner derivative 2x."},
  {id:"q-3102",cat:"calc",diff:"hard",q:"∫₀^π sin(x) dx =",opts:["0","2","1","π"],ans:0,tricky:true,exp:"∫sin(x)dx=[−cos(x)]. From 0 to π: −cos(π)−(−cos(0))=−(−1)+(1)=0. The positive and negative areas cancel!"},
  {id:"q-3103",cat:"calc",diff:"medium",q:"d/dx [|x|] for x>0 equals:",opts:["1","−1","0","x/|x| (for all x≠0)"],ans:0,tricky:true,exp:"For x>0, |x|=x, so derivative is 1. The answer 'x/|x|' is the full piecewise answer but the question asks specifically for x>0."},
  {id:"q-3104",cat:"calc",diff:"hard",q:"∫₀^∞ 1/(1+x²) dx =",opts:["0","1","π/2","∞"],ans:2,tricky:true,exp:"∫ 1/(1+x²)dx = arctan(x). arctan(∞)=π/2, arctan(0)=0. Answer is π/2."},
  {id:"q-3105",cat:"calc",diff:"medium",q:"The function f(x)=|x| at x=0 is:",opts:["Differentiable and continuous","Continuous but not differentiable","Differentiable but not continuous","Neither"],ans:1,tricky:true,exp:"|x| is continuous everywhere (no jump), but the corner at x=0 means left and right derivatives disagree."},
  {id:"q-3106",cat:"calc",diff:"hard",q:"d/dx [x^x] (for x>0) equals:",opts:["x·x^(x−1)","x^x(ln x)","x^x(ln x + 1)","x^x · x"],ans:2,tricky:true,exp:"Logarithmic diff: y=x^x, ln y=x ln x, y'/y=ln x+1, y'=x^x(ln x + 1). Can't use plain power or exponential rule."},
  {id:"q-3107",cat:"calc",diff:"medium",q:"lim (x→0) [x·sin(1/x)] =",opts:["Does not exist","∞","1","0"],ans:3,tricky:true,exp:"sin(1/x) oscillates but is bounded by [−1,1]. x→0 squeezes it: |x·sin(1/x)|≤|x|→0. Squeeze theorem."},
  {id:"q-3108",cat:"calc",diff:"hard",q:"∫ sin²(x) dx =",opts:["sin²(x)/2 + C","x/2 − sin(2x)/4 + C","cos²(x)/2 + C","sin(x)cos(x) + C"],ans:1,tricky:true,exp:"Use identity: sin²=(1−cos2x)/2. Integral = x/2 − sin(2x)/4 + C. Trap: trying to use power rule."},
  {id:"q-3109",cat:"calc",diff:"medium",q:"If f is differentiable and f(1)=3, f'(1)=2, then the tangent line at x=1 is:",opts:["y = 3x + 2","y = 2x + 1","y = 2(x−1) + 3","y = 3 − 2(x−1)"],ans:2,tricky:true,exp:"Point-slope: y − 3 = 2(x − 1) ⇒ y = 2(x−1) + 3. Trap: writing y=mx+b with wrong intercept."},
  {id:"q-3110",cat:"calc",diff:"hard",q:"d/dx [ln(ln(x))] =",opts:["1/ln(x)","1/(x·ln(x))","ln(x)/x","1/x"],ans:1,tricky:true,exp:"Chain rule twice: 1/ln(x) · 1/x = 1/(x·ln(x))."},
  {id:"q-3111",cat:"calc",diff:"medium",q:"If f''(x) < 0 for all x, then f is:",opts:["Concave down","Concave up","Linear","Constant"],ans:0,tricky:true,exp:"Negative second derivative ⇒ concave down (frowning). Students often flip the sign convention."},
  {id:"q-3112",cat:"calc",diff:"hard",q:"∫ 1/√(1−x²) dx =",opts:["arcsin x + C","arctan x + C","ln(1−x²) + C","−1/√(1−x²) + C"],ans:0,tricky:true,exp:"Standard integral: arcsin. Confusing with arctan's 1/(1+x²) is a common mistake."},
  {id:"q-3113",cat:"calc",diff:"medium",q:"lim (x→∞) [e^(−x)·x³] =",opts:["∞","0","1","3"],ans:1,tricky:true,exp:"Exponential decay beats any polynomial growth. e^(−x)→0 faster than x³→∞."},
  {id:"q-3114",cat:"calc",diff:"hard",q:"The Maclaurin series for cos(x) has only:",opts:["Odd powers of x","Even powers of x","Both","Only the constant term"],ans:1,tricky:true,exp:"cos is even ⇒ only x⁰, x², x⁴, ... terms. sin has only odd powers."},
  {id:"q-3115",cat:"calc",diff:"medium",q:"d/dx [aˣ] (where a is constant >0) =",opts:["aˣ","aˣ ln a","x·a^(x−1)","aˣ / ln a"],ans:1,tricky:true,exp:"The derivative of aˣ is aˣ ln a. When a=e, ln e=1 and we get eˣ. Students often forget the ln a factor."},
  {id:"q-3116",cat:"calc",diff:"hard",q:"If ∫₀^a f(x)dx = 3 and ∫₀^a g(x)dx = 5, then ∫₀^a [f(x)+g(x)]dx =",opts:["8","15","2","undefined"],ans:0,tricky:true,exp:"Linearity of integrals: ∫(f+g) = ∫f + ∫g = 3 + 5 = 8. Straightforward but tests fundamental understanding."},
  {id:"q-3117",cat:"calc",diff:"medium",q:"The derivative of a constant function is:",opts:["1","The constant itself","0","Undefined"],ans:2,tricky:true,exp:"d/dx c = 0. Simple but students sometimes overthink and write the constant."},
  {id:"q-3118",cat:"calc",diff:"hard",q:"For f(x)=x³−3x, the critical points are at:",opts:["x=0, x=3","x=±1","x=0, x=±√3","x=3"],ans:1,tricky:true,exp:"f'(x)=3x²−3=0 ⇒ x²=1 ⇒ x=±1. Trap: setting f(x)=0 instead of f'(x)=0."},
  {id:"q-3119",cat:"calc",diff:"medium",q:"If f is increasing, then f'(x) is:",opts:["Always positive","≥ 0","Always negative","= 0"],ans:1,tricky:true,exp:"Increasing means f' ≥ 0 (non-negative). Can be 0 at isolated points (e.g., f(x)=x³ at x=0). 'Always positive' is too strict."},
  {id:"q-3120",cat:"calc",diff:"hard",q:"∫₀^1 1/(1+x) dx =",opts:["1","ln 2","1/2","0"],ans:1,tricky:true,exp:"∫1/(1+x)dx = ln(1+x). From 0 to 1: ln(2)−ln(1) = ln 2. Trap: forgetting the chain rule gives ln(1+x) not ln x."},
  {id:"q-3121",cat:"calc",diff:"medium",q:"A function has a local minimum at x=c if:",opts:["f'(c)=0 only","f'(c)=0 and f''(c)>0","f''(c)=0","f(c) is the smallest value everywhere"],ans:1,tricky:true,exp:"Need BOTH conditions: f'=0 AND f''>0. If f'=0 and f''<0, it's a local maximum. If f''=0, test is inconclusive."},
  {id:"q-3122",cat:"calc",diff:"hard",q:"The nth derivative of e^(2x) is:",opts:["e^(2x)","2^n · e^(2x)","n · e^(2x)","2 · e^(2x)"],ans:1,tricky:true,exp:"Each derivative brings down a factor of 2: dⁿ/dxⁿ e^(2x) = 2ⁿ e^(2x)."},
  {id:"q-3123",cat:"calc",diff:"medium",q:"If f(x)=1/x, then f'(1) =",opts:["−1","1","0","1/2"],ans:0,tricky:true,exp:"f'(x)=−1/x², so f'(1)=−1. Sign error is the most common mistake."},
  {id:"q-3124",cat:"calc",diff:"hard",q:"lim (x→0⁺) ln(x) =",opts:["0","1","−∞","undefined (does not exist in reals)"],ans:2,tricky:true,exp:"ln(x)→−∞ as x→0⁺. The function is defined for x>0 and decreases without bound."},
  {id:"q-3125",cat:"calc",diff:"medium",q:"The integral of an odd function from −a to a is:",opts:["2∫₀^a f(x)dx","0","∫₀^a f(x)dx","f(a)"],ans:1,tricky:true,exp:"Odd function: f(−x)=−f(x). The areas on [−a,0] and [0,a] cancel exactly. For even functions it would be 2∫₀^a."},
  {id:"q-3126",cat:"calc",diff:"hard",q:"If f and g are both differentiable and f(g(x))=x for all x, then f'(g(x))·g'(x) =",opts:["0","1","x","f(x)"],ans:1,tricky:true,exp:"Differentiate both sides of f(g(x))=x: f'(g(x))·g'(x)=1. These are inverse functions."},
  {id:"q-3127",cat:"calc",diff:"medium",q:"d/dx [cos(2x)] =",opts:["−sin(2x)","2sin(2x)","−2sin(2x)","sin(2x)"],ans:2,tricky:true,exp:"Chain rule: −sin(2x)·2 = −2sin(2x). Trap: forgetting the inner derivative of 2x."},
  {id:"q-3128",cat:"calc",diff:"hard",q:"∫ eˣ·sin(x) dx requires:",opts:["Simple substitution","Integration by parts twice","No antiderivative","Partial fractions"],ans:1,tricky:true,exp:"Product of eˣ and sin(x) requires integration by parts twice, then solving for the integral algebraically."},
  {id:"q-3129",cat:"calc",diff:"medium",q:"The average value of f(x)=x² on [0,2] is:",opts:["2","4/3","1","8/3"],ans:1,tricky:true,exp:"Avg = (1/(2−0))∫₀² x² dx = (1/2)(8/3) = 4/3. Trap: forgetting to divide by the interval length."},

  // ---- Probability tricky ----
  {id:"q-3200",cat:"prob",diff:"medium",q:"If events A and B are independent, then P(A|B) equals:",opts:["0","P(A)","P(B)","P(A∩B)"],ans:1,tricky:true,exp:"Independence: P(A|B)=P(A). The probability of A doesn't change knowing B. This is the definition of independence."},
  {id:"q-3201",cat:"prob",diff:"hard",q:"Cov(X,Y)=0 implies:",opts:["X and Y are independent","X and Y are uncorrelated (may or may not be independent)","X=Y","Var(X+Y)=Var(X)+Var(Y)"],ans:1,tricky:true,exp:"Zero correlation does NOT imply independence (except for jointly Gaussian). Independence → zero covariance, but not conversely."},
  {id:"q-3202",cat:"prob",diff:"medium",q:"In a group of 30 people, P(at least 2 share a birthday) is approximately:",opts:["5%","30%","70%","97%"],ans:2,tricky:true,exp:"Birthday paradox! With 30 people it's ~70%, not 30/365≈8%. Most people dramatically underestimate this."},
  {id:"q-3203",cat:"prob",diff:"hard",q:"If X~Uniform(0,1), then P(X² < 0.25) =",opts:["0.25","0.5","0.75","0.125"],ans:1,tricky:true,exp:"X²<0.25 ⇒ X<0.5. P(X<0.5)=0.5. Trap: thinking P(X²<0.25)=P(X²)=0.25."},
  {id:"q-3204",cat:"prob",diff:"medium",q:"A fair coin is tossed 10 times. P(exactly 5 heads) is:",opts:["1/2","C(10,5)/2¹⁰","5/10","1/2¹⁰"],ans:1,tricky:true,exp:"Binomial: C(10,5)·(1/2)¹⁰. Not simply 1/2 — the number of heads is not uniformly distributed."},
  {id:"q-3205",cat:"prob",diff:"hard",q:"For X~N(0,1), P(|X|>2) ≈",opts:["2.5%","5%","32%","68%"],ans:1,tricky:true,exp:"P(|Z|>2)=2·P(Z>2)≈2·0.0228≈4.56%≈5%. Trap: confusing with 95% (which is P(|Z|<2))."},
  {id:"q-3206",cat:"prob",diff:"medium",q:"If P(A)=0.6, P(B)=0.5, and A,B independent, then P(A∪B) =",opts:["1.1","0.8","0.3","1.0"],ans:1,tricky:true,exp:"P(A∪B)=P(A)+P(B)−P(A)P(B)=0.6+0.5−0.3=0.8. Trap: adding 0.6+0.5=1.1 or thinking independent means disjoint."},
  {id:"q-3207",cat:"prob",diff:"hard",q:"The variance of the sum of two independent variables is:",opts:["Var(X)+Var(Y)","Var(X)+Var(Y)+2Cov(X,Y)","Var(X)·Var(Y)","Var(X)−Var(Y)"],ans:0,tricky:true,exp:"Independent ⇒ Cov=0, so Var(X+Y)=Var(X)+Var(Y). The 2Cov term vanishes. If NOT independent, you need the covariance."},
  {id:"q-3208",cat:"prob",diff:"medium",q:"A disease affects 1% of people. A test has 99% sensitivity and 95% specificity. If you test positive, P(you have the disease) is approximately:",opts:["99%","95%","~17%","~50%"],ans:2,tricky:true,exp:"Bayes: P(D|+) = 0.99×0.01 / (0.99×0.01 + 0.05×0.99) ≈ 0.0099/0.0594 ≈ 17%. Low prior overwhelms good test. Classic base rate fallacy."},
  {id:"q-3209",cat:"prob",diff:"hard",q:"If E[X]=5 and E[X²]=30, then Var(X) =",opts:["25","5","30","35"],ans:1,tricky:true,exp:"Var(X)=E[X²]−(E[X])²=30−25=5. Must subtract the SQUARE of the mean, not the mean itself."},
  {id:"q-3210",cat:"prob",diff:"medium",q:"Two fair dice are rolled. Given that the sum is 6, P(first die is 3) is:",opts:["1/5","1/6","1/3","1/2"],ans:0,tricky:true,exp:"Sum=6: {(1,5),(2,4),(3,3),(4,2),(5,1)} = 5 outcomes. First die=3: only (3,3). So 1/5. Not 1/6!"},
  {id:"q-3211",cat:"prob",diff:"hard",q:"For Poisson(λ), the probability of observing 0 events is:",opts:["0","λ","e^(−λ)","1−λ"],ans:2,tricky:true,exp:"P(X=0)=λ⁰e^(−λ)/0!=e^(−λ). Counterintuitive: even with large λ, there's a small but positive chance of zero events."},
  {id:"q-3212",cat:"prob",diff:"medium",q:"If you draw 2 cards from a standard deck without replacement, P(both are aces) is:",opts:["(4/52)²","(4/52)·(3/51)","(4/52)·(4/52)","2·(4/52)"],ans:1,tricky:true,exp:"Without replacement: (4/52)·(3/51). Trap: using (4/52)² which assumes replacement."},
  {id:"q-3213",cat:"prob",diff:"hard",q:"The law of large numbers says that as n→∞, the sample mean converges to:",opts:["0","The true mean μ","1/n","The median"],ans:1,tricky:true,exp:"LLN: X̄ₙ → μ almost surely. The sample mean converges to the population mean, not to zero or 1/n."},
  {id:"q-3214",cat:"prob",diff:"medium",q:"Mutually exclusive events A and B have:",opts:["P(A∩B)=P(A)·P(B)","P(A∩B)=0","P(A∪B)=1","P(A|B)=P(B)"],ans:1,tricky:true,exp:"Mutually exclusive = disjoint = P(A∩B)=0. They cannot happen simultaneously. Don't confuse with independent!"},
  {id:"q-3215",cat:"prob",diff:"hard",q:"The median of an exponential distribution with rate λ is:",opts:["1/λ","ln(2)/λ","2/λ","1/(2λ)"],ans:1,tricky:true,exp:"F(m)=0.5 ⇒ 1−e^(−λm)=0.5 ⇒ m=ln(2)/λ. Not 1/λ (that's the mean). Exponential is right-skewed so median < mean."},
  {id:"q-3216",cat:"prob",diff:"medium",q:"Chebyshev's inequality guarantees that P(|X−μ|≥kσ) ≤",opts:["1/k","1/k²","1/(2k)","e^(−k²/2)"],ans:1,tricky:true,exp:"Chebyshev: P(|X−μ|≥kσ) ≤ 1/k² for any distribution with finite variance. Trap: writing 1/k instead of 1/k²."},
  {id:"q-3217",cat:"prob",diff:"hard",q:"If X~Binomial(n,0.5), the most likely value of X is:",opts:["0","n","n/2","n·0.5²"],ans:2,tricky:true,exp:"For a symmetric binomial (p=0.5), the mode is at n/2. The distribution peaks in the middle."},
  {id:"q-3218",cat:"prob",diff:"medium",q:"A 95% CI means:",opts:["95% of data is in the interval","95% probability the parameter is in the interval","95% of such intervals contain the true parameter","The parameter is 95% likely"],ans:2,tricky:true,exp:"A CI is about the procedure, not the parameter. 95% of intervals constructed this way contain the true parameter. The parameter is fixed."},
  {id:"q-3219",cat:"prob",diff:"hard",q:"For X~N(μ, σ²), the maximum of the PDF occurs at:",opts:["μ+σ","μ","0","μ−σ"],ans:1,tricky:true,exp:"The normal PDF is maximized at x=μ (the mean/median/mode all coincide)."},
  {id:"q-3220",cat:"prob",diff:"medium",q:"A fair die is rolled twice. P(sum is even) =",opts:["1/4","1/2","3/4","1/3"],ans:1,tricky:true,exp:"Sum even when both even or both odd. P(even,even)=(1/2)(1/2)=1/4. P(odd,odd)=(1/2)(1/2)=1/4. Total=1/2."},
  {id:"q-3221",cat:"prob",diff:"hard",q:"If Var(X)=4, then Var(3X+7) =",opts:["12","19","36","4"],ans:2,tricky:true,exp:"Var(aX+b)=a²Var(X)=9·4=36. The additive constant (7) has no effect on variance."},
  {id:"q-3222",cat:"prob",diff:"medium",q:"The expected value of a constant c is:",opts:["0","c","1","undefined"],ans:1,tricky:true,exp:"E[c]=c. A constant takes one value with probability 1."},
  {id:"q-3223",cat:"prob",diff:"hard",q:"Two random variables can be uncorrelated but dependent. An example is X~Uniform(−1,1) and Y=X². Here Cov(X,Y) =",opts:["1","0.5","0","−1"],ans:2,tricky:true,exp:"E[XY]=E[X³]=0 (odd function, symmetric). E[X]=0. So Cov=E[XY]−E[X]E[Y]=0. But Y=X² is completely determined by X — strongly dependent!"},
  {id:"q-3224",cat:"prob",diff:"medium",q:"If P(A|B)=P(A), then A and B are:",opts:["Mutually exclusive","Independent","Complements","Identical"],ans:1,tricky:true,exp:"This IS the definition of independence. P(A|B)=P(A) means knowing B gives no info about A."},
  {id:"q-3225",cat:"prob",diff:"hard",q:"A 99% CI is wider than a 95% CI because:",opts:["The sample size is smaller","Higher confidence requires a wider interval","The mean is larger","The variance is larger"],ans:1,tricky:true,exp:"To be more confident the interval contains the parameter, it must be wider. z=2.576 vs z=1.96."},
  {id:"q-3226",cat:"prob",diff:"medium",q:"Sampling without replacement from a finite population:",opts:["Always gives independent samples","Makes samples dependent","Is the same as with replacement","Changes the population mean"],ans:1,tricky:true,exp:"Without replacement, each draw changes the population composition, making samples dependent. This is why we use hypergeometric, not binomial."},
  {id:"q-3227",cat:"prob",diff:"hard",q:"For a Poisson process with rate λ, the expected time between events is:",opts:["λ","1/λ","λ²","0"],ans:1,tricky:true,exp:"Inter-arrival time ~ Exp(λ), mean = 1/λ. Higher rate ⇒ shorter average wait. Counterintuitive: rate and wait are inversely related."},
  {id:"q-3228",cat:"prob",diff:"medium",q:"If A implies B (A⊆B), then P(A) compared to P(B) is:",opts:["P(A) > P(B)","P(A) ≤ P(B)","P(A) = P(B)","Unrelated"],ans:1,tricky:true,exp:"If A⊆B then P(A)≤P(B). Every outcome in A is also in B, but B may have more."},
  {id:"q-3229",cat:"prob",diff:"hard",q:"The bias of the sample variance s²=Σ(xᵢ−x̄)²/n (dividing by n) is:",opts:["Unbiased","Biased (underestimates σ²)","Biased (overestimates σ²)","Zero only for n=1"],ans:1,tricky:true,exp:"Dividing by n gives E[s²]=(n−1)/n · σ² < σ². Must use n−1 (Bessel's correction) for unbiased estimate."},

  // ---- Programming tricky ----
  {id:"q-3300",cat:"prog",diff:"medium",q:"What is the worst-case time complexity of quicksort?",opts:["O(n log n)","O(n²)","O(n)","O(2ⁿ)"],ans:1,tricky:true,exp:"Worst case O(n²) when pivot is smallest or largest element (already sorted). Average is O(n log n). Many forget the worst case."},
  {id:"q-3301",cat:"prog",diff:"medium",q:"Python's `list.append()` in a loop of n elements has total time:",opts:["O(n²)","O(n)","O(n log n)","O(1)"],ans:1,tricky:true,exp:"Amortized O(1) per append, so O(n) total. The list pre-allocates extra space. Not O(n²) like repeatedly concatenating."},
  {id:"q-3302",cat:"prog",diff:"hard",q:"Binary search on a sorted array of 1 million elements takes at most:",opts:["1 million comparisons","20 comparisons","1 million / 2 comparisons","log₂(1M) ≈ 20 steps"],ans:3,tricky:true,exp:"O(log n): log₂(1,000,000) ≈ 20. You only need ~20 probes, not 500,000 (which would be linear search)."},
  {id:"q-3303",cat:"prog",diff:"medium",q:"In Python, `a = [1,2,3]; b = a; b.append(4)`. What is a?",opts:["[1,2,3]","[1,2,3,4]","Error","[4,1,2,3]"],ans:1,tricky:true,exp:"b=a creates a reference, NOT a copy. Both a and b point to the same list. Use b=a.copy() or b=list(a) to copy."},
  {id:"q-3304",cat:"prog",diff:"hard",q:"The master theorem applies to recurrences of the form:",opts:["T(n)=T(n−1)+T(n−2)+n","T(n)=aT(n/b)+f(n)","T(n)=n·T(n/2)","T(n)=T(n²)+1"],ans:1,tricky:true,exp:"Standard form: T(n)=aT(n/b)+f(n) where a≥1, b>1. Not T(n−1) type recurrences (use iteration/other methods for those)."},
  {id:"q-3305",cat:"prog",diff:"medium",q:"Hash table worst-case lookup time is:",opts:["O(1)","O(log n)","O(n)","O(n²)"],ans:2,tricky:true,exp:"If all keys hash to the same bucket, it degrades to O(n) linked list traversal. Average is O(1) but worst case matters."},
  {id:"q-3306",cat:"prog",diff:"hard",q:"A sorting algorithm that is stable AND O(n log n) worst-case is:",opts:["Quicksort","Heapsort","Merge sort","Bubble sort"],ans:2,tricky:true,exp:"Merge sort is both stable and O(n log n) worst-case. Quicksort is O(n²) worst-case. Heapsort is not stable."},
  {id:"q-3307",cat:"prog",diff:"medium",q:"What does `len(set([1,1,2,2,3]))` return in Python?",opts:["5","3","Error","0"],ans:1,tricky:true,exp:"Sets remove duplicates. {1,1,2,2,3} = {1,2,3}, len = 3."},
  {id:"q-3308",cat:"prog",diff:"hard",q:"Space complexity of merge sort for an array of size n is:",opts:["O(1)","O(log n)","O(n)","O(n log n)"],ans:2,tricky:true,exp:"Merge sort needs O(n) auxiliary space for the temporary arrays during merging. Not O(1) like in-place sorts."},
  {id:"q-3309",cat:"prog",diff:"medium",q:"In Python, `sorted([3,1,2])` vs `[3,1,2].sort()` — the difference is:",opts:["No difference","sorted() returns new list; .sort() modifies in place","sorted() is faster","sort() returns new list"],ans:1,tricky:true,exp:"sorted() returns a new list and doesn't modify original. .sort() modifies in place and returns None."},
  {id:"q-3310",cat:"prog",diff:"hard",q:"Dijkstra's algorithm does NOT work correctly with:",opts:["Dense graphs","Negative edge weights","Trees","Directed graphs"],ans:1,tricky:true,exp:"Dijkstra assumes non-negative weights. Negative edges can cause it to miss shorter paths. Use Bellman-Ford for negative weights."},
  {id:"q-3311",cat:"prog",diff:"medium",q:"The time complexity of checking if a key exists in a Python dict is:",opts:["O(n)","O(log n)","O(1) average, O(n) worst","O(n²)"],ans:2,tricky:true,exp:"Average O(1) but worst case O(n) with hash collisions. The question tests whether you know about the worst case."},
  {id:"q-3312",cat:"prog",diff:"hard",q:"For a complete binary tree with n nodes, the height is:",opts:["n","O(n)","O(log n)","O(√n)"],ans:2,tricky:true,exp:"A complete binary tree with n nodes has height ⌊log₂(n)⌋. Not n — that would be a degenerate linked list."},
  {id:"q-3313",cat:"prog",diff:"medium",q:"In Python, `x = 0; x += 1` is equivalent to:",opts:["x = x++","x = x + 1","x++","++x"],ans:1,tricky:true,exp:"Python has no ++ operator. `x += 1` is `x = x + 1`. Students coming from C/Java expect ++ to work."},
  {id:"q-3314",cat:"prog",diff:"hard",q:"Building a min-heap from an unordered array takes:",opts:["O(n log n)","O(n²)","O(n)","O(log n)"],ans:2,tricky:true,exp:"Heapify (bottom-up) is O(n), not O(n log n). This is a classic result: building is cheaper than n insertions."},
  {id:"q-3315",cat:"prog",diff:"medium",q:"The difference between a stack and a queue is:",opts:["Speed","Stack is LIFO, queue is FIFO","Stack is FIFO, queue is LIFO","Memory usage"],ans:1,tricky:true,exp:"LIFO vs FIFO. Easy to confuse. Stack: last-in-first-out (like a pile of plates). Queue: first-in-first-out (like a line)."},
  {id:"q-3316",cat:"prog",diff:"hard",q:"BFS guarantees finding the shortest path in:",opts:["Any graph","Unweighted graphs","Weighted graphs","Directed graphs only"],ans:1,tricky:true,exp:"BFS finds shortest path in unweighted graphs. For weighted graphs, use Dijkstra's algorithm."},
  {id:"q-3317",cat:"prog",diff:"medium",q:"In Python, string concatenation `s += 'x'` in a loop of n iterations has total time:",opts:["O(n)","O(n²)","O(1)","O(n log n)"],ans:1,tricky:true,exp:"Strings are immutable. Each += creates a new string, copying all previous characters. Total: O(n²). Use list + join for O(n)."},
  {id:"q-3318",cat:"prog",diff:"hard",q:"A balanced BST with n nodes has height:",opts:["n","n/2","O(log n)","O(√n)"],ans:2,tricky:true,exp:"Height is ⌈log₂(n+1)⌉ ≈ O(log n). An unbalanced BST can degenerate to O(n)."},
  {id:"q-3319",cat:"prog",diff:"medium",q:"Which data structure would you use to implement LRU cache?",opts:["Array","Hash table + doubly linked list","Stack","Binary tree"],ans:1,tricky:true,exp:"Hash table gives O(1) lookup. Doubly linked list gives O(1) insertion/deletion at ends. Together they achieve O(1) for all operations."},
  {id:"q-3320",cat:"prog",diff:"hard",q:"The amortized cost of inserting n elements into a dynamic array one by one is:",opts:["O(n²) total","O(n) total (O(1) amortized each)","O(n log n) total","O(1) total"],ans:1,tricky:true,exp:"Dynamic array doubles when full. Total copies: 1+2+4+...+n = 2n−1 = O(n). Amortized per insert: O(1)."},
  {id:"q-3321",cat:"prog",diff:"medium",q:"In Python, `range(10)` returns:",opts:["A list of 10 elements","An iterable (not a list)","A tuple","An array"],ans:1,tricky:true,exp:"range() returns a range object (lazy iterable), not a list. Use list(range(10)) if you need a list. Memory efficient!"},
  {id:"q-3322",cat:"prog",diff:"hard",q:"The Floyd-Warshall algorithm finds:",opts:["Shortest path from one source","Shortest paths between ALL pairs","Minimum spanning tree","Maximum flow"],ans:1,tricky:true,exp:"All-pairs shortest paths in O(V³). Dijkstra only does single-source. Floyd-Warshall handles negative weights too."},
  {id:"q-3323",cat:"prog",diff:"medium",q:"In a max-heap, the largest element is always at:",opts:["The last position","The root (index 0)","A leaf node","The middle"],ans:1,tricky:true,exp:"Max-heap property: parent ≥ children. The largest is at the root. In a min-heap, the smallest is at the root."},
  {id:"q-3324",cat:"prog",diff:"hard",q:"Radix sort has time complexity:",opts:["O(n log n)","O(nk) where k is digit count","O(n²)","O(n)"],ans:1,tricky:true,exp:"O(nk) where k = max number of digits. For fixed-width integers, k is constant, giving O(n). Not comparison-based!"},
  {id:"q-3325",cat:"prog",diff:"medium",q:"What is the output of `print(type([]) is list)` in Python?",opts:["False","True","Error","None"],ans:1,tricky:true,exp:"`is` checks identity. type([]) returns <class 'list'>, and `list` refers to the same class object. So True."},
  {id:"q-3326",cat:"prog",diff:"hard",q:"A graph with V vertices and E edges, stored as adjacency matrix, has space complexity:",opts:["O(V+E)","O(V²)","O(E)","O(V)"],ans:1,tricky:true,exp:"Adjacency matrix is V×V boolean/weight entries = O(V²). For sparse graphs, adjacency list O(V+E) is more efficient."},
  {id:"q-3327",cat:"prog",diff:"medium",q:"The `__name__ == '__main__'` guard in Python ensures code runs only when:",opts:["Imported as module","Run as script directly","In a class","In a function"],ans:1,tricky:true,exp:"Code under this guard runs when the file is executed directly, not when imported. Useful for separating test code from library code."},
  {id:"q-3328",cat:"prog",diff:"hard",q:"The time complexity of finding the kth smallest element using QuickSelect is:",opts:["O(n log n)","O(n) average","O(n²) average","O(k)"],ans:1,tricky:true,exp:"QuickSelect (like quicksort but only recurse into one side) has O(n) average case. Worst case is O(n²) but rare with random pivot."},
  {id:"q-3329",cat:"prog",diff:"medium",q:"In Python, `a = (1, 2); a[0] = 3` gives:",opts:["(3, 2)","Error: tuples are immutable","[1, 2]","None"],ans:1,tricky:true,exp:"Tuples are immutable. You cannot modify individual elements. Use a list if you need mutability."},

  // ---- OOP tricky ----
  {id:"q-3400",cat:"oop",diff:"medium",q:"In Python, can a subclass override a method with fewer parameters?",opts:["Yes, always","No — Liskov substitution is violated","Only with @staticmethod","Only if the parent method has default values"],ans:1,tricky:true,exp:"LSP: subtype methods must accept at least what the parent accepts. Fewer params breaks substitutability — callers passing extra args would fail."},
  {id:"q-3401",cat:"oop",diff:"hard",q:"If class B extends A, and A has `def __init__(self)`, does B automatically call A.__init__?",opts:["Yes, always","No — must call super().__init__() explicitly","Only if B has no __init__","Only in Python 3"],ans:1,tricky:true,exp:"In Python, if B defines __init__, it does NOT auto-call A's. You must explicitly call super().__init__(). If B doesn't define __init__, then A's is called."},
  {id:"q-3402",cat:"oop",diff:"medium",q:"Composition over inheritance means:",opts:["Always use inheritance","Prefer has-a relationships over is-a","Use only abstract classes","Never use subclasses"],ans:1,tricky:true,exp:"Favor composition (has-a) over inheritance (is-a) for flexibility. Inheritance creates tight coupling; composition is more flexible."},
  {id:"q-3403",cat:"oop",diff:"hard",q:"A Singleton pattern can be broken in a multi-threaded environment if:",opts:["The constructor is private","Double-checked locking isn't used correctly","It's implemented in Java","It uses a static method"],ans:1,tricky:true,exp:"Without proper synchronization, two threads can each check 'instance==null' before either creates one, resulting in two instances."},
  {id:"q-3404",cat:"oop",diff:"medium",q:"In Python, `@property` without a setter makes the attribute:",opts:["Public","Read-only (raises AttributeError on set)","Private","Protected"],ans:1,tricky:true,exp:"A property with only a getter acts as read-only. Attempting to set it raises AttributeError. Python has no true 'private' or 'readonly' keyword otherwise."},
  {id:"q-3405",cat:"oop",diff:"hard",q:"The Diamond Problem occurs with:",opts:["Single inheritance","Multiple inheritance","Interfaces only","Abstract classes only"],ans:1,tricky:true,exp:"Diamond problem: D extends B and C, both extend A. D inherits A's methods twice. C++ uses virtual inheritance; Python uses MRO."},
  {id:"q-3406",cat:"oop",diff:"medium",q:"In Python, a class variable is shared across:",opts:["Each instance independently","All instances of the class","Only the first instance","None — each instance gets a copy"],ans:1,tricky:true,exp:"Class variables (defined in class body, not __init__) are shared. Mutating them affects all instances. Instance vars (self.x) are per-instance."},
  {id:"q-3407",cat:"oop",diff:"hard",q:"Dependency Inversion Principle says high-level modules should depend on:",opts:["Concrete implementations","Abstractions (interfaces)","Low-level modules","Database classes"],ans:1,tricky:true,exp:"Depend on abstractions, not concretions. This enables swapping implementations (e.g., MockDB for testing instead of RealDB)."},
  {id:"q-3408",cat:"oop",diff:"medium",q:"An abstract method in Python is defined using:",opts:["@abstractmethod (from abc module)","abstract keyword","virtual keyword","Just pass"],ans:0,tricky:true,exp:"Python uses the abc module: from abc import ABC, abstractmethod. The @abstractmethod decorator marks methods that subclasses must implement."},
  {id:"q-3409",cat:"oop",diff:"hard",q:"The Strategy pattern is preferred over a long switch/elseif chain because:",opts:["It's faster","It uses less memory","It's extensible — add new strategies without changing client code","It avoids polymorphism"],ans:2,tricky:true,exp:"New strategies can be added as separate classes without modifying existing code (Open/Closed principle). Switch chains require modifying the core logic."},
  {id:"q-3410",cat:"oop",diff:"medium",q:"`isinstance()` returns True for:",opts:["Only exact class match","The class and any parent class","Only the first parent","Never for subclasses"],ans:1,tricky:true,exp:"isinstance(obj, cls) is True if obj is an instance of cls OR any subclass of cls. type() only checks exact class."},
  {id:"q-3411",cat:"oop",diff:"hard",q:"In Python's MRO (Method Resolution Order), C3 linearization ensures:",opts:["The first parent always wins","A consistent, monotonic ordering that respects all parent orderings","Methods are randomly chosen","The last defined class wins"],ans:1,tricky:true,exp:"C3 linearization produces a deterministic order that is consistent with the inheritance graph. This resolves ambiguities in multiple inheritance."},
  {id:"q-3412",cat:"oop",diff:"medium",q:"Encapsulation in Python is achieved via:",opts:["public/private/protected keywords","Convention: _prefix (protected) and __prefix (name-mangled)","Access modifiers","The 'sealed' keyword"],ans:1,tricky:true,exp:"Python has no access keywords. Single _ is convention for internal use. Double __ triggers name mangling. Both are conventions, not enforcement."},
  {id:"q-3413",cat:"oop",diff:"hard",q:"The Observer pattern's main disadvantage is:",opts:["Too fast","Memory leaks and unexpected updates if observers aren't unregistered","Too much inheritance","Cannot be tested"],ans:1,tricky:true,exp:"If subjects hold references to dead observers, they can't be garbage collected. Also, the order of notifications can cause cascading issues."},
  {id:"q-3414",cat:"oop",diff:"medium",q:"In Python, `__str__` vs `__repr__`: `__repr__` should be:",opts:["User-friendly string","Unambiguous, ideally valid Python expression","Always shorter than __str__","Only used in print()"],ans:1,tricky:true,exp:"__repr__ aims for unambiguous representation (often eval-repr). __str__ is for user-friendly display. If __str__ isn't defined, Python falls back to __repr__."},
  {id:"q-3415",cat:"oop",diff:"hard",q:"The Template Method pattern defines:",opts:["A data structure","A skeleton algorithm with hooks for subclasses","A specific algorithm","A way to create objects"],ans:1,tricky:true,exp:"Template Method: base class defines the algorithm structure, with 'hook' methods that subclasses override. It's behavioral, not creational."},
  {id:"q-3416",cat:"oop",diff:"medium",q:"In Python, all classes ultimately inherit from:",opts:["Nothing","object","BaseClass","Class"],ans:1,tricky:true,exp:"In Python 3, every class implicitly inherits from `object`. This is why all objects have methods like __str__, __repr__, etc."},
  {id:"q-3417",cat:"oop",diff:"hard",q:"Open/Closed Principle means a class should be:",opts:["Open for modification, closed for extension","Open for extension, closed for modification","Always public","Always abstract"],ans:1,tricky:true,exp:"You should extend behavior by adding new code (subclass, strategy), not by modifying existing code. This reduces regression risk."},
  {id:"q-3418",cat:"oop",diff:"medium",q:"A shallow copy of an object with a list attribute:",opts:["Copies the list deeply","Copies the reference to the list (shared)","Creates a new list","Errors"],ans:1,tricky:true,exp:"Shallow copy duplicates the object but shares nested objects. Changing the list in the copy also changes it in the original. Use deepcopy() to avoid this."},
  {id:"q-3419",cat:"oop",diff:"hard",q:"The Interface Segregation Principle says:",opts:["One interface for everything","Many specific interfaces are better than one general interface","Interfaces should have no methods","Only use abstract classes"],ans:1,tricky:true,exp:"Clients shouldn't be forced to depend on methods they don't use. Prefer many small, focused interfaces over one large, bloated interface."},
  {id:"q-3420",cat:"oop",diff:"medium",q:"`super()` in Python's __init__ is used to:",opts:["Call the parent class's __init__","Create a new instance","Delete the parent","Call a sibling class"],ans:0,tricky:true,exp:"super().__init__() delegates to the parent class's initializer. Essential for proper initialization chains in inheritance."},
  {id:"q-3421",cat:"oop",diff:"hard",q:"A decorator in Python that adds caching is called:",opts:["@staticmethod","@lru_cache","@abstractmethod","@classmethod"],ans:1,tricky:true,exp:"@functools.lru_cache memoizes function results. @staticmethod and @classmethod are different — they're about method binding, not caching."},
  {id:"q-3422",cat:"oop",diff:"medium",q:"In Python, `class Dog(Animal): pass` — Animal must be:",opts:["A module","A class (or any valid base)","A function","A variable"],ans:1,tricky:true,exp:"The base class must be a class. Python supports multiple inheritance: Dog(Animal, Pet). But each base must be a class."},
  {id:"q-3423",cat:"oop",diff:"hard",q:"The Law of Demeter says an object should only talk to:",opts:["Its global variables","Its immediate friends (not strangers)","All other objects","Only private methods"],ans:1,tricky:true,exp:"Don't chain: a.getB().getC().doX(). This creates tight coupling. Instead: a.doX() where a delegates internally."},
  {id:"q-3424",cat:"oop",diff:"medium",q:"Polymorphism via duck typing in Python means:",opts:["Using isinstance checks","Calling methods based on what the object supports, not its type","Using abstract classes","Only inheritance-based"],ans:1,tricky:true,exp:"\"If it walks like a duck...\" — Python doesn't require formal inheritance for polymorphism. Any object with the needed methods works."},
  {id:"q-3425",cat:"oop",diff:"hard",q:"The Adapter pattern is used to:",opts:["Create objects","Convert one interface into another that clients expect","Add behavior at runtime","Sort data"],ans:1,tricky:true,exp:"Adapter wraps an incompatible class to make it usable with existing code. Like a power adapter converting plug types."},
  {id:"q-3426",cat:"oop",diff:"medium",q:"In Python, `__del__` is called when:",opts:["The object is created","The object is about to be garbage collected","A method is deleted","The class is imported"],ans:1,tricky:true,exp:"__del__ is the destructor, called when reference count reaches zero. But you can't reliably predict when GC runs in Python."},
  {id:"q-3427",cat:"oop",diff:"hard",q:"The Builder pattern is preferred over a constructor with many parameters because:",opts:["It's faster","It improves readability and allows optional parameters","It uses less memory","It avoids inheritance"],ans:1,tricky:true,exp:"Instead of MyClass(a, b, c, d, e, f), you use Builder().setA(1).setB(2)...build(). Clear which param is which, and can skip optional ones."},
  {id:"q-3428",cat:"oop",diff:"medium",q:"A `@classmethod` in Python receives:",opts:["self (instance)","cls (class itself)","Neither","Both self and cls"],ans:1,tricky:true,exp:"@classmethod receives the class as first argument (cls), not the instance (self). Useful for alternative constructors."},
  {id:"q-3429",cat:"oop",diff:"hard",q:"In the SOLID principles, which one is most commonly violated by God classes?",opts:["Interface Segregation","Single Responsibility","Liskov Substitution","Open/Closed"],ans:1,tricky:true,exp:"A God class handles too many responsibilities. SRP: one class, one reason to change. This is the most common SOLID violation."},

  // ---- Machine Learning tricky ----
  {id:"q-3500",cat:"ml",diff:"medium",q:"Regularization helps prevent overfitting by:",opts:["Adding more data","Penalizing complex models","Removing features manually","Increasing model size"],ans:1,tricky:true,exp:"L1/L2 penalty on weights discourages large weights and complex models. It's a mathematical constraint, not a manual feature selection."},
  {id:"q-3501",cat:"ml",diff:"hard",q:"If training accuracy is 99% but test accuracy is 60%, the model is:",opts:["Underfitting","Overfitting","Well-balanced","Broken"],ans:1,tricky:true,exp:"Large gap between train and test performance = overfitting. The model memorized training data but doesn't generalize."},
  {id:"q-3502",cat:"ml",diff:"medium",q:"K-fold cross-validation with k=5 means:",opts:["Training on 5 models simultaneously","Splitting data into 5 parts, training on 4 and testing on 1, rotating","Using 5% of data for testing","Training 5 times on the same data"],ans:1,tricky:true,exp:"Each of 5 folds serves as the validation set once. All data is used for both training and validation. More robust than a single split."},
  {id:"q-3503",cat:"ml",diff:"hard",q:"Precision = 1.0 and Recall = 0.01 means the model:",opts:["Is very accurate","Predicts positive on almost nothing (very conservative)","Is random","Has high false positive rate"],ans:1,tricky:true,exp:"High precision + low recall: model is very picky about what it calls positive. When it does predict positive, it's usually right, but it misses most positives."},
  {id:"q-3504",cat:"ml",diff:"medium",q:"In a highly imbalanced dataset (99% negative), accuracy is misleading because:",opts:["It's always 100%","Predicting all negatives gives 99% accuracy","It can't be computed","F1 is always 1"],ans:1,tricky:true,exp:"A trivial model predicting 'negative' for everything achieves 99% accuracy but is useless. Use precision, recall, F1, or AUC instead."},
  {id:"q-3505",cat:"ml",diff:"hard",q:"PCA preserves directions of:",opts:["Minimum variance","Maximum variance","Equal variance","Random directions"],ans:1,tricky:true,exp:"PCA projects onto eigenvectors of the covariance matrix sorted by eigenvalue (variance). It keeps directions that capture the most variance."},
  {id:"q-3506",cat:"ml",diff:"medium",q:"Feature scaling is necessary for:",opts:["Decision trees","Distance-based and gradient-based algorithms","All algorithms","Only neural networks"],ans:1,tricky:true,exp:"KNN, SVM, logistic regression, neural networks all need scaling. Tree-based methods (decision trees, random forests) don't."},
  {id:"q-3507",cat:"ml",diff:"hard",q:"L1 regularization (Lasso) can produce exactly zero weights. This means it:",opts:["Always removes features","Performs automatic feature selection","Overfits more","Is always better than L2"],ans:1,tricky:true,exp:"The L1 penalty creates corners in the constraint region where weights can be exactly zero → automatic feature selection. L2 makes weights small but rarely zero."},
  {id:"q-3508",cat:"ml",diff:"medium",q:"A model with high bias will typically have:",opts:["Low training error, high test error","High training error, high test error","Low training error, low test error","High training error, low test error"],ans:1,tricky:true,exp:"High bias = underfitting = too simple. Fails to capture patterns in BOTH training and test data. Both errors are high."},
  {id:"q-3509",cat:"ml",diff:"hard",q:"The kernel trick allows SVMs to:",opts:["Reduce training time","Find non-linear decision boundaries without explicit transformation","Automatically select features","Remove outliers"],ans:1,tricky:true,exp:"Kernels compute dot products in high-dimensional space implicitly. No need to actually compute the transformed features. This makes non-linear classification feasible."},
  {id:"q-3510",cat:"ml",diff:"medium",q:"In k-fold CV, increasing k (e.g., from 5 to 10):",opts:["Always reduces bias","Reduces bias but increases variance and compute","Always improves accuracy","Reduces overfitting"],ans:1,tricky:true,exp:"Higher k = more training data per fold (lower bias) but correlated estimates (higher variance) and more computation. k=n is LOO-CV."},
  {id:"q-3511",cat:"ml",diff:"hard",q:"A confusion matrix for a binary classifier has:",opts:["2 entries","4 entries","8 entries","1 entry"],ans:1,tricky:true,exp:"TP, TN, FP, FN = 4 entries. For multi-class with k classes, it's k×k."},
  {id:"q-3512",cat:"ml",diff:"medium",q:"Gradient descent can get stuck in:",opts:["Global minima only","Local minima or saddle points","Only saddle points","Only convex regions"],ans:1,tricky:true,exp:"In non-convex landscapes (neural nets), GD can find local minima, saddle points, or plateaus. In convex problems (linear/logistic regression), it converges to the global minimum."},
  {id:"q-3513",cat:"ml",diff:"hard",q:"Bootstrap aggregation (bagging) reduces:",opts:["Bias","Variance","Both equally","Neither"],ans:1,tricky:true,exp:"Bagging trains multiple models on different bootstrap samples and averages. This reduces variance (by averaging noisy predictions) much more than bias."},
  {id:"q-3514",cat:"ml",diff:"medium",q:"The learning rate in gradient descent that's too large causes:",opts:["Slow convergence","Divergence (overshooting minima)","No effect","Convergence to global minimum"],ans:1,tricky:true,exp:"Too large LR: the step overshoots the minimum and loss increases → diverges. Too small: very slow convergence."},
  {id:"q-3515",cat:"ml",diff:"hard",q:"In a random forest, each tree is trained on:",opts:["The full dataset","A bootstrap sample with random feature subset","A random subset of features only","The same data every time"],ans:1,tricky:true,exp:"Each tree gets a bootstrap sample (sampling with replacement) AND a random subset of features at each split. This decorrelates the trees."},
  {id:"q-3516",cat:"ml",diff:"medium",q:"Standardization (z-score) transforms features to have:",opts:["Range [0,1]","Mean 0 and standard deviation 1","Mean 1","Range [−1,1]"],ans:1,tricky:true,exp:"z = (x−μ)/σ gives mean 0, std 1. Min-max scaling gives [0,1]. Don't confuse them."},
  {id:"q-3517",cat:"ml",diff:"hard",q:"AUC of 0.5 for a binary classifier means:",opts:["Perfect classifier","Random guessing (no discriminative power)","Perfect wrong predictions","Model is undefined"],ans:1,tricky:true,exp:"AUC=0.5 = random. AUC=1.0 = perfect. AUC=0.0 = perfectly wrong (which is also informative, just inverted)."},
  {id:"q-3518",cat:"ml",diff:"medium",q:"Naive Bayes is called 'naive' because:",opts:["It's simple to implement","It assumes features are conditionally independent given the class","It always makes wrong predictions","It doesn't use probabilities"],ans:1,tricky:true,exp:"The 'naive' assumption: all features are independent given the class label. This is almost never true but works surprisingly well in practice."},
  {id:"q-3519",cat:"ml",diff:"hard",q:"When comparing two models, one with lower training loss but higher test loss, choose:",opts:["The one with lower training loss","The one with lower test loss (better generalization)","Neither — train longer","The more complex one"],ans:1,tricky:true,exp:"Test/Validation performance is what matters for generalization. Lower training loss with higher test loss = overfitting."},
  {id:"q-3520",cat:"ml",diff:"medium",q:"One-hot encoding a feature with 50 categories creates:",opts:["1 new column","50 new columns","2 new columns","49 new columns (if using drop-first)"],ans:1,tricky:true,exp:"Standard one-hot: one column per category = 50. With drop-first to avoid multicollinearity: 49. Most libraries use 50 by default."},
  {id:"q-3521",cat:"ml",diff:"hard",q:"Gradient boosting sequentially adds models that correct:",opts:["Previous model's bias","Residuals (errors) of the ensemble so far","Random noise","The features"],ans:1,tricky:true,exp:"Each new tree fits the negative gradient (pseudo-residuals) of the current ensemble. It corrects mistakes of all previous trees combined."},
  {id:"q-3522",cat:"ml",diff:"medium",q:"If two features are perfectly correlated (r=1), you should:",opts:["Keep both for better accuracy","Remove one to avoid multicollinearity","Transform both to log scale","Normalize them differently"],ans:1,tricky:true,exp:"Perfectly correlated features provide redundant information and cause numerical instability in linear models. Remove one."},
  {id:"q-3523",cat:"ml",diff:"hard",q:"The VC dimension of a model represents:",opts:["Training time","The maximum number of points it can perfectly classify (capacity)","The number of layers","The batch size"],ans:1,tricky:true,exp:"Higher VC dimension = more complex model = can shatter more point configurations. Too high VC → overfitting risk."},
  {id:"q-3524",cat:"ml",diff:"medium",q:"Collaborative filtering in recommender systems uses:",opts:["Content features","User-item interaction patterns","Only user demographics","Only item attributes"],ans:1,tricky:true,exp:"Collaborative filtering recommends based on similar users/items interactions. Content-based uses features of items/users."},
  {id:"q-3525",cat:"ml",diff:"hard",q:"t-SNE differs from PCA in that t-SNE:",opts:["Is linear","Preserves global structure","Preserves local structure and is non-linear","Is faster"],ans:2,tricky:true,exp:"t-SNE preserves local neighborhoods (nearby points stay nearby) but can distort global distances. PCA is linear and preserves global variance."},
  {id:"q-3526",cat:"ml",diff:"medium",q:"The no free lunch theorem states that:",opts:["All algorithms are equally good","No single algorithm is best for all problems","Machine learning is free","Data doesn't matter"],ans:1,tricky:true,exp:"For every problem where algorithm A excels, there's another where it fails. Context and data matter — there's no universal best algorithm."},
  {id:"q-3527",cat:"ml",diff:"hard",q:"In ensemble methods, diversity among base learners is important because:",opts:["It reduces bias","Correlated errors cancel out","It reduces training time","It reduces memory"],ans:1,tricky:true,exp:"If all base models make the same errors, averaging doesn't help. Diversity ensures different errors, so averaging/voting reduces overall error."},
  {id:"q-3528",cat:"ml",diff:"medium",q:"A validation set is different from a test set because:",opts:["They're the same thing","Validation is used for hyperparameter tuning; test is for final evaluation","Validation is always larger","Test set is used during training"],ans:1,tricky:true,exp:"Validation set guides model selection/tuning. Test set is held out until the very end for an unbiased estimate of generalization."},
  {id:"q-3529",cat:"ml",diff:"hard",q:"The curse of dimensionality means that in high dimensions:",opts:["Everything is faster","Data becomes sparse and distances lose meaning","Models always overfit","Features are always correlated"],ans:1,tricky:true,exp:"In high dimensions, the volume grows exponentially, making data sparse. Nearest-neighbor distances become similar, and many algorithms degrade."},

  // ---- Deep Learning tricky ----
  {id:"q-3600",cat:"dl",diff:"medium",q:"Batch normalization normalizes activations across:",opts:["All layers","The batch dimension","Each feature independently across the batch","All training data"],ans:2,tricky:true,exp:"BN computes mean and variance per feature (channel) across the batch. Not across features or layers."},
  {id:"q-3601",cat:"dl",diff:"hard",q:"A 'dead ReLU' neuron always outputs 0 because:",opts:["The input is always 0","The gradient flowing into it is always 0 (learned a large negative bias)","ReLU is undefined at 0","The learning rate is too high"],ans:1,tricky:true,exp:"If a neuron's weights are updated such that it never activates (always in the negative region), gradient is always 0 and it can never recover."},
  {id:"q-3602",cat:"dl",diff:"medium",q:"Weight sharing in CNNs reduces the number of parameters because:",opts:["Fewer layers","The same filter is applied at every spatial position","No bias terms","Smaller input images"],ans:1,tricky:true,exp:"A conv filter slides across all positions. A 3×3 filter has 9 weights regardless of input size. This is spatial parameter sharing."},
  {id:"q-3603",cat:"dl",diff:"hard",q:"The vanishing gradient problem is more severe in networks using:",opts:["ReLU","Sigmoid/tanh","Leaky ReLU","ELU"],ans:1,tricky:true,exp:"Sigmoid saturates at 0 or 1, and its max derivative is 0.25. Chain of sigmoids: 0.25ⁿ → vanishes. ReLU's derivative is 0 or 1, much better."},
  {id:"q-3604",cat:"dl",diff:"medium",q:"Dropout should only be applied during:",opts:["Testing","Training","Both training and testing","Data preprocessing"],ans:1,tricky:true,exp:"During training, dropout randomly zeros activations. At test time, all neurons are active (weights are implicitly scaled by 1-p)."},
  {id:"q-3605",cat:"dl",diff:"hard",q:"The attention mechanism in transformers has complexity:",opts:["O(n)","O(n²)","O(n log n)","O(1)"],ans:1,tricky:true,exp:"Self-attention computes pairwise interactions between all n tokens: QKᵀ is n×n. This is the main bottleneck for long sequences."},
  {id:"q-3606",cat:"dl",diff:"medium",q:"Transfer learning is most effective when:",opts:["The source and target tasks are very different","The source task is related and has more data","You train from scratch","The model is very small"],ans:1,tricky:true,exp:"Best when source task is related and has abundant data. Pre-train on large dataset, fine-tune on smaller target dataset."},
  {id:"q-3607",cat:"dl",diff:"hard",q:"In a residual connection y = F(x) + x, the gradient flows through:",opts:["Only F(x)","Both F(x) and the skip connection (x)","Only x","Neither"],ans:1,tricky:true,exp:"∂y/∂x = ∂F/∂x + 1. The '+1' from the skip connection lets gradient flow directly, solving vanishing gradients in very deep networks."},
  {id:"q-3608",cat:"dl",diff:"medium",q:"Padding='same' in convolution means:",opts:["No padding","Padding to keep output size equal to input size","Random padding","Padding with zeros only on one side"],ans:1,tricky:true,exp:"'same' calculates the needed padding so output spatial dimensions match input. 'valid' means no padding (output shrinks)."},
  {id:"q-3609",cat:"dl",diff:"hard",q:"LSTMs solve the vanishing gradient problem via:",opts:["Removing hidden states","Gates that control what to remember/forget in the cell state","Using larger learning rates","Adding more layers"],ans:1,tricky:true,exp:"The cell state acts as a conveyor belt with additive (not multiplicative) updates. Forget/input/output gates regulate flow without squashing gradients."},
  {id:"q-3610",cat:"dl",diff:"medium",q:"Data augmentation helps by:",opts:["Adding more parameters","Artificially expanding the training dataset with transformed copies","Removing bad data","Increasing model size"],ans:1,tricky:true,exp:"Flips, crops, rotations create new training samples from existing data. Improves generalization without collecting more data."},
  {id:"q-3611",cat:"dl",diff:"hard",q:"The softmax function converts logits to probabilities that:",opts:["Sum to 1 and are always > 0.5","Sum to 1 and are all positive","Sum to 0","Are all < 1"],ans:1,tricky:true,exp:"softmax: e^(z_i) / Σe^(z_j). All outputs are positive (exponential) and sum to 1. Individual probabilities can be very small."},
  {id:"q-3612",cat:"dl",diff:"medium",q:"Adam optimizer is popular because:",opts:["It's the simplest","It combines momentum with adaptive learning rates","It always finds the global minimum","It doesn't need gradients"],ans:1,tricky:true,exp:"Adam = momentum (1st moment) + RMSProp (2nd moment). Per-parameter adaptive learning rates make it robust to different gradient scales."},
  {id:"q-3613",cat:"dl",diff:"hard",q:"Overfitting in deep learning can be detected when:",opts:["Training loss is high","Training loss is very low but validation loss increases","Both losses decrease equally","Validation loss is 0"],ans:1,tricky:true,exp:"Classic overfitting signal: training loss keeps decreasing while validation loss starts increasing. The gap between them grows."},
  {id:"q-3614",cat:"dl",diff:"medium",q:"Convolutional layers are preferred over fully connected for images because:",opts:["They're always faster","They exploit spatial locality and share parameters","They use less memory","They don't need training"],ans:1,tricky:true,exp:"Local connectivity (nearby pixels are related) + weight sharing (same filter everywhere) = fewer parameters and better spatial understanding."},
  {id:"q-3615",cat:"dl",diff:"hard",q:"The gradient of the loss w.r.t. weights is computed using:",opts:["Forward propagation only","Backpropagation (chain rule through the network)","Random search","The loss function directly"],ans:1,tricky:true,exp:"Backprop applies the chain rule layer by layer, from output to input. Each layer gets gradients from the layer above."},
  {id:"q-3616",cat:"dl",diff:"medium",q:"A learning rate schedule that decreases the LR over time is used to:",opts:["Speed up training","Allow fine-grained convergence near minima","Avoid using momentum","Reduce batch size"],ans:1,tricky:true,exp:"High LR for fast initial progress, decreasing LR for stable convergence. Without it, the optimizer may oscillate near the minimum."},
  {id:"q-3617",cat:"dl",diff:"hard",q:"In multi-head attention, each head learns to focus on:",opts:["The same thing","Different aspects/relationships","Different layers","Random tokens"],ans:1,tricky:true,exp:"Different heads capture different patterns: one might focus on syntax, another on coreference, another on semantic similarity. Concatenation combines them."},
  {id:"q-3618",cat:"dl",diff:"medium",q:"Global average pooling (GAP) before a classifier:",opts:["Increases parameters","Reduces spatial dimensions to a single value per channel","Adds convolutional layers","Increases resolution"],ans:1,tricky:true,exp:"GAP averages each feature map to one number. This dramatically reduces parameters vs. flattening + FC layer, and acts as a structural regularizer."},
  {id:"q-3619",cat:"dl",diff:"hard",q:"The exploding gradient problem is typically addressed by:",opts:["Using deeper networks","Gradient clipping","Removing regularization","Using smaller batch sizes"],ans:1,tricky:true,exp:"Gradient clipping caps the gradient norm to a threshold, preventing weights from being updated too dramatically in a single step."},
  {id:"q-3620",cat:"dl",diff:"medium",q:"Fine-tuning a pretrained model typically involves:",opts:["Training all layers from scratch","Unfreezing some/all layers and training on new data","Only changing the output labels","Removing layers"],ans:1,tricky:true,exp:"Start with pretrained weights, optionally freeze early layers, and continue training on the target dataset. This adapts learned features to the new task."},
  {id:"q-3621",cat:"dl",diff:"hard",q:"The receptive field of a neuron in a deep CNN is:",opts:["Only the pixels directly above it","The area of the input image that affects that neuron","Always 3×3","The entire output layer"],ans:1,tricky:true,exp:"Due to stacking convolutions and pooling, a neuron in a deep layer 'sees' a large region of the original input. This grows with depth."},
  {id:"q-3622",cat:"dl",diff:"medium",q:"Label smoothing replaces one-hot labels with:",opts:["All zeros","A soft distribution (e.g., 0.9 for target, 0.1/N for others)","Random labels","Uniform distribution"],ans:1,tricky:true,exp:"Instead of [0,0,1,0], use [0.033,0.033,0.9,0.033]. Prevents the model from becoming overconfident and improves calibration."},
  {id:"q-3623",cat:"dl",diff:"hard",q:"Autodiff (automatic differentiation) differs from symbolic differentiation because:",opts:["It's slower","It computes exact numerical gradients using the chain rule on actual values","It only works for linear functions","It approximates gradients"],ans:1,tricky:true,exp:"Autodiff (as in PyTorch/TensorFlow) computes exact gradients by applying the chain rule to actual numerical values. Not symbolic (analytical expressions) or numerical (finite differences)."},
  {id:"q-3624",cat:"dl",diff:"medium",q:"The KL divergence D_KL(P||Q) = 0 means:",opts:["P and Q are uniform","P and Q are identical distributions","Q is always 0","P is always 0"],ans:1,tricky:true,exp:"KL divergence is 0 only when P and Q are the same distribution. It's not symmetric: D_KL(P||Q) ≠ D_KL(Q||P) in general."},
  {id:"q-3625",cat:"dl",diff:"hard",q:"Positional encoding in transformers is needed because:",opts:["It reduces computation","Self-attention has no inherent notion of word order","It makes the model smaller","It's required for batch normalization"],ans:1,tricky:true,exp:"The attention mechanism is permutation-equivariant — it treats the input as a set, not a sequence. Positional encoding injects order information."},
  {id:"q-3626",cat:"dl",diff:"medium",q:"Early stopping prevents overfitting by:",opts:["Adding more layers","Monitoring validation loss and stopping when it increases","Training for more epochs","Reducing the dataset"],ans:1,tricky:true,exp:"Stop training when validation loss stops improving (or starts increasing). The model at that point typically generalizes best."},
  {id:"q-3627",cat:"dl",diff:"hard",q:"In backpropagation through time (BPTT), the main challenge is:",opts:["Too many parameters","Long-range dependencies cause vanishing/exploding gradients","Memory allocation","Slow forward pass"],ans:1,tricky:true,exp:"BPTT unfolds the RNN through time steps. Gradients multiply through each step, causing vanishing (sigmoids) or exploding problems for long sequences."},
  {id:"q-3628",cat:"dl",diff:"medium",q:"He initialization (for ReLU) sets weights from N(0, √(2/n_in)) because:",opts:["It's the simplest","It keeps variance stable through layers with ReLU","It minimizes loss","It prevents overfitting"],ans:1,tricky:true,exp:"For ReLU, about half the activations are zeroed, so variance is halved. He init compensates: √(2/n_in) instead of √(1/n_in) (Xavier)."},
  {id:"q-3629",cat:"dl",diff:"hard",q:"A generative adversarial network (GAN) has two networks that:",opts:["Cooperate to classify","Compete: generator tries to fool, discriminator tries to distinguish","Both generate data","Both classify data"],ans:1,tricky:true,exp:"Generator creates fake data; discriminator tries to tell real from fake. They compete, pushing each other to improve."},

  // ---- NLP tricky ----
  {id:"q-3700",cat:"nlp",diff:"medium",q:"Bag-of-words ignores:",opts:["Word frequency","Word order","Stopwords","Capitalization"],ans:1,tricky:true,exp:"BoW treats text as an unordered set of words. 'The cat ate the rat' and 'The rat ate the cat' have the same BoW representation."},
  {id:"q-3701",cat:"nlp",diff:"hard",q:"Word2Vec Skip-gram is trained to:",opts:["Predict the center word from context","Predict context words from the center word","Classify sentiment","Translate text"],ans:1,tricky:true,exp:"Skip-gram: given center word, predict surrounding context words. CBOW is the reverse: predict center from context."},
  {id:"q-3702",cat:"nlp",diff:"medium",q:"Stemming 'running' gives 'run', but lemmatizing 'better' gives:",opts:["'better'","'good'","'bett'","'best'"],ans:1,tricky:true,exp:"Stemming uses rules: 'running'→'run'. Lemmatization uses dictionary: 'better'→'good' (lemma). Stemming can't handle irregular forms."},
  {id:"q-3703",cat:"nlp",diff:"hard",q:"BLEU score computes:",opts:["Recall of n-grams","Precision of n-grams with brevity penalty","F1 of n-grams","Exact match rate"],ans:1,tricky:true,exp:"BLEU is n-gram precision (how much of the output matches references) with a brevity penalty (punishes too-short outputs). No recall."},
  {id:"q-3704",cat:"nlp",diff:"medium",q:"BERT is bidirectional because:",opts:["It reads text backwards","Each token attends to both left and right context","It uses two models","It reverses word order"],ans:1,tricky:true,exp:"BERT's encoder attention is unmasked — each token sees all other tokens. GPT uses causal masking (only left context)."},
  {id:"q-3705",cat:"nlp",diff:"hard",q:"The mask in BERT's masked language model randomly replaces ~15% of tokens. Of those:",opts:["All 15% are replaced with [MASK]","80% [MASK], 10% random, 10% unchanged","100% random tokens","50% [MASK], 50% deleted"],ans:1,tricky:true,exp:"80% [MASK], 10% random token, 10% original unchanged. This prevents the model from only learning about [MASK] tokens and being useless at inference time."},
  {id:"q-3706",cat:"nlp",diff:"medium",q:"TF-IDF gives high weight to words that are:",opts:["Very frequent across all documents","Frequent in one document but rare across documents","Short words","Stopwords"],ans:1,tricky:true,exp:"High TF (frequent in this doc) × High IDF (rare across all docs) = distinctive, informative words. Common words like 'the' get low TF-IDF."},
  {id:"q-3707",cat:"nlp",diff:"hard",q:"Subword tokenization (BPE) solves the problem of:",opts:["Slow processing","Out-of-vocabulary words","Grammar errors","Spelling mistakes"],ans:1,tricky:true,exp:"BPE breaks unknown words into frequent subword units: 'unhappiness' → 'un', 'happi', 'ness'. No true OOV since any word can be split into subwords."},
  {id:"q-3708",cat:"nlp",diff:"medium",q:"Cosine similarity of two identical vectors is:",opts:["0","1","−1","undefined"],ans:1,tricky:true,exp:"cos(0°) = 1. Same vector = same direction = angle 0 = cos 0 = 1. Cosine measures angle, not magnitude."},
  {id:"q-3709",cat:"nlp",diff:"hard",q:"Perplexity = 2^H where H is cross-entropy. Lower perplexity means:",opts:["Higher uncertainty","Better language model (lower uncertainty)","More diverse outputs","Larger vocabulary"],ans:1,tricky:true,exp:"Lower perplexity = the model is less 'surprised' by the actual data = better predictions. Higher = worse predictions."},
  {id:"q-3710",cat:"nlp",diff:"medium",q:"GloVe differs from Word2Vec because GloVe uses:",opts:["Local context only","Global co-occurrence statistics","Neural networks only","Character-level info"],ans:1,tricky:true,exp:"GloVe factorizes the global word-word co-occurrence matrix. Word2Vec uses local context windows (predictive approach)."},
  {id:"q-3711",cat:"nlp",diff:"hard",q:"Seq2seq models with attention solve the bottleneck of:",opts:["Slow training","Compressing the entire input into a single fixed-size vector","Too many parameters","Large vocabulary"],ans:1,tricky:true,exp:"Without attention, the encoder compresses the whole input into one vector (the bottleneck). Attention lets the decoder look at all encoder states."},
  {id:"q-3712",cat:"nlp",diff:"medium",q:"NER (Named Entity Recognition) identifies:",opts:["Sentiment","Specific entities like people, organizations, locations","Grammar structure","Word meanings"],ans:1,tricky:true,exp:"NER extracts structured information: person names, dates, locations, organizations, etc. It's a token-level classification task."},
  {id:"q-3713",cat:"nlp",diff:"hard",q:"The encoder-decoder architecture (like T5) is preferred for:",opts:["Only classification","Sequence-to-sequence tasks (translation, summarization)","Only language modeling","Only tokenization"],ans:1,tricky:true,exp:"Encoder processes input, decoder generates output. Ideal for mapping one sequence to another. GPT (decoder-only) can also do seq2seq but less naturally."},
  {id:"q-3714",cat:"nlp",diff:"medium",q:"In NLP, 'context window' refers to:",opts:["The browser window","Maximum number of tokens a model can process at once","The training dataset size","The vocabulary size"],ans:1,tricky:true,exp:"The context window is the maximum number of tokens the model can attend to in a single forward pass (e.g., 512, 1024, 128k)."},
  {id:"q-3715",cat:"nlp",diff:"hard",q:"Fine-tuning BERT for classification typically adds:",opts:["A recurrent layer","A classification head (linear layer on [CLS] token output)","More transformer layers","No new parameters"],ans:1,tricky:true,exp:"The [CLS] token's final hidden state is fed into a new linear layer for classification. Only the new head (and optionally all BERT layers) is trained."},
  {id:"q-3716",cat:"nlp",diff:"medium",q:"Stopword removal can be harmful when:",opts:["Processing large documents","The task needs function words (e.g., sentiment, authorship attribution)","Translating text","Building a search engine"],ans:1,tricky:true,exp:"Function words (not, very, the, a) carry sentiment and stylistic information. Removing them destroys signal for sentiment analysis and similar tasks."},
  {id:"q-3717",cat:"nlp",diff:"hard",q:"The attention mechanism computes similarity between:",opts:["All words and a fixed query","Query and Key vectors, weighted by dimension","Query and Key to produce attention weights for Value","Random pairs of tokens"],ans:2,tricky:true,exp:"Attention = softmax(QKᵀ/√d)V. Q and K determine how much each position attends to others. V is the content that gets weighted and summed."},
  {id:"q-3718",cat:"nlp",diff:"medium",q:"One-hot encoding creates sparse vectors that:",opts:["Are very compact","Have dimension equal to vocabulary size with one 1 and rest 0","Can capture word similarity","Are always normalized"],ans:1,tricky:true,exp:"One-hot: vector with one 1, all else 0. Dimension = vocab size (often 30k+). Can't capture similarity ('cat' and 'dog' are orthogonal)."},
  {id:"q-3719",cat:"nlp",diff:"hard",q:"In beam search with beam width k, the final output is:",opts:["The k-th hypothesis","The highest-scoring hypothesis among all k candidates at the end","The average of all k hypotheses","Randomly chosen"],ans:1,tricky:true,exp:"After generating all hypotheses, the best one (highest total score) is selected. Beam search explores k paths but outputs 1."},
  {id:"q-3720",cat:"nlp",diff:"medium",q:"POS tagging assigns:",opts:["Named entities","Grammatical roles (noun, verb, adjective...) to each token","Sentiment","Topic labels"],ans:1,tricky:true,exp:"Part-of-speech tagging labels each word with its grammatical role. It's a token-level classification task, distinct from NER."},
  {id:"q-3721",cat:"nlp",diff:"hard",q:"Word embeddings can capture analogies: 'king − man + woman ≈ queen'. This works because:",opts:["It is programmed manually","Embedding space preserves relational structure linearly","All words are equidistant","It only works for royalty"],ans:1,tricky:true,exp:"The offset vector (king−man) ≈ (queen−woman). Relationships like gender are captured as consistent directions in embedding space."},
  {id:"q-3722",cat:"nlp",diff:"medium",q:"ROUGE differs from BLEU in that ROUGE measures:",opts:["Precision","Recall","Exact match","Word error rate"],ans:1,tricky:true,exp:"ROUGE is recall-oriented (how much of the reference is covered by the summary). BLEU is precision-oriented. They're complementary."},
  {id:"q-3723",cat:"nlp",diff:"hard",q:"Transformer models process all tokens in parallel because:",opts:["They use recurrence","Self-attention computes all pairwise interactions simultaneously","They use convolution","They are very simple"],ans:1,tricky:true,exp:"Unlike RNNs (sequential), self-attention computes QKᵀ for all positions at once. This enables parallel training on GPUs."},
  {id:"q-3724",cat:"nlp",diff:"medium",q:"Lowercasing text can cause problems when:",opts:["Speed is important","Case carries information (e.g., 'US' vs 'us', 'Apple' vs 'apple')","Doing sentiment analysis","Using bag-of-words"],ans:1,tricky:true,exp:"'US' (country) vs 'us' (pronoun), 'Apple' (company) vs 'apple' (fruit). Lowercasing destroys this distinction."},
  {id:"q-3725",cat:"nlp",diff:"hard",q:"A 'tokenizer vocabulary size of 32k' with BPE means:",opts:["32,000 full words","32,000 subword units (mix of words and word parts)","32,000 characters","32,000 sentences"],ans:1,tricky:true,exp:"BPE vocabulary contains a mix of full words and subword units. Common words are kept whole; rare words are split into pieces."},
  {id:"q-3726",cat:"nlp",diff:"medium",q:"Pre-trained embeddings are useful because:",opts:["They're smaller","They capture general linguistic knowledge from large corpora","They never need updating","They work for all languages"],ans:1,tricky:true,exp:"Trained on billions of words, embeddings encode syntax, semantics, analogies. Fine-tuning on task-specific data adapts them to your domain."},
  {id:"q-3727",cat:"nlp",diff:"hard",q:"Teacher forcing in seq2seq training means:",opts:["The teacher writes the code","Using ground truth as decoder input at each step during training","Using the model's own predictions as input","Training without a teacher"],ans:1,tricky:true,exp:"During training, feed the actual target token (not the model's prediction) as the next input. At inference, use the model's own predictions (no ground truth)."},
  {id:"q-3728",cat:"nlp",diff:"medium",q:"A 'pipeline' in NLP typically means:",opts:["A single model","A sequence of processing steps (tokenize → model → post-process)","A type of neural network","A programming language"],ans:1,tricky:true,exp:"NLP pipelines chain multiple components: tokenization, preprocessing, model inference, and post-processing into a workflow."},
  {id:"q-3729",cat:"nlp",diff:"hard",q:"Multilingual models (like mBERT, XLM-R) are trained on:",opts:["English only","Multiple languages simultaneously","Translations only","Code-switched text only"],ans:1,tricky:true,exp:"They're trained on data from 100+ languages simultaneously. They learn shared cross-lingual representations, enabling zero-shot cross-lingual transfer."},

  // ---- LLM tricky ----
  {id:"q-3800",cat:"llm",diff:"medium",q:"Top-p (nucleus) sampling with p=0.9 means:",opts:["Always pick the top 90% of tokens","Pick the smallest set of tokens whose cumulative probability ≥ 0.9","Pick exactly 9 tokens","Pick tokens with probability > 0.9"],ans:1,tricky:true,exp:"Nucleus sampling: sort by probability, accumulate until sum ≥ p, then sample from that set. The number of tokens varies."},
  {id:"q-3801",cat:"llm",diff:"hard",q:"RLHF (Reinforcement Learning from Human Feedback) uses PPO to:",opts:["Train the reward model","Optimize the language model policy against the reward model","Generate training data","Tokenize text"],ans:1,tricky:true,exp:"First train a reward model on human preferences, then use PPO to optimize the LLM to maximize that reward. RM is separate from the policy optimization."},
  {id:"q-3802",cat:"llm",diff:"medium",q:"LoRA works by:",opts:["Training all weights from scratch","Adding trainable low-rank matrices alongside frozen weights","Quantizing to 4-bit","Pruning weights"],ans:1,tricky:true,exp:"LoRA: W_new = W_frozen + BA, where A and B are small trainable matrices. Only ~1-2% of parameters are updated, saving memory."},
  {id:"q-3803",cat:"llm",diff:"hard",q:"The KV cache is used during inference to:",opts:["Store training data","Cache key and value matrices of previous tokens to avoid recomputation","Store model weights","Cache user prompts"],ans:1,tricky:true,exp:"In autoregressive generation, the K and V projections of all previous tokens are cached. Without it, each new token would require recomputing attention over the entire sequence."},
  {id:"q-3804",cat:"llm",diff:"medium",q:"Temperature = 0 in decoding means:",opts:["Completely random output","Greedy decoding (always pick the most likely next token)","All tokens have equal probability","Model is frozen"],ans:1,tricky:true,exp:"Temperature 0 makes the softmax distribution a one-hot (argmax). Effectively greedy decoding. Higher temperature makes the distribution more uniform."},
  {id:"q-3805",cat:"llm",diff:"hard",q:"Hallucination in LLMs is harder to eliminate than in traditional search because:",opts:["LLMs are always wrong","LLMs generate fluent text regardless of factual accuracy","Search engines hallucinate more","LLMs have no training data"],ans:1,tricky:true,exp:"LLMs are designed to produce fluent, plausible text. They can't distinguish between confident truth and confident falsehood. RAG helps but doesn't eliminate it."},
  {id:"q-3806",cat:"llm",diff:"medium",q:"Prompt injection is dangerous because:",opts:["It makes the model slower","It can bypass safety filters by embedding malicious instructions","It increases memory usage","It requires more compute"],ans:1,tricky:true,exp:"Adversarial inputs can override system prompts, extract private data, or make the model perform unintended actions. Defense is an active research area."},
  {id:"q-3807",cat:"llm",diff:"hard",q:"The Chinchilla scaling law says that for compute-optimal training:",opts:["You should maximize parameters","The number of tokens should be ~20× the number of parameters","Tokens and parameters should be equal","Parameters should be 20× tokens"],ans:1,tricky:true,exp:"Chinchilla finding: most LLMs were undertrained (too many params, too few tokens). Optimal: ~20 tokens per parameter."},
  {id:"q-3808",cat:"llm",diff:"medium",q:"Chain-of-thought prompting works better than direct answering because:",opts:["It's shorter","It forces the model to reason step-by-step before answering","It uses more parameters","It always produces correct answers"],ans:1,tricky:true,exp:"CoT: 'think step by step' → intermediate reasoning steps improve accuracy on math, logic, and multi-step problems. The reasoning process matters, not just the answer."},
  {id:"q-3809",cat:"llm",diff:"hard",q:"RAG (Retrieval-Augmented Generation) helps reduce hallucination by:",opts:["Making the model larger","Providing relevant documents as context at inference time","Training longer","Removing parameters"],ans:1,tricky:true,exp:"RAG retrieves real documents and injects them into the prompt. The model can ground its answers in retrieved evidence, though it can still ignore or misinterpret the context."},
  {id:"q-3810",cat:"llm",diff:"medium",q:"DPO (Direct Preference Optimization) differs from RLHF because DPO:",opts:["Needs a reward model","Directly optimizes the policy from preference pairs (no separate RM)","Uses more compute","Only works for small models"],ans:1,tricky:true,exp:"DPO eliminates the reward model training step. It directly maps preference data to a policy optimization objective. Simpler pipeline than RLHF."},
  {id:"q-3811",cat:"llm",diff:"hard",q:"The context window of an LLM is limited by:",opts:["The vocabulary size","The O(n²) attention memory and compute","The number of layers","The batch size"],ans:1,tricky:true,exp:"Self-attention requires O(n²) memory for the attention matrix. This is the main bottleneck limiting context length. Techniques like Flash Attention help."},
  {id:"q-3812",cat:"llm",diff:"medium",q:"A vector database in a RAG system stores:",opts:["Plain text documents","Embeddings of document chunks for similarity search","Model weights","User passwords"],ans:1,tricky:true,exp:"Documents are split into chunks, embedded, and stored. At query time, the query is embedded and similar chunks are retrieved via nearest neighbor search."},
  {id:"q-3813",cat:"llm",diff:"hard",q:"Speculative decoding speeds up inference by:",opts:["Using a larger model","Drafting with a small model and verifying in parallel with a large model","Compressing the model","Removing layers"],ans:1,tricky:true,exp:"Small 'draft' model generates multiple candidate tokens quickly. Large 'target' model verifies them in a single forward pass. Accept/reject per token."},
  {id:"q-3814",cat:"llm",diff:"medium",q:"Constitutional AI (CAI) uses:",opts:["Human annotators for every response","The LLM itself to critique and revise its own outputs against principles","A separate classifier","More pretraining data"],ans:1,tricky:true,exp:"The model generates responses, then critiques them using a set of 'constitutional' principles, then revises. Reduces need for human feedback at scale."},
  {id:"q-3815",cat:"llm",diff:"hard",q:"Quantization (e.g., INT4) reduces model size by:",opts:["Removing parameters","Reducing precision of weight values from FP32 to INT4","Removing layers","Compressing activations only"],ans:1,tricky:true,exp:"Each weight goes from 32 bits to 4 bits → 8× smaller. Quality loss is often minimal for inference. Requires calibration data for optimal performance."},
  {id:"q-3816",cat:"llm",diff:"medium",q:"In-context learning (few-shot prompting) works because:",opts:["The model is retrained","The prompt provides task examples that the model uses as implicit conditioning","It modifies model weights","It requires gradient updates"],ans:1,tricky:true,exp:"No weight updates! The examples in the prompt condition the model's attention and generation. This is why longer context windows improve few-shot performance."},
  {id:"q-3817",cat:"llm",diff:"hard",q:"RoPE (Rotary Position Embedding) encodes position by:",opts:["Adding a position vector to embeddings","Rotating query and key vectors by an angle proportional to position","Using learned absolute position vectors","Random perturbation"],ans:1,tricky:true,exp:"RoPE applies rotation matrices to Q and K based on position. This encodes relative positions (the angle between tokens) naturally in the dot product."},
  {id:"q-3818",cat:"llm",diff:"medium",q:"A 'system prompt' in chat models sets:",opts:["The model's weights","The behavior, persona, and constraints for the conversation","The training data","The temperature"],ans:1,tricky:true,exp:"System prompt: high-level instructions that shape all subsequent responses (persona, rules, format). It's prepended to the conversation context."},
  {id:"q-3819",cat:"llm",diff:"hard",q:"Function calling/tool use in LLMs works by:",opts:["Manually coding every tool","The model outputs structured JSON that triggers external API calls","Training a separate model for each tool","Disabling the language model"],ans:1,tricky:true,exp:"The model is fine-tuned to detect when a tool is needed and output structured JSON with function name and arguments. An execution layer runs the actual API call."},
  {id:"q-3820",cat:"llm",diff:"medium",q:"The 'pretraining' phase of an LLM involves:",opts:["Learning to follow instructions","Next-token prediction on a massive text corpus","Classification tasks","Human feedback"],ans:1,tricky:true,exp:"Pretraining: predict next token on trillions of tokens. This gives the model world knowledge and language ability. Instruction following comes later (SFT/RLHF)."},
  {id:"q-3821",cat:"llm",diff:"hard",q:"Flash Attention improves upon standard attention by:",opts:["Removing the softmax","Computing attention in a memory-efficient tiled manner without materializing the full n×n matrix","Using fewer heads","Skipping some tokens"],ans:1,tricky:true,exp:"Standard attention materializes the n×n attention matrix (O(n²) memory). Flash Attention computes it in tiles, reducing memory to O(n) and improving IO efficiency."},
  {id:"q-3822",cat:"llm",diff:"medium",q:"Repetition penalty is applied during decoding to:",opts:["Increase diversity of topics","Reduce the chance of the model repeating already-generated tokens","Speed up generation","Increase output length"],ans:1,tricky:true,exp:"Penalizes tokens that have already appeared in the output by dividing their logits by a factor >1. Helps avoid repetitive loops."},
  {id:"q-3823",cat:"llm",diff:"hard",q:"The MMLU benchmark evaluates LLMs on:",opts:["Code generation","Multiple-choice questions across 57 academic subjects","Creative writing","Image recognition"],ans:1,tricky:true,exp:"MMLU (Massive Multitask Language Understanding) tests knowledge across STEM, humanities, social sciences, etc. It's a standard LLM evaluation."},
  {id:"q-3824",cat:"llm",diff:"medium",q:"A decoder-only Transformer (like GPT) generates text:",opts:["Bidirectionally","Autoregressively (one token at a time, left to right)","All tokens at once","In random order"],ans:1,tricky:true,exp:"Decoder-only = causal masking = each token only sees previous tokens. Generation is sequential: predict next, append, repeat."},
  {id:"q-3825",cat:"llm",diff:"hard",q:"When fine-tuning with LoRA, the rank r parameter controls:",opts:["The learning rate","The dimensionality of the low-rank update matrices (higher = more expressiveness)","The batch size","The number of tokens"],ans:1,tricky:true,exp:"LoRA rank r determines the size of A (d×r) and B (r×k). Higher r = more parameters to train = more expressive but more memory. Common: r=8,16,64."},
  {id:"q-3826",cat:"llm",diff:"medium",q:"Continuous batching in LLM inference servers:",opts:["Batches all requests at startup","Starts processing new requests as soon as current ones finish (no waiting for full batch)","Processes one request at a time","Requires identical prompt lengths"],ans:1,tricky:true,exp:"Unlike static batching which waits for a full batch, continuous batching (iteration-level scheduling) fills slots immediately when a request completes."},
  {id:"q-3827",cat:"llm",diff:"hard",q:"A 'reward model' in RLHF is trained to:",opts:["Generate text","Predict human preference between two model outputs","Classify text","Translate text"],ans:1,tricky:true,exp:"The RM takes two outputs for the same prompt and predicts which one a human would prefer. It's then used as the reward signal for PPO."},
  {id:"q-3828",cat:"llm",diff:"medium",q:"SwiGLU activation (used in LLaMA) differs from ReLU because:",opts:["It's always 0 for negative inputs","It's a gated activation that multiplies a linear transform by a sigmoid-gated version","It's slower but more accurate","It removes nonlinearity"],ans:1,tricky:true,exp:"SwiGLU: SwiGLU(x,W,V,b,c) = (xW+b) ⊗ σ(xV+c). The gating mechanism allows more nuanced information flow than simple ReLU."},
  {id:"q-3829",cat:"llm",diff:"hard",q:"The main advantage of grouped-query attention (GQA) over multi-head attention is:",opts:["Better accuracy","Reduced KV cache memory by sharing K/V heads across multiple Q heads","Faster training","Fewer parameters overall"],ans:1,tricky:true,exp:"GQA: multiple Q heads share a single K,V head. This reduces KV cache size (the main memory bottleneck) significantly with minimal quality loss."},

  // ---- Step-by-step worked questions ----
  // Linear Algebra: matrix & vector multiplication, vector spaces
  {id:"q-3900",cat:"la",diff:"medium",q:"Compute A·v where A = [[1,2],[3,4]] and v = [5,6]:",opts:["[17,39]","[11,25]","[23,31]","[17,24]"],ans:0,exp:"Step 1: Write out the multiplication row by row.\nRow 1 of A dots with v:\n  [1,2]·[5,6] = 1·5 + 2·6 = 5 + 12 = 17\nRow 2 of A dots with v:\n  [3,4]·[5,6] = 3·5 + 4·6 = 15 + 24 = 39\nResult: [17, 39]"},
  {id:"q-3901",cat:"la",diff:"medium",q:"Compute AB where A = [[2,0],[1,3]] and B = [[1,4],[2,1]]:",opts:["[[2,8],[7,7]]","[[2,8],[1,3]]","[[2,4],[7,7]]","[[1,8],[7,7]]"],ans:0,exp:"Step 1: Compute each entry of AB = C.\nC₁₁ = 2·1 + 0·2 = 2\nC₁₂ = 2·4 + 0·1 = 8\nC₂₁ = 1·1 + 3·2 = 1 + 6 = 7\nC₂₂ = 1·4 + 3·1 = 4 + 3 = 7\nResult: [[2,8],[7,7]]"},
  {id:"q-3902",cat:"la",diff:"hard",q:"Do v₁=[1,0,0], v₂=[0,1,0], v₃=[1,1,0] form a basis for R³?",opts:["Yes","No — they span only R² (xy-plane)","No — they are not independent","Yes — three vectors always form a basis"],ans:1,exp:"Step 1: Check linear independence.\nc₁v₁ + c₂v₂ + c₃v₃ = 0\n  c₁[1,0,0] + c₂[0,1,0] + c₃[1,1,0] = [0,0,0]\n  [c₁+c₃, c₂+c₃, 0] = [0,0,0]\n\nStep 2: Third component is 0 for all vectors.\nThe z-component is always 0 → these vectors span only the xy-plane (R²), not R³.\nConclusion: NOT a basis for R³ (span is wrong, and they are dependent: v₃ = v₁+v₂)."},
  {id:"q-3903",cat:"la",diff:"hard",q:"If A is 4×5 with rank 3, what is the nullity of A?",opts:["1","2","3","5"],ans:1,exp:"Step 1: Recall rank–nullity theorem.\n  rank(A) + nullity(A) = n (number of columns)\n\nStep 2: Plug in values.\n  rank(A) = 3, n = 5 (columns)\n  3 + nullity(A) = 5\n  nullity(A) = 5 − 3 = 2\n\nThe null space has dimension 2, meaning there are 2 free variables."},
  {id:"q-3904",cat:"la",diff:"medium",q:"Compute A·v where A = [[1,0,2],[3,1,1]] and v = [2,1,0]:",opts:["[2,7]","[3,6]","[2,8]","[1,7]"],ans:0,exp:"Step 1: A is 2×3, v is 3×1, so result is 2×1.\nRow 1: [1,0,2]·[2,1,0] = 1·2 + 0·1 + 2·0 = 2\nRow 2: [3,1,1]·[2,1,0] = 3·2 + 1·1 + 1·0 = 7\nResult: [2, 7]"},

  // Calculus: derivatives, chain rule, implicit, integration
  {id:"q-3905",cat:"calc",diff:"medium",q:"Find d/dx [x³ · eˣ] using the product rule:",opts:["x²·eˣ","3x²·eˣ + x³·eˣ","3x²·eˣ","x³·eˣ + 3"],ans:1,exp:"Step 1: Identify f = x³ and g = eˣ.\nStep 2: Find derivatives.\n  f' = 3x²,  g' = eˣ\nStep 3: Apply product rule: (fg)' = f'g + fg'.\n  (x³ · eˣ)' = 3x² · eˣ + x³ · eˣ\nStep 4: Factor (optional).\n  = eˣ(3x² + x³) = x²·eˣ·(3 + x)\n\nAnswer: 3x²·eˣ + x³·eˣ"},
  {id:"q-3906",cat:"calc",diff:"medium",q:"Find d/dx [x²/(x+1)] using the quotient rule:",opts:["2x/(x+1)²","(x²+2x)/(x+1)²","(2x+1)/(x+1)²","(x²−2x)/(x+1)²"],ans:1,exp:"Step 1: Identify f = x² (numerator), g = x+1 (denominator).\nStep 2: Find derivatives.\n  f' = 2x,  g' = 1\nStep 3: Quotient rule: (f/g)' = (f'g − fg') / g².\n  Numerator: 2x(x+1) − x²·1\n  = 2x² + 2x − x²\n  = x² + 2x\nStep 4: Divide by g² = (x+1)².\n  Result: (x² + 2x) / (x+1)²"},
  {id:"q-3907",cat:"calc",diff:"medium",q:"Find d/dx [sin(3x²)] step by step:",opts:["6x·cos(3x²)","3x²·cos(3x²)","cos(3x²)","6x·sin(3x²)"],ans:0,exp:"Step 1: Identify outer function and inner function.\n  Outer: sin(u), Inner: u = 3x²\nStep 2: Differentiate outer → cos(u).\nStep 3: Differentiate inner → du/dx = 6x.\nStep 4: Chain rule: d/dx sin(3x²) = cos(3x²) · 6x.\n\nAnswer: 6x·cos(3x²)"},
  {id:"q-3908",cat:"calc",diff:"hard",q:"Find d/dx [sin(cos x)] step by step:",opts:["sin(cos x)·cos x","cos(cos x)·(−sin x)","−sin x·cos(cos x)","cos(cos x)·sin x"],ans:1,exp:"Step 1: This is a double chain rule (nested).\nStep 2: Outermost function: sin(u), where u = cos(x).\n  Derivative: cos(u) = cos(cos x)\nStep 3: Inner function: u = cos(x).\n  Derivative: du/dx = −sin x\nStep 4: Multiply: d/dx = cos(cos x) · (−sin x)\n\nAnswer: −sin x · cos(cos x)"},
  {id:"q-3909",cat:"calc",diff:"hard",q:"Find dy/dx at (3,4) for x² + y² = 25:",opts:["−4/3","3/4","−3/4","4/3"],ans:2,exp:"Step 1: Differentiate both sides with respect to x.\n  d/dx [x² + y²] = d/dx [25]\n  2x + 2y · y' = 0\nStep 2: Solve for y'.\n  2y · y' = −2x\n  y' = −x/y\nStep 3: Evaluate at (3, 4).\n  y' = −3/4\n\nThe tangent line has slope −3/4 at (3,4)."},
  {id:"q-3910",cat:"calc",diff:"medium",q:"Find the second derivative f''(x) of f(x) = x⁴ − 6x²:",opts:["12x² − 12","4x³ − 12x","12x − 12","12x² + 12"],ans:0,exp:"Step 1: First derivative.\n  f'(x) = d/dx [x⁴ − 6x²] = 4x³ − 12x\nStep 2: Second derivative.\n  f''(x) = d/dx [4x³ − 12x] = 12x² − 12\n\nAnswer: f''(x) = 12x² − 12"},
  {id:"q-3911",cat:"calc",diff:"hard",q:"Find d/dx [x^x] for x > 0 step by step:",opts:["x^x · ln x","x · x^(x−1)","x^x · (ln x + 1)","x^x · x"],ans:2,exp:"Step 1: Let y = x^x. Take ln of both sides.\n  ln y = x · ln x\nStep 2: Differentiate implicitly (left side with chain rule).\n  y'/y = 1 · ln x + x · (1/x)\n  y'/y = ln x + 1\nStep 3: Solve for y'.\n  y' = y · (ln x + 1) = x^x · (ln x + 1)\n\nAnswer: x^x(ln x + 1)"},
  {id:"q-3912",cat:"calc",diff:"hard",q:"Find d/dx [x² · sin(3x)] using product rule + chain rule:",opts:["2x · sin(3x) + x² · 3cos(3x)","2x · sin(3x) + 3x² · cos(3x)","x² · cos(3x)","2x · sin(3x) − 3x² · cos(3x)"],ans:1,exp:"Step 1: Identify f = x² and g = sin(3x).\nStep 2: Find derivatives.\n  f' = 2x\n  g' = cos(3x) · 3 = 3cos(3x)  (chain rule on inner 3x)\nStep 3: Product rule: (fg)' = f'g + fg'.\n  = 2x · sin(3x) + x² · 3cos(3x)\n  = 2x sin(3x) + 3x² cos(3x)\n\nAnswer: 2x·sin(3x) + 3x²·cos(3x)"},
  {id:"q-3913",cat:"calc",diff:"medium",q:"Find the critical points of f(x) = x³ − 3x:",opts:["x = 0 and x = 3","x = ±1","x = ±√3","x = 0 only"],ans:1,exp:"Step 1: Find f'(x).\n  f'(x) = 3x² − 3\nStep 2: Set f'(x) = 0 to find critical points.\n  3x² − 3 = 0\n  x² = 1\n  x = 1 or x = −1\nStep 3: Check f''(x) = 6x to classify.\n  x = 1: f''(1) = 6 > 0 → local minimum\n  x = −1: f''(−1) = −6 < 0 → local maximum"},
  {id:"q-3914",cat:"calc",diff:"medium",q:"Evaluate ∫ 2x · cos(x²) dx using substitution:",opts:["sin(x²) + C","2sin(x²) + C","x²·sin(x²) + C","cos(x²) + C"],ans:0,exp:"Step 1: Choose substitution u = x².\n  Then du/dx = 2x, so du = 2x dx\nStep 2: Rewrite the integral.\n  ∫ 2x · cos(x²) dx = ∫ cos(u) du\nStep 3: Integrate.\n  ∫ cos(u) du = sin(u) + C\nStep 4: Substitute back u = x².\n  = sin(x²) + C\n\nAnswer: sin(x²) + C"},
  {id:"q-3915",cat:"calc",diff:"hard",q:"Evaluate ∫ x · eˣ dx using integration by parts:",opts:["xeˣ − eˣ + C","xeˣ + eˣ + C","eˣ + C","x²eˣ/2 + C"],ans:0,exp:"Step 1: Integration by parts: ∫ u dv = uv − ∫ v du.\n  Let u = x,  dv = eˣ dx\n  Then du = dx,  v = eˣ\nStep 2: Apply formula.\n  ∫ x·eˣ dx = x·eˣ − ∫ eˣ dx\nStep 3: Integrate the remaining part.\n  ∫ eˣ dx = eˣ\nStep 4: Final answer.\n  = x·eˣ − eˣ + C = eˣ(x − 1) + C\n\nAnswer: xeˣ − eˣ + C"},

  // Programming: recursion, complexity, loops
  {id:"q-3916",cat:"prog",diff:"medium",q:"What does fact(4) return?\ndef fact(n):\n    if n == 0: return 1\n    return n * fact(n-1)",opts:["24","12","6","1"],ans:0,exp:"Step 1: Trace the recursion.\n  fact(4) = 4 * fact(3)\n  fact(3) = 3 * fact(2)\n  fact(2) = 2 * fact(1)\n  fact(1) = 1 * fact(0)\n  fact(0) = 1  (base case)\nStep 2: Unwind the stack.\n  fact(1) = 1 * 1 = 1\n  fact(2) = 2 * 1 = 2\n  fact(3) = 3 * 2 = 6\n  fact(4) = 4 * 6 = 24\n\nAnswer: 24"},
  {id:"q-3917",cat:"prog",diff:"medium",q:"What is the time complexity of this code?\nfor i in range(n):\n    for j in range(n):\n        print(i, j)",opts:["O(n)","O(n²)","O(n log n)","O(log n)"],ans:1,exp:"Step 1: Outer loop runs n times (i = 0, 1, ..., n−1).\nStep 2: For each i, the inner loop runs n times (j = 0, 1, ..., n−1).\nStep 3: Total iterations = n × n = n².\nStep 4: Each iteration is O(1) (just a print).\n\nTotal time: O(n²)"},
  {id:"q-3918",cat:"prog",diff:"medium",q:"How many times does the inner loop run?\nfor i in range(n):\n    for j in range(i, n):\n        count += 1",opts:["n²","n(n+1)/2","n(n−1)/2","2n"],ans:2,exp:"Step 1: Count iterations for each value of i.\n  i=0: j runs n times (0 to n−1)\n  i=1: j runs n−1 times (1 to n−1)\n  i=2: j runs n−2 times\n  ...\n  i=n−1: j runs 1 time\nStep 2: Sum = n + (n−1) + (n−2) + ... + 1\n  = 1 + 2 + ... + (n−1) + n\n  = n(n+1)/2\nStep 3: But the loop starts j at i (not 0), so:\n  i=0: n iterations, i=1: n−1, ..., i=n−1: 1\n  Total = n(n−1)/2\n\nAnswer: n(n−1)/2"},

  // OOP
  {id:"q-3919",cat:"oop",diff:"medium",q:"In Python, if Dog inherits from Animal and both have a method speak(), calling dog.speak() will:",opts:["Call Animal's speak()","Call Dog's speak() (overrides parent)","Call both in order","Raise an error"],ans:1,exp:"Step 1: Method resolution order (MRO) in Python.\n  Python looks for the method in the child class first (Dog).\nStep 2: If found in Dog → use Dog's version.\n  If NOT found in Dog → look in parent (Animal).\nStep 3: This is called method overriding.\n  The child's implementation takes precedence.\n\nAnswer: Dog's speak() is called (it overrides Animal's)"},
  {id:"q-3920",cat:"oop",diff:"medium",q:"The Open/Closed Principle (OCP) from SOLID states that classes should be:",opts:["Open for modification, closed for extension","Open for extension, closed for modification","Both open and closed at all times","Only open for inheritance"],ans:1,exp:"Step 1: OCP — Open/Closed Principle.\nStep 2: \"Open for extension\" means you can add new behavior\n  (e.g., new subclasses, new implementations of an interface).\nStep 3: \"Closed for modification\" means you should NOT need to\n  change existing, tested code to add that behavior.\nStep 4: Example: Use an abstract Shape class with draw().\n  Add new Circle, Triangle subclasses without changing Shape.\n\nAnswer: Open for extension, closed for modification"},
];


